import 'package:flutter/material.dart';
import 'package:google_fonts/google_fonts.dart';
import 'package:provider/provider.dart';
import '../providers/theme_provider.dart';

class AgpeyaPage extends StatefulWidget {
  const AgpeyaPage({super.key});
  @override
  State<AgpeyaPage> createState() => _AgpeyaPageState();
}

class _AgpeyaPageState extends State<AgpeyaPage>
    with SingleTickerProviderStateMixin {
  final List<Map<String, dynamic>> _prayersList = [
    {
      'id': 'morning',
      'icon': Icons.wb_sunny_outlined,
      'name': 'صلاة باكر',
    },
    {
      'id': 'third_hour',
      'icon': Icons.access_time_rounded,
      'name': 'صلاة الساعة الثالثة',
    },
    {
      'id': 'sixth_hour',
      'icon': Icons.access_time_rounded,
      'name': 'صلاة الساعة السادسة',
    },
    {
      'id': 'ninth_hour',
      'icon': Icons.access_time_rounded,
      'name': 'صلاة الساعة التاسعة',
    },
    {
      'id': 'sunset',
      'icon': Icons.wb_twilight,
      'name': 'صلاة غروب',
    },
    {
      'id': 'bedtime',
      'icon': Icons.bedtime,
      'name': 'صلاة النوم',
    },
  ];
  late AnimationController _animationController;
  late List<Animation<double>> _fadeAnimations;
  late List<Animation<Offset>> _slideAnimations;
  @override
  void initState() {
    super.initState();
    _setupAnimations();
  }

  void _setupAnimations() {
    _animationController = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 800),
    );
    _fadeAnimations = List.generate(_prayersList.length, (index) {
      return Tween<double>(begin: 0.0, end: 1.0).animate(
        CurvedAnimation(
          parent: _animationController,
          curve: Interval(index * 0.1, 1.0, curve: Curves.easeOut),
        ),
      );
    });
    _slideAnimations = List.generate(_prayersList.length, (index) {
      return Tween<Offset>(
        begin: const Offset(0, 0.3),
        end: Offset.zero,
      ).animate(
        CurvedAnimation(
          parent: _animationController,
          curve: Interval(index * 0.1, 1.0, curve: Curves.easeOut),
        ),
      );
    });
    _animationController.forward();
  }

  @override
  void dispose() {
    _animationController.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Consumer<ThemeProvider>(
      builder: (context, themeProvider, child) {
        return Directionality(
          textDirection: TextDirection.rtl,
          child: Scaffold(
            backgroundColor: themeProvider.backgroundColor,
            appBar: AppBar(
              backgroundColor: themeProvider.cardColor,
              elevation: 0,
              centerTitle: true,
              leading: IconButton(
                icon: const Icon(Icons.arrow_back_rounded,
                    color: Color(0xFF4ADE80)),
                onPressed: () => Navigator.pop(context),
              ),
              title: Text(
                'الأجبية المقدسة',
                style: GoogleFonts.cairo(
                  fontWeight: FontWeight.w900,
                  color: const Color(0xFF4ADE80),
                  fontSize: 20 * themeProvider.fontScale,
                ),
              ),
            ),
            body: ListView.builder(
              physics: const BouncingScrollPhysics(),
              padding: const EdgeInsets.all(16),
              itemCount: _prayersList.length,
              itemBuilder: (context, index) {
                final prayer = _prayersList[index];
                return FadeTransition(
                  opacity: _fadeAnimations[index],
                  child: SlideTransition(
                    position: _slideAnimations[index],
                    child: _buildPrayerCard(
                      context,
                      themeProvider,
                      prayer['icon'] as IconData,
                      prayer['name'] as String,
                      prayer['id'] as String,
                    ),
                  ),
                );
              },
            ),
          ),
        );
      },
    );
  }

  Widget _buildPrayerCard(
    BuildContext context,
    ThemeProvider themeProvider,
    IconData icon,
    String name,
    String id,
  ) {
    return Container(
      margin: const EdgeInsets.only(bottom: 16),
      decoration: BoxDecoration(
        color: themeProvider.cardColor,
        borderRadius: BorderRadius.circular(20),
        boxShadow: [
          BoxShadow(
            color: Colors.black.withOpacity(0.05),
            blurRadius: 10,
            offset: const Offset(0, 2),
          ),
        ],
      ),
      child: Material(
        color: Colors.transparent,
        borderRadius: BorderRadius.circular(20),
        child: InkWell(
          borderRadius: BorderRadius.circular(20),
          onTap: () {
            Navigator.push(
              context,
              MaterialPageRoute(
                builder: (context) => PrayerDetailsPage(
                  prayerId: id,
                  prayerName: name,
                ),
              ),
            );
          },
          child: Padding(
            padding: const EdgeInsets.symmetric(horizontal: 20, vertical: 16),
            child: Row(
              children: [
                Container(
                  width: 56,
                  height: 56,
                  decoration: BoxDecoration(
                    gradient: LinearGradient(
                      begin: Alignment.topLeft,
                      end: Alignment.bottomRight,
                      colors: [
                        const Color(0xFF4ADE80).withOpacity(0.15),
                        const Color(0xFF4ADE80).withOpacity(0.05),
                      ],
                    ),
                    borderRadius: BorderRadius.circular(16),
                  ),
                  child: Center(
                    child: Icon(icon, size: 32, color: const Color(0xFF4ADE80)),
                  ),
                ),
                const SizedBox(width: 16),
                Expanded(
                  child: Text(
                    name,
                    style: GoogleFonts.cairo(
                      fontSize: 18 * themeProvider.fontScale,
                      fontWeight: FontWeight.bold,
                      color: themeProvider.textColor,
                    ),
                  ),
                ),
                Icon(
                  Icons.arrow_forward_ios_rounded,
                  size: 16,
                  color: const Color(0xFF4ADE80),
                ),
              ],
            ),
          ),
        ),
      ),
    );
  }
}

class PrayerDetailsPage extends StatefulWidget {
  final String prayerId;
  final String prayerName;
  const PrayerDetailsPage({
    super.key,
    required this.prayerId,
    required this.prayerName,
  });
  @override
  State<PrayerDetailsPage> createState() => _PrayerDetailsPageState();
}

class _PrayerDetailsPageState extends State<PrayerDetailsPage> {
  late List<PrayerSection> _prayerSections;
  int _selectedIndex = 0;
  late PageController _pageController;
  @override
  void initState() {
    super.initState();
    _loadPrayerSections();
    _pageController = PageController();
  }

  void _loadPrayerSections() {
    switch (widget.prayerId) {
      case 'morning':
        _prayerSections = _getMorningSections();
        break;
      case 'third_hour':
        _prayerSections = _getThirdHourSections();
        break;
      case 'sixth_hour':
        _prayerSections = _getSixthHourSections();
        break;
      case 'ninth_hour':
        _prayerSections = _getNinthHourSections();
        break;
      case 'sunset':
        _prayerSections = _getSunsetSections();
        break;
      case 'bedtime':
        _prayerSections = _getBedtimeSections();
        break;
      default:
        _prayerSections = [
          PrayerSection(
              id: 'default',
              title: 'الصلاة الربانية',
              body: '⚠️ لم يتم العثور على المحتوى')
        ];
    }
  }

  @override
  void dispose() {
    _pageController.dispose();
    super.dispose();
  }

  List<PrayerSection> _getMorningSections() {
    return [
      PrayerSection(
          id: 'morning_01',
          title: 'الصلاة الربانية',
          body:
              'بِسْم الآب والابنْ والرُوح القُدُس\nالإلَه الوَاحِد، آمين\n( كيريى لَيْسُون ) يَارَبُّ ارْحَمْ. يَارَبُّ ارْحَمْ. يَارَبُّ بارِكْ. آمين.\nالمجدُ للآبِ والابنِ والروحِ القُدسِ الآنَ وكلَّ أوانِ وإِلَى دهرِ الدهورِ. آمين.\nاللَّهُم اجْعلنا مُستحِقين أنْ نقولَ بِشكرٍ:\nأبانا الذي في السَّمَواتِ، لِيتَقدس اسْمكَ. ليأتِ مَلكوتُكَ. لتَكن مَشيئَتُكَ، كما في السّماءِ كَذلك على الأرْضِ. خُبزَنا الذي للغدِ اعطِنا اليومَ. واغفِر لنا ذنوبَنا كما نغْفر نحنُ أيضّا للمذنبينَ إلينا. ولا تُدخِلنا في تَجرِبةٍ. لكن نجّنا مِنْ الشّريرِ. بالمسيحِ يسوعُ ربُّنا، لأنَّ لَكَ المُلكَ والقوةَ والمجدَ إلى الأبدِ. آمين.'),
      PrayerSection(
          id: 'morning_02',
          title: 'صلاة الشكر',
          body:
              'فَلْنشْكُرّ صَانِعَ الخَيراتِ الرَّحُومَ الله أبَا رَبِّنَا وإلهِنَا ومُخَلِصَنا يَسُوعِ المسِيحِ. لأنَّهُ سَتَرنَا، وأعَانَنَا، وحَفِظَنا، وقَبِلَنا إليهِ، وأشْفَقَ عَلينَا، وعَضَّدنَا، وأَتَى بنا إلى هَذِهِ السَّاعَة. هُو أيْضاً فَلْنَسْأَلَهُ أنْ يَحْفَظَنا فى هَذَا اليَومِ المقَدَّسِ وكُلِّ أيَّامِ حَيَاتنَا بكلِّ سَلامِ. الضَّابِطُ الكُلّ الرَّبُ إلَهنَا. أيُّهَا السَّيِدُ الرَّبُّ الإلَه ضَابطُ الكُلِّ أبُو ربِّنَا وإلهنَا ومُخَلصَّنَا يَسُوعِ المسِيح نَشْكرُكَ عَلَى كُلِّ حالٍ، ومِنْ أجْل كلِّ حَالٍ، وفى كُلِّ حالٍ، لأنَّكَ سَترْتَنا، وأعَنْتَنا، وحفِظْتنَا، وقَبلْتنَا إليْكَ، وأشْفَقْت عَلينا، وعَضَّدْتَنَا، وأتَيتَ بِنَا إلىَ هَذِه السَّاعةِ. من أجْلِ هَذَا نَسْألُ ونَطْلبُ مِنْ صَلاحِكَ يَامُحبَّ البَشَر، امْنَحنَا أنْ نُكْملَ هذا اليَوْمَ المقَدَّسَ وكلّ أيَّامِ حَياتِنَا بِكلِّ سَلامٍ مَعَ خَوفِكَ، كُلُّ حَسَدٍ، وكلُّ تَجربَةٍ. وكلُّ فِعْلِ الشَّيْطانِ، ومُؤامَرةِ النَّاسِ الأشْرارِ، وقِيام الأعْدَاءِ الخَفيِّينَ والظَّاهِرينَ، إنْزَعهَا عنَّا وعَنْ سَائِرِ شَعْبكَ وعَنْ مَوضِعِكَ المقَدَّسِ هَذا. أمَّاَ الصَّالِحاتُ والنَّافعاتُ فَارزُقْنا إيَّاهَا. لأنَّكَ أنْتَ الذِى أعْطَيتَنا السُّلْطانَ أنْ ندوسَ الحَيَّاتِ والعَقارِبَ وكُلَّ قوَّةِ العَدوِّ. ولا تُدْخِلنَا فى تَجربَةٍ، لَكنْ نَجِّنا مِنَ الشِّرِّيرِ. بالنِّعْمةِ والرَّأْفَاتِ ومَحبَّة البَشرِ اللَّواتِى لإبْنِك الوَحيدِ ربِّنا وإلهِنَا ومُخلِّصِنا يَسُوعِ المسيحِ. هَذَا الذِى مِنْ قِبَلِه الَمجْدُ والإكْرام والعزَّةُ والسُّجودُ تَلِيقُ بكَ مَعهُ مَعُ الرُّوحِ القُدُسِ الَمحْيى المسَاوِى لَكَ الآنَ وكلَّ أوَانٍ وإلىَ دَهرِ الدُّهُورِ. آمين.'),
      PrayerSection(
          id: 'morning_03',
          title: 'المزمور الخمسون',
          body:
              'إرْحَمنِى يَا الله كَعَظيمِ رَحْمتِكَ، ومِثْل كَثْرةِ رَأفتِكَ تَمْحُو إثْمِى. تَغْسلُنِى كَثيراً مِنْ إثْمِى، ومِنْ خَطيَّتِى تُطهَّرنِى. لأنِّى عارفٌ بإثْمِى، وخَطيَّتِى أمَامِى فى كلِّ حينٍ. لَكَ وحْدَك أخْطأْت، والشَّرُّ قدامَكَ صَنعْتُ. لِكىْ تَتَبرَّرَ فى أقْوالِكَ. وتَغْلبَ إذَا حَاكمْت. لأنِّى هَا أنَذَا بالاثْمِ حُبلَ بِى، وبالَخَطايَا وَلَدتْنِى أمِّى. لأنَّكَ هَكَذا قَدْ أحْبَبتُ الحقَّ، إذْ أوْضَحتَ لِى غَوامِضَ حِكْمتِكَ ومَسْتورَاتِها. تَنضَحُ عَلىَّ بِزُوفَاكَ فأطَّهَّرُ، تَغْسلُنِى فَأبْيضُّ أكْثَر مِنَ الثَّلجِ، تَسْمعُنِى سُرُوراً وفَرحاً، فتَبْتهجُ عِظامِى المنْسَحقةُ. أصْرِفْ وجْهَكَ عَنْ خَطايَاىَ، وأمْحُ كلَّ اثَامِى. قَلبِاً نَقياً أخْلقْ فىَّ يَا الله، ورُوحاً مُسْتَقيماً جدِّدهُ فى أحْشَائِى. لا تَطْرحْنِى مِنْ قُدَّامَ وجْهكَ، ورُوحكَ القُدُّوسِ لا تَنْزعْهُ مِنِّى. امْنَحْنِى بَهْجةَ خَلاصِكَ، وبرُوحِ مُدبِّرٍ عَضِّدّنِى فأعْلمِ الأثَمَةَ طُرُقكَ، والمنَافِقونَ إليْكَ يَرجعونَ، نَجِّنِى مِنَ الدِّماء يا الله إلَه خَلاصِى، فيَبتَّهجُ لِسانِى ببرَّكَ. يَاربِّ إفْتَح شَفتَىَّ فَيُخبرُ فَمِى بَتَسْبيحِكَ. لأنَّكَ لَوْ أثَرتَ الذَّبيحةَ، لَكُنْتُ الآنَ أعْطِى. ولَكنَّكَ لا تُسرُّ بالَمحْرقَاتِ، فالذَبيحَةُ للهِ رُوحَّ مُنْسحقَّ. القَلْبُ المنْكسِرُ والمتَواضِعُ لايُرْزلهُ الله، أنْعمْ يَا ربّ بِمَسرتكَ عَلى صِهْيُون، ولْتَبنِ أسْوَارَ أورْشَلِيم. حِينَئذٍ تُسرُّ بذَبائِح البَرِّ قرباناً ومُحْرقَات ويُقَّربون عَلى مَذابِحكَ العُجُول. هَلِّلُويا.'),
      PrayerSection(
          id: 'morning_04',
          title: 'هلم نسجد',
          body:
              'هَلمَّ نَسْجدُ هَلمَّ نَسْألَ المسِيحَ إلَهنَا. هَلمَّ نَسْجدُ، هَلمَّ نَطْلبُ مِنَ المسِيحِ مَلِكِنا. هَلمَّ نَسْجدُ، هَلمَّ نَتضرَّعُ إلى المسِيح مُخَلصِنَا. يارَبَّنا يَسُوعُ المسِيحُ كَلمَةُ الله إلهنَا، بشَفَاعةِ القدِّيسة مَرْيَمٍ وجَمِيعِ قِدِيسيكَ، إحْفَظنَا ولنَبدَأ بَدْءاً حَسناً. ارْحَمْنا كإرَادَتكَ إلَى الأبَد. اللَّيْلَ عَبَر، نَشْكركَ يَارَبّ ونَسْألُ أنْ تَحْفَظَنا فى هذا اليَومِ بِغَير خَطيَّةٍ وإنْقذْنا.'),
      PrayerSection(
          id: 'morning_05',
          title: 'البولس (أفسس 4:1-5)',
          body:
              'أسْألُكُم أنَا الأسِيرُ فى الرَّبِّ أنْ تَسْلكُوا كَمَا يَحقُّ للدَّعْوةِ التِى دُعِيتُم إليْها، بكلّ تَواضُعِ القَلْب والوَدَاعةِ وطُولِ الأنَاةِ مُحْتمِلينَ بعْضَكُم بَعْضاً فى الَمَحبَّةِ. مُسْرعِينَ إلَى حِفْظِ وَحْدانَّية الروُّحِ برِبَاطِ الصُّلحِ الكَاملِ لِكىْ تَكونُوا جَسَداً واحِداً ورُوحاً واحِداً، كَما دُعِيتُم إلى رَجاءِ دَعْوتِكمْ الوَاحِد. رَبُّ وَاحِدُّ. إيِمَانٌ واحِدٌ. مَعْمودِيَّةٌ وَاحِدةٌ.'),
      PrayerSection(
          id: 'morning_06',
          title: 'من إيمان الكنيسة',
          body:
              'واحِدٌ هُوَ الله أبُو كلِّ أحَدٍ. واحِدٌ هُوَ أيْضاً إبْنُه يَسُوعُ المسِيحُ الكَلِمةُ، الذِى تَجسَّدَ وماتَ وقَامَ مِنَ الأمْواتِ فى اليَومِ الثَّالثِ وأقَامَنَا مَعهُ. واحِدٌ هُوَ الرُّوحُ القُدُسُ المعزَّى الوَاحدُ بإقْنُومِه، مُنبَثقٌ مِنَ الآبِ، يُطهِّرُ كلِّ البَريَّة. يُعلِّمُنا أنْ نَسْجدَ للثَّالُوثِ القُدَّوسِ بِلاهُوتِ واحِدٍ وطَبيعَةٍ واحِدَةٍ، نُسبِّحهُ ونُبارِكهُ إلى الأبَدِ. آمين.'),
      PrayerSection(
          id: 'morning_07',
          title: 'بدء الصلاة',
          body:
              'صَلاةٌ بَاكر مِنَ النَّهارِ المبارَكِ أقدِّمها للْمَسيحِ مَلِكى وإلَهى وأرْجوهُ أنْ يَغْفرَ لِى خَطاياىَ.'),
      PrayerSection(
          id: 'morning_08',
          title: 'مزمور 1: طوبى للرجل',
          body:
              'طُوبَى للرَّجُل الذِى لَمْ يَسْلكْ فى مَشُورةِ المنَافِقِينَ. وفى طَريقِ الَخُطَاةِ لَمْ يَقِفْ، وفى مَجْلسِ المسْتَهزِئينَ لَمْ يَجِلسْ. لكنْ فى نَامُوسِ الرَّبَّ إرادَتُه، وفى نَامُوسِهِ يَلْهجُ نَهاراً وليْلاً. فيَكونُ كالشجَرةِ المغْروسَةِ عَلى مَجارِى المياهِ، التِى تُعْطِى ثَمَرَها فى حِينِهِ. وَورَقُها لاينْتَثِرُ، وكلُّ ما يَصْنعُ ينْجَحُ فِيهِ. لَيسَ كَذلِكَ المنَافِقُونَ، لَيسَ كَذلَكَ. لكنَّهمْ كالَهَبَاءِ الذِى تَذْرِيهِ الرِّيحُ عَنْ وجُهِ الأرْضِ. فَلهَذَا لا يَقومُ المنَافِقُونَ فى الدَّينُونَةِ، ولاَ الخُطَاةُ فى مَجْمَعِ الصِّدِّيقينَ. لأنَّ الرَّبِّ يَعْرِفُ طَريق الأبْرارِ، وأمَّا طَرِيقُ المنَافِقينَ فَتُبادُ. هَلِّلُويا.'),
      PrayerSection(
          id: 'morning_09',
          title: 'مزمور 2: لماذا ارتجت الأمم',
          body:
              'لِماذَا إرْتَجَّتِ الأمَمُ، وفَكَّرتِ الشُّعوبُ بالبَاطِل. قَامَ مُلوكُ الأرْضِ، وتآمَرَ الرُّؤساءُ مَعاً عَلى الرَّبِّ وعَلىِ مَسِيحِهِ قائِلينَ: لِنَقْطَعْ أغْلالَهُم، ولِنَطرحْ عنَّا نَيْرهَا. السَاكِنُ فى السَّمَواتِ يَضْحَكُ بِهِم، والرَّبُّ يَمْقُتُهُم. حِينَئذٍ يُكلِّمهُم بغَضَبهِ، وبِرَجزِهِ يُقْلقُهمْ. أنَا أقَمْتهُ مَلكاً عَلى صُهْيونٍ جَبَل قُدْسهِ، لأكُرِّزَ بأَمْر الرَّبِّ. الرَّبُّ قالَ لِى: أنْتَ إبْنِى، وأنَاَ اليَومَ وَلدْتُك. سَلْنِى فأُعْطِيكَ الأُمَمَ مِيرَاثَكَ، وسُلْطانَكَ إلَى أقْطارِ الأرْضِ. لترْعَاهُم بقضِيبٍ مِنْ حَديدٍ. ومِثْل آنِيةِ الفَخَّارِ تَسْحقُهمْ. فالآنَ أيُّهَا الملُوكُ إفْهَموا، تأدَّبُوا ياجَميعَ قَضَاةِ الأرْضِ أعْبدُوا الرَّبَّ بَخَشْيةِ. وهَللُوا لَهُ برعْدَةٍ. الْزَمُوا الأدَبَ لِئلاَّ يغْضَبَ الرَّبُّ فتَضِلُّوا عَنْ طَريقِ الحَقِّ. عِنْدمَا يتَّقدُ غَضَبُه بسُرْعةٍ. طُوبَى لجَمِيع المتَّكلِينَ عَليْهِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'morning_10',
          title: 'مزمور 3: يارب لماذا كثر',
          body:
              'يَارَبُّ لماذَا كَثُرَ الذِينَ يُحزْنُونِى، كَثِيرونَ قامُوا علىَّ. كَثِيرونَ يقُولُونَ لِنفْسِى، لَيسَ لَهُ خَلاصٌ بإلَهِهِ. أنْتَ يارَبّ أنْتَ هُو نَاصِرِى، مَجْدِى ورَافِعُ رَأسِى. بصَوْتى إلَى الرَّبِّ صَرخْتُ. فإسْتَجابَ لِى مِنْ جَبَلِ قُدْسه. أنَا إضْطَجَعتُ ونِمْتُ، ثمَّ إسْتَيقظْتُ لأنَّ الرَّبَّ نَاصِرى. فَلاَ أخَافَ مِنْ رَبَوات الَجُمُوع المُحِيطِينَ بى القَائميِنَ عَلَىِّ. قُمْ يَارَبّ خلِّصْنِى يَا إلَهِى، لأنَّكَ ضَرَبْتَ كُلَّ مِنْ يُعادِينى بَاطِلاً. أسْنانُ الخُطاةِ سَحَقَتْها. للرَّبِّ الخَلاَص وعَلَى شَعبِه بَرَكتهُ. هَلِّلُويا.'),
      PrayerSection(
          id: 'morning_11',
          title: 'مزمور 4: إذ دعوت استجبت لي',
          body:
              'إذْ دَعَوْتُ إسْتَجَبْتَ لِى يَا إلهَ برِّى، فى الشّدَّةِ فَرَّجتَ عَنِّى. تَراءَفْ عَلىَّ يَارَبِّ وإسْمَعْ صَلاتِى. يا بَنِى البَشَرَ حتَّى مَتَى تَثْقلُ قلُوبُكُم؟ لماذَا تُحبُّونَ البَاطِلَ وتَبْتَغونَ الكَذبَ؟ أعْلمُوا أنَّ الرَّبَّ قَدْ جَعَل قُدُّوسَه عَجباً. الرَّبُّ يَسْتَجيبُ لِى إذا ما صَرخْتُ إلَيهِ. إغْضَبُوا ولا تُخْطِئوا، الذِى تَقولُونَه فى قُلوبِكُم أنْدمُوا عَليْهِ فى مَضَاجعكُم. إذْبَحُوا ذَبيحَة البِرِّ، وتَوكَّلُوا عَلى الرَّبِّ.\nإذْ دَعَوْتُ إسْتَجَبْتَ لِى يَا إلهَ برِّى، فى الشّدَّةِ فَرَّجتَ عَنِّى. تَراءَفْ عَلىَّ يَارَبِّ وإسْمَعْ صَلاتِى. يا بَنِى البَشَرَ حتَّى مَتَى تَثْقلُ قلُوبُكُم؟ لماذَا تُحبُّونَ البَاطِلَ وتَبْتَغونَ الكَذبَ؟ أعْلمُوا أنَّ الرَّبَّ قَدْ جَعَل قُدُّوسَه عَجباً. الرَّبُّ يَسْتَجيبُ لِى إذا ما صَرخْتُ إلَيهِ. إغْضَبُوا ولا تُخْطِئوا، الذِى تَقولُونَه فى قُلوبِكُم أنْدمُوا عَليْهِ فى مَضَاجعكُم. إذْبَحُوا ذَبيحَة البِرِّ، وتَوكَّلُوا عَلى الرَّبِّ.'),
      PrayerSection(
          id: 'morning_12',
          title: 'مزمور 5: أنصت يارب لكلماتي',
          body:
              'أنًصِتْ يَارَبُّ لِكَلِماتِى، وإسْمَعْ صُراخِى. إصْغَ إلى صَوْتِ طَلبَتى يامَلِكى وإلَهِى، لأنِّى إليْكَ أصلِّى. يارَبُّ بالغّداةِ تَسمَعُ صَوتِى، بالغَداةِ أقف أمَامكَ وتَرانِى. لأنَّكَ إلهٌ لا تَشَاء الأثْمَ، ولا يُساكِنُكَ مَنْ يَصنَعُ الشَّرَّ. ولا يَثْبتُ مُخالفُو النَّامُوس أمَامَ عَيْنَيكَ. يَاربُّ أبْغَضتَ جَمِيعَ فَاعِلِى الأثْمِ، وتُهِلكُ كلَّ النَّاطِقينَ بالكَذبِ. رَجلُ الدِّماءِ والغاشِّ يَرذلُهُ الرَّبُّ. أمَّا أنَا فبكثْرةِ رحْمَتكَ أدْخلُ بَيْتِكَ، وأسْجدُ قَدَّامَ هَيْكلِ قُدسِك بَمَخَافَتكَ. ياربُّ أهْدِنِى بِبرِّكَ، مِنْ أجْل أعْدائِى. سَهِّلْ أمَامِى طَريقَكَ. لأنَّهُ لَيسَ فى أفْواهِهِمْ صِدقٌ. بَاطِلٌ هُوَ قَلبُهُمِ. حَنْجرتَهُمْ قَبْرٌ مفْتُوحٌ. وبألسِنتِهم قد غَشُّوا. دِنْهُمْ يا الله. وليسْقُطُوا مِنْ جَميعِ مُؤامَراتِهِمْ وكِكَثْرةِ نِفاقِهِمْ اسْتَأصِلْهُم، لأنَّهُم قَدْ أغْضَبوكَ يَاربُّ. وليَفْرحْ جَميعُ المتَّكلِينَ عَليكَ، إلى الأبَدِ يُسرُّونَ وتَحلُّ فِيهِمْ. ويفْتَخرُ بكَ كلُّ الذِينَ يُحبُّونَ إسْمكَ. لأنَّكَ أنْتَ بَارَكتَ الصِّدِّيقَ يَاربُّ. كَما بتُرْسِ المسَرَّةِ كَلَلتَنَا. هَلِّلُويا.'),
      PrayerSection(
          id: 'morning_13',
          title: 'مزمور 6: يارب لا تبكتني بغضبك',
          body:
              'يَاربُّ لا تُبكِّتْنِى بغَضَبكَ، ولا تُؤدِّبْنِى بسَخَطكَ. إرْحَمنِى يَاربُّ فإنِّى ضَعِيفٌ، إشْفِنِى يارَبُّ فإنَّ عِظَامِى قَد إضْطَربَتْ ونَفْسِى قدِ إنْزَعجَت جِدّاً. وأنْتَ يَاربُّ فإلَى مَتَى؟ عُدْ ونَجِّى نَفْسى، وأحْيِنِى مِنْ أجْلِ رَحْمتكَ. لأنَّه لَيسَ فى الموْتِ مِنْ يَذْكُركَ ولا فى الَجَحِيم مَنْ يَعْترفُ لَك. تَعِبتُ فى تَنهُّدِى. أعُوِّمُ كلَّ لَيلةٍ سَرِيرِى، وبدُمُوعِى أبلُّ فِراشِى. تَعكَّرتْ مِنَ الغَضَبِ عَيْناىَ. هُرِمتُ مِنْ سَائِرِ أعْدائِى. أبْعُدوا عَنِّى يَاجَميعَ فَاعِلى الأثْمِ. لأنَّ الرَّبَّ قَد سَمعَ صَوتَ بُكائِى. الرَّبُّ سَمعَ تَضرُّعِىِ، الرَّبُّ لِصَلاتِى قَبِلَ، فَلْيَخزَ ولْيضْطَربَ جدِّا جَميعُ أعْدائى، ولْيرتدُّوا إلى ورَائِهِمْ بالخِزْى سَريعاً جِدِّا. هَلِّلُويا.'),
      PrayerSection(
          id: 'morning_14',
          title: 'مزمور 8: أيها الرب ربنا',
          body:
              'أيُّهَا الرَّبُّ رَبُّنَا ما أعْجَب إسْمَكَ عَلَى الأرْضِ كلِّهَا، لأنَّهُ قَدِ ارْتفَعَ عِظَمُ جَلالِكَ فَوْقَ السَّمواتِ. مِنْ أفْواهِ الأطْفالِ والرُّضْعانِ هَيَّأتَ سَبْحاً، مِنْ أجْلِ أعْدائِكَ لتُسِكتَ عَدوِّا ومُنْتَقماً. لأنَّى أرَى السَّمواتِ أعْمَالَ يَديْكَ، القَمَرَ والنُّجومَ أنْتَ أسَّسْتَها. مَنْ هُوَ الإنْسانُ حتَّى تَذْكَرهُ. وإبْنُ الإنْسانِ حَتَّى تَفْتَقِدهُ؟ أنْقَصتَهُ قَليلاً عَنِ الملائِكَةِ. بالَمجْدِ والكَرامَةِ تَوُّجْتهُ، وعَلَىِ أعْمَال يَدَيْكَ أقَمْتهُ. كلُّ شَئٍ أخْضَعْت تَحْت قَدَميْهِ. الغَنَمَ والبَقَرَ جَميِعاً وأيْضاً بَهَائِمَ الحَقْل، وطُيورَ السَّماءِ وأسْمَاكَ البَحْر السَّالِكَة فى البِحار. أيُّها الرَّبُّ ربُّنَا، مَا أعْجَبَ أسْمَكَ فى الأرْضِ كلِّها. هَلِّلُويا.'),
      PrayerSection(
          id: 'morning_15',
          title: 'مزمور 11: خلصني يارب',
          body:
              'خَلِّصْنِى يَاربُّ فإنَّ البَارَّ قَدْ فَنَى، وقَدْ قَلَّتِ الأمَانَةُ مِنْ بَنِى البَشَر. تَكَّلم كُلٌ أحَدٍ مَعَ قَريبهِ بالبَاطِلِ. شِفاةٌ غَاشَّةٌ فى قُلوبِهِمْ، وبقُلُوبِهِمْ تكَلَّمُوا. يَسْتأصِلُ الرَّبُّ جَمَيعَ الشِّفاةِ الغَاشَّةِ، واللِّسَانِ النَّاطِقِ بالكِبْريَاءِ، الذِينَ قالُوا نُعظِّمُ ألْسِنَتَنَا. شِفَاهُنا مَعَنا. فَمَن هُوَ يَسُوُد عَلْينا؟ مِنْ أجْل شَقَاءِ المسَاكِين وتَنهُّدِ البَائِسينَ الآنَ أقُومُ، يقُولُ الرَّبُّ، أصْنَعُ الَخَلاصَ عَلانيةً. كَلامُ الرَّبِّ كَلامّ نَقىٌّ، كفِضَّةٍ مُصفَّاةٍ مُجرَّبةٍ فى الأرْض قَدْ صُفِّيتْ سَبْعةَ أضْعَافٍ. وأنْتَ يارَبُّ تُنَجِّينَا وتَحْفَظُنا مِنْ هَذا الجيل وإلى الدَّهْر. المنَافِقُونَ حَوْلَنا يَمْشُونَ مِثْلَ عَظَمَتِكَ. رَفَعْتَ بَنِى البَشَرِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'morning_16',
          title: 'مزمور 12: إلى متى يارب تنساني',
          body:
              'إلَى مَتَى يارَبُّ تَنْسانِى؟ إلَى الإنْقِضَاءِ؟ حَتَّى مَتّى تَصْرفُ وَجْهَك عنِّى؟ إلَى مَتَى أرْدُدْ هَذِهِ المشُورَاتِ فى نَفْسِى، وهَذِهِ الأوْجَاعُ فى قَلْبى النّهَارَ كُلَّه؟ إلَى مَتَى يَرْتفِعُ عَدوِّى عَلىَّ؟ أنْظُرْ وإسْتَجِبْ إلىَّ يَاربِّى وإلَهِى. أنَرْ عَيْنىَّ لِئلاَّ أنَامُ نَومَ الموْتِ، لِئلاَّ يَقولَ عَدوِّى إنِّى قَدْ قَويتُ عَليْهِ. الذينَ يُحْزنُونَنِى يَتهلَّلُونَ إنْ أنَا زَلَلْتُ. أمَّا أنَا فَعَلىِ رَحْمتكَ توَكَّلتُ، يبْتَهجُ قَلبِى بَخَلاصِكَ. أُسبِّحُ الرَّبَّ الَمحْسِن إلىَّ، وأُرتِّل لإسْمِ الرَّبِّ العَالِى. هَلِّلُويا.'),
      PrayerSection(
          id: 'morning_17',
          title: 'مزمور 14: يارب من يسكن في مسكنك',
          body:
              'يارَبَّ مَنْ يَسْكنُ فى مَسْكنِكَ، مَنْ يَحلُّ فى جَبَل قُدْسِكَ؟ السَّالِكُ بِلاعَيبٍ. والفَاعِلُ البِرَّ، والمتكَلِّمُ بالَحَقِّ فى قَلْبهِ، الذِى لا يَغشُّ بلِسَانهِ، ولا يَصْنعُ بقَريبِهِ سُوءاً، ولا يَقْبلُ عَاراً عَلى جِيرانِهِ. فاعِلُ الشَّرِّ مَرْذُولٌ أمَامَه، ويُمجِّدُ الذِين يتَّقُونَ الرَّبَّ. الذِى يَحْلفُ لِقَريبِهِ، ولايَغْدرُ بهِ. ولايُعْطِى فِضَّتَهُ بالرِّبَا، ولا يَقْبلُ الرَّشْوةَ عَلَى الأبْرِياء، الذِى يَصْنعُ هَذا لايَتَزعْزعُ إلَى الأبَدِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'morning_18',
          title: 'مزمور 15: احفظني يا رب',
          body:
              'إحْفَظْنِى يا رَبُّ فإنِّى عَليْكَ تَوكَّلتُ. قُلتُ للرَّبِّ أنْتَ رَبِّىِ. ولا تَحْتاجُ إلى صَلاحِى. أظْهَرَ عَجائِبَهُ لِقدِّيسِيهِ الذِينَ فى أرْضِهِ، وصَنعَ فِيِهمْ كلَّ مِشيئاتِهِ. كَثُرتْ أمْراضُهُمْ الذِينَ أسْرَعوا وَراءَ الهٍ آخَرَ، لا أشْتَركُ فى قَرابِينِهِم مِنَ الدِّماءِ، ولا أذْكرُ أسْمَاءَهُم بشَفَتىَّ، الرَّبُّ هُوَ نَصيبُ مِراثِى وكأسِي، أنْتَ الذِى تَردُّ إلىَّ مِيرَاثِى. حِبالُ التَّقْسِيمِ وقَعَتْ لِى فى أرْضٍ خِصْبَةٍ. وإنَّ مِيراثِى لَثَابتٌ لِى.\nأُبارِكُ الرَّبَّ الذِى أفْهَمنِى. وأيْضاً إلَى اللَّيلِ وعَظَتْنى كُلْيَتاىَ، تقدَّمتُ فرأيْتُ الرَّبَّ أمامِى فى كُلِّ حينٍ، لأنَّه عَنْ يَمينِى لِكْى لا أتَزَعْزعَ، مِنْ أجْل هَذا فَرِحَ قَلْبى وتَهلَّلَ لِسَانِى. جَسَدِى أيْضاً يسْكنُ عَلىِ الرَّجاءِ. لأنَّكَ لاتَتْركُ نَفْسى فى الجحِيمِ. ولاتَدَعُ قُدُّوسَكَ يَرَى فَساداً. قَدْ عَرَّفتْنِى سُبُل الحَياةِ. تَمْلأنِى فَرحاً أمامَ وجْهكَ. البَهجَةُ فى يَمينِكَ إلَى الإنْقِضاءِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'morning_19',
          title: 'مزمور 18: السموات تحدث بمجد الله',
          body:
              'السَّموات تُحدِّثُ بِمَجْدِ الله. والفَلَكُ يُخْبرُ بعَمَلِ يَديْهِ. يَومِّ إلى يَوْمٍ يُبْدى قَولاً. ولَيلِّ إلَى ليلٍ يُظْهرُ عِلْماً. لاقولَ ولاكلامَ، الذِينَ لاتَسْمعُ أصْوَاتَهُم. فى كلِّ الأرْضِ خَرَجَ مَنْطقُهُم. وإلَى أقْصَى المسْكُونةِ بَلغتْ أقْوالُهُم. جَعَلَ فى الشَّمْسِ مِظلتَهُ. وهِىَ مِثلُ العَريسِ الخَارجِ مِنْ خِدْرهِ. يتَهلَّلُ مِثْل الجَبَّار الذِى يُسْرعُ فى طَريقِهِ. مِنْ أقْصَى السَّماءِ خُروجُها، ومُنْتهَاهَا إلَى أقْصَى السَّماءِ ولا شَئ يخْتَفى مِنَ حَرارَتْهَا.نَامُوسُ الرَّبِّ بِلاَعَيبٍ، يَردُّ النُّفوسَ. شَهادَةُ الرَّبِّ صادِقَةٌ، تُعلِّمُ الأطْفال. فَرائِضَ الرَّبِّ مُسْتقِيمةٌ، تُفْرحُ القَلْب. وَصيَّةُ الرَّبِّ مُضيئةٌ. تُنَيرُ العَيْنيْنِ عَنْ بُعدٍ. خَشْيةُ الرَّبِّ زَكيَّةٌ، دَائمَةٌ إلَى أبَدِ الأبَدِ. أحْكامُ الرَّبِّ أحْكامُ حَقِّ وعادِلةٌ مَعاً. مَشِيئةُ قَلْبهِ مُخْتارَةٌ أفْضَلُ مِنَ الذَّهَبِ والحَجَرِ الكَثِيرِ الثَّمنِ، وأحْلَى مِنَ العَسَلِ والشَّهدِ. عَبْدكَ يَحْفظُها، وفى حِفْظهَا ثَوابٌ عَظِيمٌ. الهَفَواتُ مِنَ يَشْعرُ بِهَا؟ مِنَ الخَطايَا المسْتَتِرةُ يَاربُّ طهِّرِنى. ومِنَ المتكبِّرينَ أحْفَظْ عَبْدَكَ، حَتَّى لايَتسَلَّطوا عَلىَّ فَحينَئذٍ أكُونُ بِلا عَيبٍ، وأتَنقَّى مِنْ خَطيَّةٍ عَظِيمةٍ، وتَكونُ جَميعُ أقْوالِ فَمِى وفِكْرِ قَلبىِ مَرضِيَّةً أمَامَكَ فى كلِّ حينٍ. يَاربُّ أنتَ مُعيِنى ومُخلِّصِى. هَلِّلُويا.'),
      PrayerSection(
          id: 'morning_20',
          title: 'مزمور 24: إليك يارب رفعت نفسي',
          body:
              'إلَيكَ يَارَبُّ رفَعْتُ نَفْسِى. يا إلهِى عَليْكَ تَوكَّلتُ. فَلاَ تُخْزنِى إلى الأبَدِ. ولا تُشْمِتْ بى أعْدائِى. لأنَّ جِميعَ الذِينَ ينْتظِرونَكَ لا يُخَزَونَ. ليُخْزَ الذِينَ يصْنَعونَ الإثْمَ باطِلاً. أظْهِرْ لى يَاربُّ طُرقَكَ، وعلِّمْنى سُبُلَكَ. إهْدِنى إلى عَدلِكَ وعلِّمْنِى. لأنَّكَ أنتَ هُو اللهُ مُخلِّصِى. وإيَّاكّ إنْتَظرتُ النَّهارَ كلَّهُ. إذْكُر يَاربُّ رَأْفاتِكَ ومَراحِمَك، لأنَّهَا ثَابتَةٌ مُنذُ الأزلِ. خَطايَا شَبَابِى وجَهْلى لا تُذْكَر. كَرحْمتِك إذْكُرنِى أنْتَ منْ أجْلِ خَلاصكَ يَاربُّ. الرَّبُّ صَالحِّ ومُسْتَقيمٌ، لِذلِكَ يُرشِدُ الذِينَ يُخْطئونَ فى الطَّريقِ. يَهْدى الوُدعَاءَ فى الحُكْمِ، يُعلِّمُ الوُدعَاءَ طُرقَهُ. جَميعُ طُرق الرَّبِّ رَحْمةٌ وحَقٌ لحَافِظِى عَهْدهِ وشَهَادَاتِه. مِنْ أجْلِ إسْمِكَ يارَبُّ إغْفِر لى خَطيَّتِى لأنَّها كَثيرةٌ. مَنْ هُو الإنْسانُ الخَائفُ الرَّبِّ، يرْشِدهُ فى الطَّريقِ التِى إرْتَضَاهَا. نَفْسهُ فى الخَيْراتِ تثْبُتُ، ونَسْلهُ يَرثُ الأرْضَ. الرَّبِّ عزٌّ لخَائفِيهِ. وإسْمُ الرَّبِّ لأتْقيَائه. ولَهُم يُعْلنُ عَهدَه. عَيْناىَ تَنْظرَان إلى الرَّبِّ فى كلِّ حينٍ. لأنَّهُ يُخْرجُ مِنْ الفخِّ رِجْلَىَّ. إنْظُرْ إلىَّ وأرْحَمنِى. لأنِّى إبنٌ وَحِيدٌ وفَقِيرٌ أنَا. أحْزانُ قَلبِى قَدْ كثُرَتْ. أخْرِجْنِى مِنْ شَدائِدِى. أنْظُر إلى ذُلِّى وتَعَبى. وأغْفِرْ لى جَمِيعَ خَطايَاىَ. أنْظُر إلى أعْدائِىِ فإنَّهمْ قَد كَثُرُوا وأبّغَضونِى ظلْماً. أحْفَظْ نَفْسِى ونَجِّنِى، لا أخْزَى لأنِّى عَليكَ تَوكَّلتُ. الذِينَ لا شَرَّ فِيهمْ والمسْتَقيمُونَ لَصقُوا بى، لأنِّى إنْتظَرْتَكَ يارَبُّ. يا اللَّهُ إنْقذْ إسْرائِيلَ مِنْ جَمِيعِ شَدائِدِهِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'morning_21',
          title: 'مزمور 26: الرب نوري وخلاصي',
          body:
              'الرَّبُّ نُورِى وخَلاصِى مِمَّن أخَافُ. الرَّبُّ نَاصِرُ حَياتِى مِمَّن أجْزَعُ. عِندَ اقْتِرابِ الأشْرارِ مِنِّى لِيأْكُلوا لحْمِى، مُضايقَىَّ وأعْدائِى عَثُروا وسَقَطُوا. إنْ يُحارِبَنِى جَيشٌ فلَنْ يَخافَ قَلْبى. إنْ قامَ علىَّ قِتالٌ فَفى هَذا أنَا أطَمْئنُّ. وَاحِدة سَألتُ مِنَ الرَّبِّ وإيَّاهَا ألْتمسُ. أنْ أسْكُنَ فى بَيتِ الرَّبِّ كلَّ أيَّامِ حَياتِى. لِكىْ أنْظرَ نَعيمَ الرَّبِّ، أتَفرَّسَ فى هَيْكلِه المقُدَّسِ. لأنَّهُ أخْفانِى فى خَيْمتِهِ، فى يَومِ شِدَّتِى، سَتَرنِى بسِتْرِ مِظلَّتهِ. وعَلَى صَخْرةٍ رفَعَنى. والآنَ هُوذَا قَدْ رَفَع رَأسِى عَلَى أعْدائِى. طُفْتُ وذَبَحْتُ فى مِظلَّتِه ذَبيحَةَ التَّهْليلِ. أسبِّحُ وأرتِّلُ للرَّبِّ. اسْتَمعْ يارَبُّ صَوْتِى الذِى بِهِ دَعوتُكَ. ارْحَمنِى واسْتَجبْ لى فإنَّهُ لكَ قالَ قلْبِى: طَلبْتُ وجْهَك، ووَجْهَك ياربُّ ألْتمِسُ. لا تَحْجبْ وجْهَك عنِّى ولا تُعْرضْ بغَضَبٍ عَن عَبْدكَ. كُنْ لى مُعيناُ. لا تخْذُلنِى ولا تَرْفضنِى يَا اللهُ مُخلِّصِى. فإنَّ أبِى وأُمِّى قَدْ ترَكانِى، وأمَّا الرَّبُّ فقبِلَنِى. علِّمْنىِ ياربُّ طّريقَكَ وأهْدِنى فى سَبِيلٍ مسْتَقيمٍ مِنْ أجل أعدائىِ. لا تسلمَنى إلى أيدى مُضايِقىَّ، لأنَّه قَدْ قامَ عَلىَّ شُهودُ زُورٍ. وكَذبُوا عَلىَّ ظُلماً. أنَا أؤمِنُ أنِّى أُعايِنُ خَيْرات الرَّبِّ فى أرْض الأحْياءِ. أنْتظِرِ الرَّبِّ تَقوَّ وليتَشَدَّدْ قلْبكَ وأنْتَظِر الرَّبِّ. هَلِّلُويا.'),
      PrayerSection(
          id: 'morning_22',
          title: 'مزمور 62: يا الله إلهي إليك أبكر',
          body:
              'يا اللَّهُ إلَهِى إليْكَ أُبكِّرُ. إذْ عَطِشَتْ إلَيكَ نَفْسِى. يَشْتاقُ إليْكَ جَسَدِى، فى أرْضٍ مُقفِرةٍ وموْضِعٍ غَيرِ مَسْلوكٍ ومَكانٍ بِلا مَاءٍ. هَكَذا ترَاءيْتَ لَكَ فى القُدسِ، لأرَى قُوَّتكَ ومَجْدكَ. لأنَّ رحْمتَكَ أفْضَلُ مِنَ الحَياةِ، شَفَتاىَ تُسبِّحانِكَ. لذلِكَ أُباركُكَ فى حَياتِى، وباسْمِكَ أرْفَع يَدِىَّ. فتَشَبعُ نَفْسِى كَما مِنْ شَحْمٍ ودَسَمٍ، بشِفاةِ الإبْتِهاجِ نُبارِكُ أسْمَكَ. كنْتُ أذْكرُكَ عَلى فِراشِى. وفى أوْقاتِ الأسْحَارِ كُنتُ أرتِّل لَكَ. لأنَّكَ صِرْتَ لى عَوناً، وبِظلِّ جَنَاحَيكَ أبْتَهجُ. إلْتَصقَتْ نَفْسىِ بكَ، ويَمينُكَ عَضَّدتْنِى، أمَّا الذِينَ طلَبُوا نَفْسى للْهَلاكِ، فيَدْخلُونَ فى أسافِلِ الأرْضِ. ويُدْفَعونَ إلى يَدِ السَّيْفِ، وَيكونُونَ أنْصِبَةً للثَّعالِبِ. أمَّا الملِكُ فَيفْرحُ باللهِ، ويفْتَخرُ كلُّ مَنْ يَحلفُ بهِ. لأنَّ أفْواهَ المتَكلِّمينَ بالظَّلمِ تُسَدُّ. هَلِّلُويا.'),
      PrayerSection(
          id: 'morning_23',
          title: 'مزمور 66: ليتراءف الله علينا',
          body:
              'لِيتَراءفَ اللَّهُ عَلينَا ولِيُباركِنَا، وليُنِرْ بوجْهِهِ عَليْنَا ويَرْحَمْنا. لَتُعْرفَ فى الأرْض طَريقُكَ، وفى جَميعِ الأممِ خَلاصُكَ. فلْتَعْتَرَفْ لكَ الشَّعوبُ يااللَّهُ، فلْتَعْترفْ لكَ الشُّعوبُ كلُّها. لتَفْرَح الأمَمُ وتَبْتهجُ، لأنَّكَ تدِينُ الشَّعوبَ بالإسْتِقامَةِ وتَهْدى الأممَ فى الأرْض. فلْتَعْتَرفْ لَكَ الشُّعوبُ يَااللَّهُ، فلْتَعْتَرفْ لَكَ الشُّعوبُ جَميعاً الأرْضُ أعْطَتْ ثَمَرتَها. فَليُبارِكنَا اللهُ إلهنَا. لِيُباركنَا اللهُ. فَلْتَخشَهُ جَميعُ أقْطارِ الأرْضِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'morning_24',
          title: 'مزمور 69: اللهم التفت إلى معونتي',
          body:
              'اللَّهُمَّ إلْتَفتْ إلى مَعُونَتِى، يَاربُّ أسْرعْ وأعِنِّى. ليُخْزَ ويَخْجَل طَالبُو نَفْسى، وليرْتَدَّ إلى خَلْفٍ ويَخْجَل الذِينَ يبْتَغونَ لى الشَّرَّ. وليرْجعَ بالخِزْىِ سَريعاً القَائِلونَ لى نَعماً نعمَا. ولِيبْتَهجْ ويَفْرَح بكَ جَميعُ الذِينَ يلْتمسُونِكَ، ولِيَقَل فى كلِّ حينٍ مُحبُّو خَلاصِكَ لِيتعَظَّمَ الرَّبُّ. وأمَّا أنَا فمِسْكينٌ وفَقِيرٌ. اللَّهمَّ أعِنِّى. أنْتَ مُعينِى ومُخلِّصِى يَاربُّ فَلا تُبْطِئ. هَلِّلُويا.'),
      PrayerSection(
          id: 'morning_25',
          title: 'مزمور 112: سبحوا الرب أيها الفتيان',
          body:
              'سبِّحُوا الرَّبِّ أيُّها الفتِيانُ، سَبِّحُوا إسْمَ الرَّبِّ. لِيَكُنِ إسْمُ الرَّبِّ مُبارَكاً مِنَ الآنِ وإلى الأبَدِ. مِنْ مَشَارقِ الشَّمْسِ إلى مَغارِبِها بَاركُوا إسْمَ الرَّبِّ. الرَّبُّ عَالٍ عَلى كلِّ الأمُمِ، فَوْقَ السَّمَوات مَجْدهُ. مَنْ مِثْلُ الرَّبِّ إلَهنَا السَّاكِنِ فى الأعَالى، النَّاظِرِ إلى المتَواضِعِينَ فى السَّماءِ وعَلى الأرْضِ. المقِيمِ المسْكِينَ مِنَ التُّرابِ، الرَّافِع البَائِسِ مِنَ المزْبَلةِ، لِكىْ يُجْلسَهُ مَعَ رُؤسَاءِ شَعْبهِ. الذِى يَجْعلُ العَاقِرَ ساكِنَة فى بَيْتٍ، أمَّ أوْلادٍ فرِحةً. هَلِّلُويا.'),
      PrayerSection(
          id: 'morning_26',
          title: 'مزمور 142: يارب اسمع صلاتي',
          body:
              'يارَبُّ إسْمَع صَلاتِى. إنْصِتْ إلى طَلبَتِى بَحَقِّكَ. إسْتَجبْ لى بَعدْلِكَ. ولا تدْخُلْ فى المحَاكَمةِ مَعَ عَبْدكَ فإنَّهُ لَنْ يَتَزكَّىِ قُدَّامكَ كلُّ حَىِّ. لأنَّ العَدوَّ قدِ إضْطهدَ نَفْسِى، وأذَلَّ فى الأرْضِ حَياتِى. أجْلسَنِى فى الظَلَّمَاتِ مِثْلَ الموْتَى مُنْذُ الدَّهرٍ. أضّجَرتْ فى رُوحى، إضْطَربَ فى قَلْبِى. تذكَّرتُ الأيَّامَ الأولَى ولَهِجْتُ فى كلِّ أعْمالِكَ، وفى صَنائِع يَدَيْك كنْتُ أتَأمَّلُ. بَسَطتُ إليْكَ يَدىَّ، صَارتْ نَفْسِى لكَ مِثلُ أرْضٍ بِلا مَاءٍ. إسْتَجبْ لى يَاربُّ عاجلاً فَقَد فَنِيتْ رُوحِى، لا تَحْجبْ وجْهَكَ عنِّى فأشَابهُ الهابِطينَ فى الجُبِّ. فلأسْمَعْ فى الغَدَاةِ رحْمَتكَ، فإنِّى عَليكَ تَوكَّلتُ. عرِّفْنِى يارَبُّ الطَّريقَ التى أسْلُكَ فِيهَا لأنِّى إليْكَ رفَعْتُ نَفْسِى. إنْقِذْنِى مِنْ أعْدائِى يارَبُّ، فإنِّى لجأْتُ إليْكَ. علِّمنِى أنْ أصْنَعَ مَشِيئتَكَ، لأنَّك أنْتَ هُو إلهِى. رُوحُكَ القُدُّوسُ فَليهْدنِى إلى الإسْتِقامَةِ. مِنْ أجْلِ إسْمِكَ ياربُّ تُحْيِينِى، بَحَقِّكَ تُخْرجُ مِنَ الشِّدَّةِ نَفْسى. وبرَحْمتِكَ تَسْتأصِلُ أعْدائِى، وتُهلِكَ جُميعَ مُضايقى نَفْسِى لأنِّى أنَا هُو عَبْدكَ أنَا. هَلِّلُويا.'),
      PrayerSection(
          id: 'morning_27',
          title: 'الإنجيل (يوحنا 1:1-17)',
          body:
              'فى البَدْءِ كَانَ الكَلِمةَ، والكَلِمةُ كانَ عِنْدَ اللهِ، وكانَ الكَلِمةَ اللَّهُ. هَذا كانَ فى البَدءِ عِنْدَ اللهِ. كلُّ شئٍ بهِ كانَ، وبِغيرهِ لمْ يَكُن شَئٍ مْمَّا كانَ. فِيهِ كانَتِ الحَياةُ والحَياةُ كَانَتْ نُورَ النَّاسِ والنُّورُ أضَاءَ فى الظَّلْمةِ، والظَّلْمةُ لَمْ تُدْركهُ. كانَ إنْسانٌ مُرْسَلٌ مِنَ اللهِ أسْمُه يُوحَنَّا، هَذَا جَاءَ للشَّهَادةِ لِيشْهَد للنُّورِ لِيؤمِنَ الكُلُّ بوَاسِطتهِ. لَمْ يَكُن هُوَ النُّورُ بَلْ ليشْهَدَ للنَّورِ. كانَ النُّورُ الحَقِيقىُّ الذِى يُنِيرُ كلَّ إنْسَانٍ آتِياً إلى العَالمِ. كانَ فى العَالَم وكَونُ العَالَم بهِ ولَمْ يَعْرفْهُ العَالَمُ. إلى خاصَّتِه جَاءَ، وخاصَّتُهُ لَمْ تَقْبلْهُ. وأمَّا الذِينَ قَبلُوهُ فأعْطاهُمْ سُلْطاناً أنْ يَصيرُوا أبْنَاءَ اللهِ الذِينَ يُؤمنُونَ بإسْمِهِ، الذِينَ وُلدُوا لَيسَ مِنْ دَمٍ، ولا مِنْ مَشِيئةِ جَسَدٍ، ولا مِنْ مَشِيئةِ رَجُلٍ، لِكنْ مِنَ اللهِ وُلدُوا. والكَلمةُ صارَ جَسَداً وحَلَّ بَيْننَا ورَأينَا مَجْدهُ مِثْل مَجدِ إبْنٍ وَحيدِ لأبِيهِ مَمْلوءاً نِعْمةً وحَقَّا. يُوحنَّا شَهِدَ لَهُ وصَرخَ قائِلاً: هَذا هُو الذِى قلْتُ عَنْهِ أنَّ الذِى يَأتِى بَعْدِى كانَ قَبْلِى، حَقَّا كانَ أقْدَمَ مِنِّى، ونَحنُ جَميعاً أخَذْنا مِنَ إمتِلائِه، ونعْمةً عِوضاً عَنْ نِعْمةٍ. لأنَّ النَّامُوسَ بَمُوسَى أعْطَى، أمَّا النِّعْمةُ والحَقُّ فبيَسُوع المسَيح صَاراَ. والمجْدَ للَهِ دَائماً.'),
      PrayerSection(
          id: 'morning_28',
          title: 'القطعة الأولى',
          body:
              'أيُّهَا النُّورُ الحَقِيقىُّ الذِىِ يُضئُّ لِكلِّ إنْسَانٍ آتٍ إلى العَالَمِ، أتَيْتَ إلى العَالَم بِمَحِّبتَكَ للبَشَرِ، وكلُّ الخَلِيقَةِ تَهَّللَت بْمَجِيِئكَ. خَلَّصْتَ أبَانَا أدَمَ مِنَ الغِوايَةِ، وعتَقْتَ أمَّنَا حَواءَ مِنْ طَلقَاتِ الموْتِ وأعْطَيتنَا رُوحَ البُنوَّةِ، فَلنسَبِّحْكَ ونُبارِككَ قائِلينَ. ( ذُوكصَابترى )'),
      PrayerSection(
          id: 'morning_29',
          title: 'القطعة الثانية',
          body:
              'عِنْدمَا دِخَلَ إليْنَا وقْتَ الصَّباحِ أيُّهَا المسَيحُ إلهنَا النّورُ الحَقِيقى، فَلتشْرقْ فَينَا الحَواسُّ المضِيئةُ والأفْكارُ النُّورانَّيةُ. ولا تُغَطِّينَا ظُلْمة الآلاَمِ، لِكىْ نُسبِّحكَ عَقليَّاً مَعَ دَاودَ قَائلينَ: "سَبَقَتْ عَيْنَاىَ وقْتَ السَّحَر لأتَلُو فى جَمِيعِ أقْوالِكَ". إسْمَعُ أصْواتَنَا كعَظيَم رَحْمَتِكَ، ونجِّنا أيُّها الرَّبُّ إلهنَا بَتحنُّنكَ. ( كى نين )'),
      PrayerSection(
          id: 'morning_30',
          title: 'القطعة الثالثة',
          body:
              'أنْت هِىَ أمُّ النُّورِ المكرَّمةُ مِنْ مَشَارقِ الشَّمسِ إلى مَغارِبَها، يُقدِّمُونَ لَكَ تَمْجيدَات يَاوَالدَة الإلَهِ السَّماء الَّثانِيَة، لأنَّكَ أنْتَ هِىَ الزَّهْرةُ النَّيِّرةُ غَيْر المتَغيِّرةِ والأمُّ البَاقِيةَ عَذْراءَ لأنَّ الآب إخْتَارك والرُّوحَ القُدُس ظَلَّلك والأبْنَ تَنازَلَ وتَجسَّدَ مِنْك. فإسْألِيهِ أنْ يُعْطىَ الخَلاصَ للعالَمِ الذِى خَلقَهُ، وأنْ يُنجيَهُ مِنَ التَّجارِبِ. ولنُسَبِّحهُ تَسْبيحاً جَدِيداً ونُباَرِكهُ الآنَ وكُلَّ أوانٍ وإلى الأبَدِ. آمين.'),
      PrayerSection(
          id: 'morning_31',
          title: 'تسبحة الملائكة',
          body:
              'فَلْنُسبِّحْ مَعَ الملائِكةِ قائِلينَ: المجْدُ للهِ فى الأعالِى وعَلَى الأرْضِ السَّلامُ وَفى النّاسِ المسَرَّةُ. نُسَبِّحكَ. نُبارِككَ. نَخْدمُكَ. نَسْجُدُ لَكَ. ونَعْترِفُ لكَ. نَنْطقُ بمَجْدكَ. نَشْكُركَ مِنْ أجْل عِظَمِ مَجْدكَ. أيُّها الرَّبُّ المالِكُ عَلَى السَّمواتِ اللهُ الآبُ ضابِطُ الكُلِّ، والرَّبُ الابْنُ الواحدُ الوَحيدُ يسوعُ المسيحُ، والرّوحُ القُدُسُ. أيُّها الرِّبُّ الإلَهُ حَمَل الله إبْنَ الآبِ رافِعَ خَطِيّةِ العالَم إرْحَمْنا. يا حَامِلَ خطيَّةِ العالَم اقْبَل طَلَباتِنا إليْكَ. أيُّها الجالسُ عَنْ يَمينِ أبيهِ ارْحَمْنا. أنْتَ وحْدَكَ القُدّوسُ. أنْتَ وحْدَكَ العالى يا رَبّى يسوعُ المسيحُ والرّوحُ القُدُسُ. مَجْداً للهُُُ الآبَ آمين. أُبارِككَ كُلَّ يَومٍ، وأسبِّحُ إسْمَكَ القُدّوسَ إلَى الأبَدِ وإلَى أبَدِ الأبَدِ آمين. مُنْذُ اللَّيلِ روحى تُبَكرُ إليْكَ يا إلَهى، لأنَّ أوامِركَ هِىَ نورٌ عَلَى الأرْضِ. كنْتُ أتْلو فى طُرقكَ، لأنَّكَ صِرْتَ لِى مُعيناً. باكراً يا ربُّ تَسْمعُ صوْتى، بالغَداةِ أقِفُ أمامكَ وتَرانى.'),
      PrayerSection(
          id: 'morning_32',
          title: 'الثلاث تقديسات',
          body:
              'قُدّوسٌ اللَّهُ. قُدّوسٌ القَوىُّ. قُدّوسٌ الحَىُّ الَّذى لا يَموتُ الَّذى وُلِدَ مِنَ العَذْراءِ إرْحَمْنا. قُدّوسٌ اللَّهُ. قُدّوسٌ القَوىُّ. قُدّوسٌ الحَىُّ الَّذى لا يَموتُ الَّذى صُلِبَ عنّا إرْحَمْنا. قُدّوسٌ اللَّهُ. قُدّوسٌ القَوىُّ. قُدّوسٌ الحَىُّ الَّذى لا يَموتُ الّذى قامَ مِنَ الأمْواتِ وصَعِدَ إلَى السَّمواتِ إرْحَمْنا. المجْدُ للآبِ والإبنِ والرّوحِ القُدُسِ، الآنَ وكلُّ أَوان وإلَى دَهْرِ الدّهورِ آمين. أيُّها الثّالوثُ القُدّوسُ إرْحَمْنا، أيُّها الثّالوثُ القُدّوسُ إرْحَمْنا، أيُّها الثّالوثُ القُدّوسُ إرْحَمْنا، يا رَبُّ إغْفِرْ لَنا خَطايانا. يا رَبُّ إغْفِرْ لَنا آثامَنا، يا رَبُّ إغْفِرْ لَنا زَلاّتَنا. يا رَبُّ إفْتَقدْ مَرْضَى شَعْبكَ، إشْفِهمْ مِنْ أجْل إسْمكَ القُدّوسِ. آباؤُنا وإخْوَتنا الَّذينَ رَقدوا يا رَبُّ نَيِّحْ نُفوسَهُم، يا مَنْ هُوَ بِلا خَطيَّة يا رَبُّ إرْحَمْنا، يا الَّذى بِلا خَطيَّةِ يا رَبُّ أَعِنّا، واقْبَلْ طَلباتِنا إلَيْكَ. لأنَّ لَكَ المجْدَ والعِزَّةَ والتَّقْديسَ المثلَّثَ. يا رَبُّ إرْحَمْ، يا رَبُّ إرْحَمْ، يا رَبُّ بارِكْ. آمين.'),
      PrayerSection(
          id: 'morning_33',
          title: 'الصلاة الربانية',
          body:
              'اللَّهُم اجْعلنا مُستحِقين أنْ نقولَ بِشكرٍ:\nأبانا الذي في السَّمَواتِ، لِيتَقدس اسْمكَ. ليأتِ مَلكوتُكَ. لتَكن مَشيئَتُكَ، كما في السّماءِ كَذلك على الأرْضِ. خُبزَنا الذي للغدِ اعطِنا اليومَ. واغفِر لنا ذنوبَنا كما نغْفر نحنُ أيضّا للمذنبينَ إلينا. ولا تُدخِلنا في تَجرِبةٍ. لكن نجّنا مِنْ الشّريرِ. بالمسيحِ يسوعُ ربُّنا، لأنَّ لَكَ المُلكَ والقوةَ والمجدَ إلى الأبدِ. آمين.'),
      PrayerSection(
          id: 'morning_34',
          title: 'السلام لك',
          body:
              'السَّلامُ لَك. نَسْألكِ أيَّتُها القِدّيسَةُ الممْتَلِئةُ مَجْداً العَذْراءُ كلَّ حينٍ والِدةُ الإلَهِ أمُّ المسيحِ، أصْعدى صَلَواتَنا إلَى إبْنِكِ الحَبيبِ ليغْفِرَ لَنا خَطايانا. السَّلامُ لِلَّتى وَلَدتْ لَنا النّورَ الحَقيقىَّ المسيحَ إلَهنا العَذْراءُ القدّيسَةُ، إسْألى الرَّبَّ عنّا ليَصْنَعَ رَحْمَةً مَعَ نُفوسِنا ويغْفر لَنا خَطايانا. أيَّتُها العَذْراءُ مَرْيَم والِدةُ الإلهِ القِدّيسَةُ الشَّفيعَةُ الأمينَةُ لجنْسِ البَشرِيّةِ، إشْفَعى فينا أَمامَ المَسيحِ الَّذى وَلدْتيهِ لِكَىْ يُنْعِم عَلَيْنا بغُفْران خَطايانا. السَّلامُ لَكِ أيَّتُها العَذْراءُ الملِكةُ الحَقيقيَّةُ. السَّلامُ لفَخْر جنْسِنا، وَلدْتِ لَنا عمّانوئيل. نَسْألُكِ اذْكرينا أيَّتُها الشَّفيعَةُ المؤْتَمَنةُ أَمامَ ربِّنا يَسوعِ المسيحِ ليغْفِرَ لَنا خَطايانا.'),
      PrayerSection(
          id: 'morning_35',
          title: 'بدء قانون الإيمان',
          body:
              'نُعظِّمُكِ يا أمَّ النّورِ الحَقيقىِّ ونُمجِّدكِ أيَّتُها العَذْراءُ القِدّيسةُ والِدةُ الإلهِ لأنَّكِ وَلدْتِ لَنا مُخلِّصَ العالَم، أتَى وخَلَّصَ نُفوسَنا. المجْدُ لكَ يا سَيِّدُنا ومَلكُنا المسيحُ، فَخْرَ الرُّسُل، إكْليلَ الشُهداءِ، تَهْليلَ الصِدّيقينَ، ثَباتَ الكَنائسِ، غُفْرانَ الخَطايا. نُبشِّرُ بالثَّالوثِ القُدّوسِ، لاهوتٌ واحِدٌ نَسجُدُ لهُ ونُمجِّدهُ يا رَبُّ إرْحَم. يا رَبُّ إرْحَم. يا رَبُّ بارِك. آمين.'),
      PrayerSection(
          id: 'morning_36',
          title: 'قانون الإيمان',
          body:
              'بالحَقيقَةِ نُؤمِنُ بإلهٍ واحدٍ اللَُّهُ الآبُ ضابطُ الكُلِّ خالِقُ السَّماءِ والأرضِ، ما يُرَى وما لا يُرَى.\nنُؤمِنُ بربٍّ واحدٍ يَسوعِ المسيحِ إبْن اللهِ الوَحيدِ الموْلودِ مِنَ الآبِ قَبْلَ كلِّ الدُّهورِ. نورٌ مِنْ نورٍ إلهٌ حَقٌ مِنْ إلهٍ حَقٍّ، مَولودٌ غَيْرُ مَخْلوقٍ، مُساوٍ للآبِ فى الجَوْهرِ. الَّذى بِهِ كانَ كلُّ شئٍ. هَذا الَّذى مِنْ أجْلنا نَحنُ البَشَرَ ومِنْ أجْلِ خَلاصِنا نَزلَ مِنَ السَّماءِ وتَجسَّدَ مِنَ الرّوحِ القُّدُسِ، ومِنْ مَرْيَم العَذْراءِ تَأنَّسَ. وصُلبَ عنّا علَى عَهدِ بيلاطُس البنْطى، تألَّمَ وقُبرَ وقامَ مِن بَين الأمْواتِ فى اليَومِ الثّالثِ كَما في الكتُبِ، وصَعِدَ إلَى السَّمواتِ وجَلسَ عَنْ يَمينِ أبيهِ وأيْضاً يَأتي فى مَجدهِ ليُدينَ الأحْياءَ والأمْوات َ، الَّذى لَيسَ لملْكِهِ إنْقِضاءٌ. نَعَم نُؤمِنُ بالرّوحِ القُدُسِ، الرَّبُّ المحْيى المنْبَثقِ مِنَ الآبِ نَسْجُد لهُ ونُمجِّدهُ مَعَ الآبِ والإبْنِ النّاطِقِ فى الأنْبياءِ. وبكنيسَةٍ واحِدَةٍ مُقدَّسةٍ جامعَةٍ رسوليَّةٍ، ونَعْترِفُ بمَعْموديَّةٍ واحِدَةٍ لمغْفِرَةِ الخَطايا. وننْتَظرُ قِيامَةَ الأمْواتِ وحَياةَ الدَّهرِ الآتى. آمين.'),
      PrayerSection(
          id: 'morning_37',
          title: 'يارب ارحم 41 مرة',
          body: 'يُقال ( كيريى لَيْسُون ) يَارَبُّ ارْحَمْ 41 مرة.'),
      PrayerSection(
          id: 'morning_38',
          title: 'قدوس قدوس قدوس',
          body:
              'قُدّوسٌ قُدّوسٌ قُدّوسٌ رَبُّ الصَّباؤوتِ. السَّماءُ والأرْضُ مَمْلوءتانِ مِنْ مَجْدكَ وكَرامَتكَ. إرْحَمْنا يا اللَّهُ الآبُ ضابِطُ الكُلِّ، أيُّها الثّالوثُ القُدّوسُ إرْحَمْنا. أيُّها الرَّبُّ إلهُ القُوّاتِ كُنْ مَعَنا، لأنَّهُ لَيسَ لَنا مُعينٌ فى شَدائِدنا وضيقاتِنا سِواكَ. حلّ واغْفِرْ واصْفَحْ لَنا يا اللَّهُ عَنْ سَيِّئاتِنا الَّتى صَنَعْناها بإرادَتِنا والَّتى صَنَعْناها بغَيرِ إرادَتنا، الَّتى فَعلْناها بمَعرِفةٍ والَّتى فَعلْناها بغَير مَعْرِفةٍ، الخَفيَّةِ والظاهِرةِ، يا رَبُّ اغْفِرها لَنا مِنْ أجْلِ إسْمِكَ القُدّوسِ الَّذى دُعى عَليْنا. كَرحْمتِكَ يا رَبُّ ولا كَخَطايانا.'),
      PrayerSection(
          id: 'morning_39',
          title: 'الصلاة الربانية',
          body:
              'اللَّهُم اجْعلنا مُستحِقين أنْ نقولَ بِشكرٍ:\nأبانا الذي في السَّمَواتِ، لِيتَقدس اسْمكَ. ليأتِ مَلكوتُكَ. لتَكن مَشيئَتُكَ، كما في السّماءِ كَذلك على الأرْضِ. خُبزَنا الذي للغدِ اعطِنا اليومَ. واغفِر لنا ذنوبَنا كما نغْفر نحنُ أيضّا للمذنبينَ إلينا. ولا تُدخِلنا في تَجرِبةٍ. لكن نجّنا مِنْ الشّريرِ. بالمسيحِ يسوعُ ربُّنا، لأنَّ لَكَ المُلكَ والقوةَ والمجدَ إلى الأبدِ. آمين.'),
      PrayerSection(
          id: 'morning_40',
          title: 'التحليل',
          body:
              'أيُّها الرَّبُّ إلَهُ القُوّاتِ الكائنُ قَبْل الدُّهورِ، والدّائمُ إلَى الأبَدِ، الَّذى خَلقَ الشَّمسَ لِضياءِ النَّهارِ واللَّيلَ راحَةً لِكلِّ البَشَرِ، نشْكُركَ يا مَلكَ الدُّهورِ لأنَّكَ أجَزْتَنا هَذا اللَّيلَ بِسَلامٍ وأتَيْتَ بِنا إلَى مَبْدأ النَّهارِ. مِنْ أجْل هَذا نَسْألكَ يا مَلِكنا مَلكَ الدُّهورِ، ليشْرقْ لَنا نورُ وجْهكَ وليُضِئ عَلَيْنا نورُ عِلْمكَ الإلَهى. واجْعَلنا يا سَيِّدنا أنْ نَكونَ بَنى النّورِ وبَنى النَّهارِ، لِكىْ نَجوزَ هَذا اليوْمَ بِبِرٍّ وطهارةٍ وتَدْبيرٍ حَسَنٍ، لِنكمِّلَ بَقيَّةَ أيّامِ حَياتِنا بِلا عَثْرةٍ. بالنِّعمةِ والرَّأفةِ ومَحَبةِ البَشَرِ اللَّواتى لإبْنِكَ الوَحيدِ يَسوعِ المسيحِ، ومَوْهبَةِ روحِكَ القُدّوس. الآنَ وكلّ أوانٍ وإلَى الأبَدِ. آمين.'),
      PrayerSection(
          id: 'morning_41',
          title: 'تحليل آخر',
          body:
              'أيُّها الباعثُ النّورَ فَينْطلقُ، المشْرِقُ شَمسه عَلى الأبْرارِ والأشْرارِ، الَّذى صَنَع النّورَ الَّذى يُضئ عَلَى المسْكونةِ، أنِرْ عُقولَنا وقُلوبَنا وأفْهامَنا يا سَيِّد الكلِّ.هَبْ لَنا فى هَذا اليَومِ الحاضِرِ أنْ نُرْضيكَ فيهِ، واحْرُسْنا مِنْ كلِّ شئٍ ردِئٍ، ومِنْ كلِّ خَطيَّةٍ، ومِنْ كلِّ قُوةٍ مُضادةٍ بالمسيحِ يَسوعِ ربِّنا. هَذا الَّذى أنْتَ مُبارَكٌ مَعهُ ومَعَ الرّوحِ القُدُسِ المحْيى المساوِى لَكَ الآنَ وكلُّ أَوانٍ وإلَى دَهْرِ الدُّهورِ. آمين.'),
      PrayerSection(
          id: 'morning_42',
          title: 'طلبات آخر كل ساعة',
          body:
              'إرْحَمْنا يا اللَّهُ ثمَّ إرْحَمْنا، يا مَنْ فى كلِّ وقْتٍ وكلِّ ساعَةٍ، فى السَّماءِ وعلَى الأرْض مَسْجودٌ لَهُ ومُمجَّدٌ، المسيحُ إلَهنا الصّالحُ الطَّويلُ الرّوحِ الكثيرُ الرَّحْمةِ الجَزيلُ التَّحنُّنِ، الَّذى يُحبُّ الصِّدّيقيَن ويَرْحمُ الخُطاةَ الَّذينَ أوَّلهُم أَنا، الَّذى لا يَشاءُ مَوْت الخاطِئ مِثل ما يَرجعُ ويَحْيا، الدّاعى الكُلَّ إلَى الخَلاصِ لأجْلِ الموْعدِ بالخَيْراتِ المنْتَظرةِ. يا رَبُّ اقْبَل مِنّا فى هَذهِ السّاعةِ وكُلِّ ساعَةٍ طلباتِنا. سَهِّلْ حَياتَنا، وأرشِدْنا إلَى العَمَل بوَصاياكَ. قَدِّسْ أرْواحَنا.طهِّرْ أجْسامَنا. قَوِّمْ أفْكارَنا. نَقِّ نِيّاتَنا واشْفِ أمْراضَنا واغْفِرْ خَطايانا. ونَجِّنا مِنْ كلِّ حُزنٍ رَدئٍ ووَجَِعِ قَلْبٍ، أحِطْنا بمَلائِكتِكَ القدّيسينَ لكىْ نَكونَ بمُعَسْكَرهِم مَحْفوظينَ ومُرْشَدينَ، لنَصِلَ إلَى إتِّحاد الإيمانِ وإلَى مَعْرفةِ مَجْدكَ غَيرِ المحْسوسِ وغَيْر المحْدود، فإنَّكَ مُبارَكٌ إلَى الأبَدِ. آمين'),
    ];
  }

  List<PrayerSection> _getThirdHourSections() {
    return [
      PrayerSection(
          id: 'third_01',
          title: 'الصلاة الربانية',
          body:
              'بِسْم الآب والابنْ والرُوح القُدُس\nالإلَه الوَاحِد، آمين\n( كيريى لَيْسُون ) يَارَبُّ ارْحَمْ. يَارَبُّ ارْحَمْ. يَارَبُّ بارِكْ. آمين.\nالمجدُ للآبِ والابنِ والروحِ القُدسِ الآنَ وكلَّ أوانِ وإِلَى دهرِ الدهورِ. آمين.\nاللَّهُم اجْعلنا مُستحِقين أنْ نقولَ بِشكرٍ:\nأبانا الذي في السَّمَواتِ، لِيتَقدس اسْمكَ. ليأتِ مَلكوتُكَ. لتَكن مَشيئَتُكَ، كما في السّماءِ كَذلك على الأرْضِ. خُبزَنا الذي للغدِ اعطِنا اليومَ. واغفِر لنا ذنوبَنا كما نغْفر نحنُ أيضّا للمذنبينَ إلينا. ولا تُدخِلنا في تَجرِبةٍ. لكن نجّنا مِنْ الشّريرِ. بالمسيحِ يسوعُ ربُّنا، لأنَّ لَكَ المُلكَ والقوةَ والمجدَ إلى الأبدِ. آمين.'),
      PrayerSection(
          id: 'third_02',
          title: 'صلاة الشكر',
          body:
              'فَلْنشْكُرّ صَانِعَ الخَيراتِ الرَّحُومَ الله أبَا رَبِّنَا وإلهِنَا ومُخَلِصَنا يَسُوعِ المسِيحِ. لأنَّهُ سَتَرنَا، وأعَانَنَا، وحَفِظَنا، وقَبِلَنا إليهِ، وأشْفَقَ عَلينَا، وعَضَّدنَا، وأَتَى بنا إلى هَذِهِ السَّاعَة. هُو أيْضاً فَلْنَسْأَلَهُ أنْ يَحْفَظَنا فى هَذَا اليَومِ المقَدَّسِ وكُلِّ أيَّامِ حَيَاتنَا بكلِّ سَلامِ. الضَّابِطُ الكُلّ الرَّبُ إلَهنَا.\nأيُّهَا السَّيِدُ الرَّبُّ الإلَه ضَابطُ الكُلِّ أبُو ربِّنَا وإلهنَا ومُخَلصَّنَا يَسُوعِ المسِيح نَشْكرُكَ عَلَى كُلِّ حالٍ، ومِنْ أجْل كلِّ حَالٍ، وفى كُلِّ حالٍ، لأنَّكَ سَترْتَنا، وأعَنْتَنا، وحفِظْتنَا، وقَبلْتنَا إليْكَ، وأشْفَقْت عَلينا، وعَضَّدْتَنَا، وأتَيتَ بِنَا إلىَ هَذِه السَّاعةِ.\nمن أجْلِ هَذَا نَسْألُ ونَطْلبُ مِنْ صَلاحِكَ يَامُحبَّ البَشَر، امْنَحنَا أنْ نُكْملَ هذا اليَوْمَ المقَدَّسَ وكلّ أيَّامِ حَياتِنَا بِكلِّ سَلامٍ مَعَ خَوفِكَ، كُلُّ حَسَدٍ، وكلُّ تَجربَةٍ. وكلُّ فِعْلِ الشَّيْطانِ، ومُؤامَرةِ النَّاسِ الأشْرارِ، وقِيام الأعْدَاءِ الخَفيِّينَ والظَّاهِرينَ، إنْزَعهَا عنَّا وعَنْ سَائِرِ شَعْبكَ وعَنْ مَوضِعِكَ المقَدَّسِ هَذا. أمَّاَ الصَّالِحاتُ والنَّافعاتُ فَارزُقْنا إيَّاهَا. لأنَّكَ أنْتَ الذِى أعْطَيتَنا السُّلْطانَ أنْ ندوسَ الحَيَّاتِ والعَقارِبَ وكُلَّ قوَّةِ العَدوِّ.\nولا تُدْخِلنَا فى تَجربَةٍ، لَكنْ نَجِّنا مِنَ الشِّرِّيرِ. بالنِّعْمةِ والرَّأْفَاتِ ومَحبَّة البَشرِ اللَّواتِى لإبْنِك الوَحيدِ ربِّنا وإلهِنَا ومُخلِّصِنا يَسُوعِ المسيحِ. هَذَا الذِى مِنْ قِبَلِه الَمجْدُ والإكْرام والعزَّةُ والسُّجودُ تَلِيقُ بكَ مَعهُ مَعُ الرُّوحِ القُدُسِ الَمحْيى المسَاوِى لَكَ الآنَ وكلَّ أوَانٍ وإلىَ دَهرِ الدُّهُورِ. آمين.'),
      PrayerSection(
          id: 'third_03',
          title: 'المزمور الخمسون',
          body:
              'إرْحَمنِى يَا الله كَعَظيمِ رَحْمتِكَ، ومِثْل كَثْرةِ رَأفتِكَ تَمْحُو إثْمِى. تَغْسلُنِى كَثيراً مِنْ إثْمِى، ومِنْ خَطيَّتِى تُطهَّرنِى. لأنِّى عارفٌ بإثْمِى، وخَطيَّتِى أمَامِى فى كلِّ حينٍ. لَكَ وحْدَك أخْطأْت، والشَّرُّ قدامَكَ صَنعْتُ. لِكىْ تَتَبرَّرَ فى أقْوالِكَ. وتَغْلبَ إذَا حَاكمْت. لأنِّى هَا أنَذَا بالاثْمِ حُبلَ بِى، وبالَخَطايَا وَلَدتْنِى أمِّى. لأنَّكَ هَكَذا قَدْ أحْبَبتُ الحقَّ، إذْ أوْضَحتَ لِى غَوامِضَ حِكْمتِكَ ومَسْتورَاتِها. تَنضَحُ عَلىَّ بِزُوفَاكَ فأطَّهَّرُ، تَغْسلُنِى فَأبْيضُّ أكْثَر مِنَ الثَّلجِ، تَسْمعُنِى سُرُوراً وفَرحاً، فتَبْتهجُ عِظامِى المنْسَحقةُ. أصْرِفْ وجْهَكَ عَنْ خَطايَاىَ، وأمْحُ كلَّ اثَامِى. قَلبِاً نَقياً أخْلقْ فىَّ يَا الله، ورُوحاً مُسْتَقيماً جدِّدهُ فى أحْشَائِى. لا تَطْرحْنِى مِنْ قُدَّامَ وجْهكَ، ورُوحكَ القُدُّوسِ لا تَنْزعْهُ مِنِّى. امْنَحْنِى بَهْجةَ خَلاصِكَ، وبرُوحِ مُدبِّرٍ عَضِّدّنِى فأعْلمِ الأثَمَةَ طُرُقكَ، والمنَافِقونَ إليْكَ يَرجعونَ، نَجِّنِى مِنَ الدِّماء يا الله إلَه خَلاصِى، فيَبتَّهجُ لِسانِى ببرَّكَ. يَاربِّ إفْتَح شَفتَىَّ فَيُخبرُ فَمِى بَتَسْبيحِكَ. لأنَّكَ لَوْ أثَرتَ الذَّبيحةَ، لَكُنْتُ الآنَ أعْطِى. ولَكنَّكَ لا تُسرُّ بالَمحْرقَاتِ، فالذَبيحَةُ للهِ رُوحَّ مُنْسحقَّ. القَلْبُ المنْكسِرُ والمتَواضِعُ لايُرْزلهُ الله، أنْعمْ يَا ربّ بِمَسرتكَ عَلى صِهْيُون، ولْتَبنِ أسْوَارَ أورْشَلِيم. حِينَئذٍ تُسرُّ بذَبائِح البَرِّ قرباناً ومُحْرقَات ويُقَّربون عَلى مَذابِحكَ العُجُول. هَلِّلُويا.'),
      PrayerSection(
          id: 'third_04',
          title: 'بدء الصلاة',
          body:
              'تَسْبحَةُ السّاعة الثّالثَة مِنَ النَّهارِ المبارَكِ أقدِّمها للْمَسيحِ مَلِكى وإلَهى وأرْجوهُ أنْ يَغْفرَ لِى خَطاياىَ.'),
      PrayerSection(
          id: 'third_05',
          title: 'مزمور 19: يستجيب لك الرب',
          body:
              'يَسْتَجيبُ لكَ الرَّبُّ فى يَومِ شِدَّتكَ، يَنْصُركَ إسْمُ إلَهِ يَعْقوبَ. يُرْسِلُ لَكَ عَوْناً مِنْ قُدْسِهِ، ومِنْ صهْيون يعضِّدَكَ، يَذْكُرُ جَميعَ ذَبائِحكَ، يُسَمِّنُ مُحْرقاتكَ، يُعْطيكَ الرَّبُّ حَسَبَ قَلْبكَ، ويُتمِّمُ كلَّ مَشورَتَكَ. نَعْترفُ لَكَ يا رَبُّ بخَلاصِكَ، وباسْمِ إلهِنا نِغْلبُ. يُكمِّلُ الرَّبُّ كلَّ سُؤْلكَ.\nالآنَ عَلمْت أنَّ الرَّبَّ قَدْ خَلَّصَ مَسيحَهُ، واسْتَجابَ لهُ مِنْ سَماءِ قُدْسِهِ بجَبَروتِ خَلاصِ يمينِهِ. هَؤُلاءِ بمَرْكباتٍ، وهَؤُلاءِ بخَيْلٍ. ونَحنُ باسْم الرَّبِّ إلَهِنا نَغْلبُ. هُمْ عَثَروا وسَقَطوا، ونَحْن قُمْنا وانْتَصَبْنا. يا رَبُّ خلِّصْ مَلِككَ واسْتَجِبْ لَنا يَوْمَ نَدْعوكَ. هَلِّلُويا.'),
      PrayerSection(
          id: 'third_06',
          title: 'مزمور 22: الرب يرعاني',
          body:
              'الرَّبُ يَرْعانى فَلا يُعْوزُنى شَئ فى مَراعٍ خُضْرٍ يُسْكِنُنى، إلَى مِياهِ الرّاحةِ يورِدُنى. يَردُّ نَفْسى. يَهْدينى إلَى سُبُل البرِّ مِنْ أجْلِ إسْمِهِ. إنْ سَلَكْتُ فى وَسَطِ ظِلالِ الموْتِ فَلا أخافُ شَرًّا لأنَّكَ أنْتَ مَعى، عَصاكَ وعُكّازكَ هُما يُعزِّياننى.\nهَيَّأتَ قُدّامى مائدةً تِجاه مُضايقى. مَسَحتَ بالزَّيتِ رَأسى، وكَأْسُك رَوتْنى بِقوَّةٍ. ورَحْمتُكَ تُدْركنى جَميعَ أيّامِ حَياتى، ومَسْكَنى فى بَيتِ الربِّ إلَى مَدَى الأيَّامِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'third_07',
          title: 'مزمور 23: للرب الأرض وملؤها',
          body:
              'للرَّبِّ الأرْضُ ومِلْؤُها، المسْكونَةُ وجَميعُ السّاكِنينَ فيها. لأنَّهُ عَلى البِحار أسَّسَها، وعَلَى الأنْهار هَيَّأها.\nمَنْ يَصْعَد إلَى جَبلِ الرَّبِّ، أوْ مَنْ يقومُ في مَوْضع قُدْسِهِ؟ الطّاهِرُ اليَدَيْن والنَّقىُّ القَلْبِ، الَّذى لَمْ يَحْمل نَفْسَه إلَى الباطِل ولَمْ يَحْلف بالغِشِّ، هَذا يَنالُ بَرَكةً مِنَ الرَّبِّ، ورَحْمةً مِنَ اللَّهِ مُخَلِّصهُ. هَذا هُوَ جيلُ الَّذينَ يَطلبونَ الرَّبَّ ويبْتَغونَ وَجْه إلهِ يَعْقوبَ.\nإرْفَعوا أيُّها الرُّؤساءُ أَبْوابَكُم، وارْتفعى أيَّتها الأبْوابُ الدَّهْريَّةُ فَيدْخُلُ مَلِكُ المجْدِ. مَنْ هُوَ هَذا مَلِكُ المجْدِ؟ الرَّبُّ العَزيزُ القَديرُ، الرَّبُّ القَّوِىُّ فى الحُروبِ. ارْفعوا أيُّها الرُّؤساءُ أبْوابَكمْ، وارْتَفعى أيَّتُها الأبْوابُ الدَّهْريَّةُ فَيدْخُلُ مَلِكُ المجْدِ. مَنْ هُوَ هَذا مَلِكُ المجْدِ؟ رَبُّ القُوّاتِ، هَذا هُوَ مَلِكُ المجْدِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'third_08',
          title: 'مزمور 25: احكم لي يا رب',
          body:
              'احْكُمْ لى يا ربُّ فإنّي بِدعَتى سَلَكتُ، وعَلَى الرَّبِّ تَوكَّلتُ فَلا أضْعُفُ. اخْتَبرْنى يا رَبُّ وجَرِّبْنى، نَقِّ قَلبى وكُلْيَتَىَّ لأنَّ رَحْمتَكَ أمامَ عَيْنى، وقَد ارْتضيْتُ بحَقِّكَ. لَمْ أجْلسْ فى مَجْلسِ شرّيرٍ، ومَعَ مُخالِفى النّاموس لَمْ أدْخُلْ. أبْغَضتُ مَحْفلَ الأشْرارِ، ومَعَ المنافِقينَ لَمْ أجْلسْ.\nأغْسلُ يَدىَّ بالنَّقاوةِ، وأَطوف بِمذْبَحكَ يا رَبُّ لأسْمَعَ صَوتَ تَسْبيحِكَ وأْنطقُ بجميعِ عَجائِبكَ. يا رَبُّ أحْبَبْتُ جَمالَ بَيْتِكَ، ومَوضِعَ مَسْكنِ مَجْدكَ فَلا تُهْلِك مَعَ المنافِقينَ نَفْسى ولا مَعَ رِجالِ الدِّماءِ حَياتى. الَّذينَ فى أيْديهمُ الإثْمُ، ويَمينُهُمُ امْتَلأتْ رشْوَةً. أمّا أَنا فَبدَعتى سَلكْتُ انْقِذْنى وارْحَمنى لأنَّ رِجْلى وقَفَت فى طَريقٍ مُسْتَقيمٍ فى الجَماعاتِ أُبارِكُكَ يا رَبُّ. هَلِّلُويا.'),
      PrayerSection(
          id: 'third_09',
          title: 'مزمور 28: قدموا للرب يا أبناء الله',
          body:
              'قَدِّموا للرَّبِّ يا أبْناءَ اللَّهِ. قَدِّموا للرَّبِّ أبْناءَ الكِباشِ. قَدِّموا للرَّبِّ مَجْدًا وكَرامَةً. قَدِّموا للرَّبِّ مَجْدًا لاسْمِهِ. اسْجُدوا للرَّبِّ فى دارِ قُدْسِهِ.\nصَوْتُ الرَّبِّ عَلَى المياهِ. إلَهُ المجْدِ أرْعَدَ. الرَّبُّ عَلَى المياهِ الكَثيرةِ. صَوْتُ الرَّبِّ بقُوَّةٍ. صَوْتُ الرَّبِّ بجَلالٍ عَظيمٍ. صَوْتُ الرَّبِّ يُحَطِّمُ الأرْز. الرَّبُّ يُكسِّرُ أرْز لُبْنانَ فتَقْفزُ مِثْل عِجْل لُبْنانَ وسِرْبون مِثْلَ إبْنِ البَقَر الوَحْشىِّ. صَوْتُ الرَّبِّ يُزَلْزلُ القَفْرَ. الرَّبُّ يُزَلْزلُ بَرِّيَّة قادِش. صَوْتُ الرَّبِّ يُولِّد الأيائِلَ ويُجرّد الغاباتِ. وفى هَيْكلِهِ المقَدَّسِ كُلُّ واحِدٍ ينْطِقُ بالمجْدِ. الرَّبُّ يَسْكنُ فى الطّوفانِ، الرَّبُّ يَجْلسُ. مَلِكاً إلَى الأبَدِ. الرَّبُّ يُعْطى شَعْبهُ قوَّةَ، الرَّبُّ يُبارِكُ شَعْبَه بالسَّلامِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'third_10',
          title: 'مزمور 29: أعظمك يا رب',
          body:
              'أعظِّمُكَ يا رَبُّ لأنَّكَ إحْتَضَنْتنى، ولَمْ تُشمِت بى أعْدائى. أيُّها الرَّبُّ إلَهي صَرخْتُ إليْكَ فَشفَيْتنى. يا رَبُّ أصْعَدتَ مِنَ الجَحيم نَفْسى، وخلَّصْتَنى مِنَ الهابِطينَ فى الجُبِّ.\nرَتِّلوا للرَّبِّ يا جَميعَ قِدّيسيهِ، واعْتَرفوا لذِكْرِ قَداسَتِه لأنَّ للحْظَة غَضَبَه، وحَيَاٌة فى رِضاه. فى العَشاءِ يَحلُّ البُكاءُِ وفى الصَّباحِ السُّرورُ. أَنا قُلتُ فى طُمأْنينَتى لا أتَزعْزَعُ إلَى الدَّهْر، يا رَبُّ بمَسَرَّتكَ أعْطَيتَ بَهائى قُوَّةً. صَرفْتَ وجْهَكَ عَنّى فَصِرْتُ قَلِقًا.إليْكَ يا رَبُّ أصْرُخُ، وإلَى إلَهى أتَضرَّعُ. أيَّةُ منْفَعةِ مِنْ دَمى إذا هَبَطتُ إلَى الجَحيمِ، هَلْ يَعْترِفُ لَكَ التُّرابُ أوْ يُخْبرُ بحقِّكَ. سَمعَ الرَّبُّ فَرحِمَنى، الرَّبُّ صارَ لى عَوْناً، حَوَّلتَ نَوْحى إلَى فَرَحٍ لى، مزَّقْتَ مِسْحى ومَنْطَقْتنى سُروراً لِكىْ تُرَتل لَكَ نَفْسى ولا يَحْزَنُ قَلْبى. أيُّها الرَّبُّ إلَهى إلَى الأبَدِ أعْتَرفُ لَكَ. هَلِّلُويا.'),
      PrayerSection(
          id: 'third_11',
          title: 'مزمور 33: أبارك الرب في كل وقت',
          body:
              'ُأباركُ الرَّبَّ فى كُلِّ وَقْتٍ، وفى كُلِّ حينٍ تَسْبحَتُهُ فى فَمى، بالرَّبِّ تَفْتَخرُ نَفْسى، يَسْمعُ الوُدَعاءُ ويفْرَحونَ عَظِّموا الرَّبَّ مَعى لنَرْفَع إسْمَهُ جَميعاً، طلَبْتُ إلَى الرَّبِّ فاسْتَجابَ لى، ومِنْ جَميعِ مَخاوِفى نَجّانى تَقدَّموا إلَيْهِ واسْتَنيروا، ووُجوهكُمْ لا تَخْزَى، هَذا المسْكينُ صَرَخَ فاسْتَمعَهُ الرَّبُّ ومِنْ جَميعِ ضيقاتِه خَلَّصَهُ. يُعَسْكِرُ مَلاكُ الرَّبِّ حَوْلَ كُلِّ خائِفيه ويُنَجّيهِم. ذوقوا وانْظُروا ما أطْيَبَ الرَّبَّ، طوبَى للإنْسانِ المتَّكِلِ عَليْهِ. اتَّقوا الرَّبَّ يا جَميعَ قِدّيسيهِ، فإنَّ الَّذينَ يتَّقونهُ لا يَعوزهُمْ شَئٌ، الأشْبالُ إحْتاجتْ وجاعَتْ أمّا الَّذينَ يبْتَغونَ الرَّبَّ فَلا يَعوزهُمْ أىُّ خَيرٍ.\nهَلُمَّ أيُّها البَنونَ اسْتَمعوا لى، فأُعلِّمكُمْ مخافَة الرَّبِّ. مَنْ هُوَ الإنْسانُ الَّذى يَهْوَى الحَياةَ، ويُحبُّ أَنْ يَرَى أيّاماً صالِحَةً؟ صُنْ لِسانَكَ عَنِ الشَّرِّ وشَفَتَيْكَ عَنِ النُّطْقِ بالغِشِّ، حِدْ عَنِ الشَّرِّ واصْنَع الخَيْرَ، اطْلُب السَّلامَةَ واتَّبِعْها فإنَّ عَيْنَى الرَّبِّ عَلَى الصِّدّيقينَ، وأذُنَيْهِ مُصْغيَتانِ إلَى طلبَتِهِمْ. وجْهُ الرَّبِّ ضِدَّ صانِعى الشَّرِّ ليَمْحو مِنَ الأرْضِ ذِكْرَهُم. الصِّدّيقونَ صَرَخوا والرَّبُّ اسْتَجابَ لَهُم، ومِنْ جَميعِ شَدائِدِهمْ نَجّاهُمْ.\nقَريبٌ هُوَ الرَّبُّ مِنْ مُنْسَحِقى القَلْب، ويُخلِّصُ المتَواضِعينَ بالرّوحِ.كَثيرةٌ هِىَ أحْزانُ الصِّدّيقينَ ومِنْ جَميعِها يُنجّيهمُ الرَّبُّ. يَحْفظُ الرَّبُّ جَميعَ عِظامِهِم وواحِدةٌ مِنْها لا تَنْكسِرُ. يَموتُ الخُطاةُ بشَرِّهم، ومُبْغضو الصِّدّيقِ يَنْدمونَ. الرَّبُّ يَفْدى نُفوسَ عَبيدهِ، ولا يَنْدمُ جَميعُ المتَّكلينَ عَليْه. هَلِّلُويا.'),
      PrayerSection(
          id: 'third_12',
          title: 'مزمور 40: طوبى لمن يتعطف على المسكين',
          body:
              'طوبَى لِمَنْ يَتعَطَّفُ عَلَى المسْكينِ، فى يَومِ الشَّرِّ يُنَجّيهِ الرَّبُّ. الرَّبُّ يَحْفظُهُ ويُحَيّيهِ ويَجْعَلهُ فى الأرْضِ مَغْبوطاً. ولا يُسلِّمهُ لأيْدى أعْدائِهِ. الرَّبُّ يُعينُهُ عَلَى سَرير وَجَعِهِ، إنَّكَ أقَمْتَه مِنْ كُلِّ أوْجاعِ مَرَصٍهٍ.\nأَنا قُلْتُ يا رَبُّ إرْحَمْنى، إشْفِ نَفْسى لأنّى قَدْ أخْطأتُ إلَيكَ. أعْدائى تَقوَّلوا عَلَىَّ شَرًّا: مَتَى يَموتُ ويُبادُ اسْمُه؟ الَّذي دَخَل لِيراني كانَ يتَكلَّمُ بالرِّياءِ، وقَلبُهُ يُضْمرُ لهُ شَرَّا، ثمَّ كانَ يخْرُجُ خارجاً ويَتكلَّمُ عَلىَّ. تَهامَسَ عَلىَّ جَميعُ أعْدائى وتَشاوَروا عَلىَّ بالسّوءِ، وكَلاماً مُخالِفاً للنّاموس رَتَّبوا عَلىَّ، قالوا: ألا يَعود الرّاقِدُ أنْ يَقوم؟ حتَّى الإنْسانُ المسالِمُ الَّذى وَثقْتُ بهِ الَّذى أكَلَ خُبْزى رَفَعَ عَلىَّ عَقِبَهُ.\nوأنْتَ يا رَبُّ إرْحَمْنى وأقمْنى فأُجازيهم. بهَذا عَلمْتُ أنَّك هَويتَنى، لأنَّ عَدوّى لَنْ يُسرّ بى. أمّا أنا فَمِنْ أجْلِ دَعَتى قَبلْتَنى وثَبتنى أَمامك إلَى الأبَدِ. مُبارَكٌ الرَّبُّ إلهُ إسْرائيل، مِن الأزَل وإلَى الأبَدِ آمين. هَلِّلُويا.'),
      PrayerSection(
          id: 'third_13',
          title: 'مزمور 42: احكم لي يا رب',
          body:
              'احْكُمْ لى يا رَبُّ وانْتقِمْ لمظْلمتى، مِنْ امَّةٍ غَيرِ بارَّةٍ ومِنْ إنْسانٍ ظالمٍ وغاشٍّ نَجِّنى. لأنَّكَ أنْتَ هُوَ إلَهى وقُوَّتى، لماذا أقْصَيْتنى؟ ولِماذا أسْلكُ كَئيباً مِنْ مُضايَقةِ عَدُوّى؟ أَرْسِلْ نورَكَ وحَقَّكَ فإنَّهما يَهْدِيانَنى ويُصْعِدانَنى إلَى جَبَلكَ المقَدَّسِ وإلَى مَسْكنِكَ، فأدْخلُ إلَى مَذْبحِ اللَّهِ تِجاهَ وَجْه اللَّهِ الَّذى يُفرحُ شَبابى. أعْتَرفُ لَكَ بالقيثارةِ يا اللَّهُ إلَهى. لِماذا أنْتِِ حَزينَةٌُ يا نَفْسى ولِماذا تُزْعِجينَنى؟ تَوكَّلى عَلَى اللَّهِ فإنِّى أعْترفُ لهُ، خَلاص وَجْهى هُوَ إلَهى. هَلِّلُويا.'),
      PrayerSection(
          id: 'third_14',
          title: 'مزمور 44: فاض قلبي',
          body:
              'فاضَ قَلْبى بِكلامٍ صالحٍ. إنّى أُخْبرُ الملكَ بأفْعالى، لِسانى قَلمٌ كاتِبٌ ماهِرٌ. إنَّك أبْرعُ جَمالاً مِنْ بَنى البَشَرِ. وقَد انْسكَبتِ النِّعْمةُ عَلَى شَفَتيْكَ، فَلذَلكَ بارَكَكَ اللَّهُ إلَى الدَّهْرِ. تَقلَّدْ سَيْفكَ عَلَى فَخذِكَ أيُّها القَوىُّ بجلالِكَ وجَمالِكَ، اسْتَله وانْجَحْ وامْلُكْ. مِنْ أجْلِ الحَقِّ والدَّعةِ والعَدْلِ، وتَهْديكَ بالعَجَبِ يَمينُكَ. نبْلُكَ مَسْنونَةٌ فى قَلْب أعْداءِ الملِكِ أيُّها الجَبّارُ، الشُّعوبُ تَحْتكَ يسْقُطونَ.\nكرسِيُّكَ يا اللَّهُ إلَى دَهْرِ الدُّهورِ، قَضيبُ الاسْتِقامَةِ هُوَ قَضيبُ مُلْككَ لأنَّكَ أحْبَبْتَ البِّرَ وأبْغَضْتَ الإثْمَ، مِنْ أجْلِ هَذا مَسَحكَ اللَّهُ إلَهكَ بزَيْتِ البَهجةِ أفْضَلَ مِنْ رُفقائِكَ، المرُّ والميعَةُ والسَّليخَةُ مِنْ ثِيابكَ، مِنْ قُصورِ العاجِ الَّتى أبْهَجتْكَ. بَناتُ المُلوكِ فى تَكْريمِكَ. قامَت الملِكةُ عَنْ يَمينِكَ بِثَوْبٍ موشَّى بالذَّهَبِ، مُزَيَّنةٌ بأنْواعٍ كَثيرةٍ.\nاسْمَعى يا إبْنَتى وانْظُرى وأَميلى أُذُنَكِ، وانْسَىْ شَعْبكِ وبَيْتَ أبيكِ فإنَّ الملِكَ قَد اشْتَهَى حُسْنَكِ، لأنَّهُ هُوَ ربُّكِ ولَهُ تَسْجُدينَ. ولَهُ تَسْجُد بَناتُ صورٍ بالهَدايا، ويَتَرجَّى وجْهَهُ أغْنياءُ شَعْبِ الأرْضِ.\nكُلُّ مَجْد إبْنَةُ الملِكِ مِنْ داخِل. مشْتمِلةٌ بأطرافٍ مُوَشّاةٍ بالذَّهَبِ، مُزَيَّنَةٍ بأشْكالٍ كَثيرةٍ. تَدْخلُ إلَى الملِكِ عَذارَى فى إثْرها، جَميعُ قَريباتِها إليْهِ يُقَدَّمنَ. يَبْلغنَ بفَرحٍ وابْتِهاجٍ، يدْخُلنَ إلَى هَيْكلِ الملِكِ ويَكونُ لَكَ أْبناء عِوَضاً مِنْ أبائِكَ، تُقيمهُم رُؤساءَ عَلَى سائِرِ الأرْضِ، ويَذْكُرونَ إسْمَكَ جيلاً بَعْد جيلٍ، مِنْ أجْل ذَلكَ تَعْترفُ لَكَ الشُّعوبُ يا اللَّهُ إلَى الدَّهْرِ وإلَى دَهْرِ الدُّهورِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'third_15',
          title: 'مزمور 45: إلهنا ملجأنا وقوتنا',
          body:
              'إلَهُنا مَلجَأُنا وقَُّوُتنا، ومُعينُنا فى شَدائدِنا الَّتى أصابتْنا جداً، لِذَلكَ لا نَخْشَى إذا تزَعْزَعتِ الأرْضُ وانْقَلبَتِ الجِبالُ إلَى قَلبِ البحارِ. تعُجُّ المياهُ وتَجيشُ. تَتَزعْزَعُ الجِبالُ بعِزَّتهِ. مَجارى الأنْهارِ تُفَرِّحُ مَدينَةَ اللَّهِ. لقَد قَدَّس العَلىُّ مَسْكنَهُ، واللَّهُ فى وَسَطها فَلَن تَتَزَعْزع. يُعينُ اللَّهُ وَجْهَها. إضْطَربَتِ الأُممُ، وماجَتِ الممالِكُ، أبْدَى صَوْتَه فَتَزلْزَلت الأرْضُ. إلهُ القُوَاتِ مَعَنا ناصِرُنا هُوَ إلهُ يَعْقوبَ.\nهَلُمَّ فانْظُروا أعْمالَ الرَّبِّ الَّتى جَعَلها آياتٍ عَلَى الأرْضِ. الَّذى يَنْزعُ الحُروبَ إلَى أَقاصى الأرْضِ، يَسْحقُ قِسِيَّهُمْ ويَكْسِرُ سِلاحَهُم، ويَحْرقُ أتْراسَهُم بالنّارِ، تأمَّلوا واعْلَموا أنّى أَنا هُوَ اللَّهُ، أرْتَفِعُ بَينَ الأمَمِ وأتَعالَى فى الأرْضِ. الرَّبُّ إلهُ القُوّات مَعَنا، ناصِرُنا هُوَ إلَهُ يَعْقوبَ. هَلِّلُويا.'),
      PrayerSection(
          id: 'third_16',
          title: 'مزمور 46: يا جميع الأمم صفقوا بأيديكم',
          body:
              'يا جَميعَ الأُمَمِ صَفِّقوا بَأيْديكُم، هَلِّلوا لِلهِ بصَوْتِ الابْتِهاجِ. لأنَّ الرَّبَّ عالٍ ومرْهوبٌ، مَلِكٌ كَبيرٌ عَلَى كافَّةِ الأرْضِ. أخْضَعَ الشُّعوبَ لَنا. والأمَمَ تَحْتَ أقْدامِنا. اخْتارنا ميراثاً لَهُ، جَمالُ يَعْقوبَ الَّذى أُحبُّه.\nصَعِدَ اللَّهُ بتَهْليلٍ والرَّبُّ بصَوْتِ البوقِ، رَتِّلوا لإلَهنا رَتِّلوا، رَتِّلوا لمَليكِنا رَتِّلوا. لأنَّ الرَّبَّ هُوَ مَلِكُ الأرْضِ كلِّها، رَتِّلوا بفَهْمٍ. فإنَّ الرَّبَّ مَلكٌ عَلَى جَميعِ الأمَمِ، اللهُ جَلسَ عَلَى كُرْسيِّه المقَدَّسِ. رُؤَساءُ الشُّعوبِ إجْتَمعوا مَعَ إلهِ إبْراهيمَ، لأنَّ أعِزّاء اللَّهِ قَد ارْتَفعوا فى الأرْضِ جداً. هَلِّلُويا.'),
      PrayerSection(
          id: 'third_17',
          title: 'الإنجيل (يوحنا 14:15-26)',
          body:
              'مَتَى جاءَ المعَزّى الرّوحُ القُدسُ الَّذى سَيُرسِلهُ الآبُ بإسْمى، فَهُوَ يُعلِّمكُم كُلَّ شئٍ ويُذكِّركُم بكُلِّ ما قُلتُه لَكُم، سَلامى أتْركُ لَكُم. سَلامى أَنا أُعْطيكُمْ. لَيسَ كَما يُعْطى العالَم أُعْطيكُمْ. لا تَضْطَربُ قُلوبُكمْ ولا تَجْزعُ. سَمِعْتُم إنّى قُلتُ لَكُم إنّى أمْضى ثُمَّ آتى إليْكُم، لَوْ كُنتُمْ تُحبّونَنى لَكنْتُم تفْرَحون بأنّى أمْضى إلَى الآبِ لأنَّ أَبى أعْظَمُ مِنّى. وقَدْ قُلتُ لَكُم الآنَ قَبْل أنْ يَكونَ، حتَّى مَتَى كانَ تُؤْمنونَ. لْسُت أُكلِّمكُم كَلاماً كَثيراً بَعْد، لأنَّ رَئيسَ هَذا العالَم آتٍ ولَيسَ لَهُ فى شَئٍ. لَكِن لِكىْ يَعْلمَ العالَمُ أنَّنى أحبُّ أَبى وكَما أوْصانى أَبى هَكَذا أفْعل. قوموا نَنْطلقُ مِنْ هَهُنا.\nأَنا هُوَ الكَرْمَةُ الحَقيقيَّةُ وأَبى الكَرّام. كُلُّ غُصْنٍ فىَّ لا يَأتى بثمَرٍ يَقْطعُهُ. وكُلُّ ما يَأتى بثمَرٍ يُنقّيهِ لِيأتى بثمَرٍ أَكْثر. وأنْتُم مِنْ قَبل أنْقِياءُ مِنْ أجْلِ الكَلامِ الَّذى كلَّمْتكُم بهِ. إثبُتوا فىَّ وأَنا أيْضاً فيكُم. والمجْدُ لِلهِ دائِماً.'),
      PrayerSection(
          id: 'third_18',
          title: 'القطعة الأولى',
          body:
              'روحُكَ القُدّوسُ يا رَبُّ الَّذى أرْسَلتَهُ عَلًى تَلاميذِكَ القدّيسينَ ورُسُلِكَ المكرَّمينَ فى السّاعةِ الثّالثةِ، هَذا لا تَنْزعُه مِنّا أيُّها الصّالحُ. لَكِن جَدِّدهُ فى أحْشائِنا. قَلباً نَقياً اخْلُق فىَّ يا اللَّهُ وروحاً مُسْتَقيماً جَدِّد فى أحْشائى. لا تَطْرحنى مِنْ قُدّام وَجْهكَ، وروحكَ القُدّوس لا تَنْزَعهُ مِنّى. ( ذُو كصابترى )'),
      PrayerSection(
          id: 'third_19',
          title: 'القطعة الثانية',
          body:
              'أيُّها الرَّبُّ الَّذى أرْسَلتَ روحَ قُدْسِكَ عَلَى تَلاميذِكَ القدّيسيَن ورُسُلِكَ المكَرَّمينَ فى السّاعَةِ الثّالِثَة هَذا لا تَنْزعهُ مِنّا أيُّها الصّالحُ. لَكِن نَسْألكَ أنْ تُجدِّدَه فى أحْشائِنا يا ربَّنا يَسوعَ المسيحَ إبنَ اللَّهِ الكَلمَة. روحاً مُسْتَقيماً ومُحْيياً، روحَ البُنوةِ والعفَّةِ، روحَ القداسَةِ والعَدالةِ والسُّلطةِ، أيُّها القادرُ عَلَى كُلِّ شَئٍ لأنَّكَ أنْتَ هُوَ ضِياء نُفوسِنا. يا مَنْ يُضئ لِكلِّ إنْسانٍ آتٍ إلَى العالَم إرْحَمْنا. ( كى نين )'),
      PrayerSection(
          id: 'third_20',
          title: 'القطعة الثالثة',
          body:
              'يا والدةَ الإلَهِ أنْتِ هِىَ الكَرْمةُ الحَقيقيَّةُ الحامِلةُ عنْقودَ الحَياة، نَسْألُكِ أيَّتُها الممْتَلئةُ نِعْمةً مَعَ الرُّسلِ مِنْ أجْلِ خَلاصِ نُفوسِنا. مُبارَكٌ الرَّبُّ إلهُنا. مُبارَكٌ الرَّبُّ يَوماً فَيوْماً يُهيِّئ طَريقَنا لأنَّهُ إلهُ خَلاصِنا. ( كى نين )'),
      PrayerSection(
          id: 'third_21',
          title: 'القطعة الرابعة',
          body:
              'أيُّها الملِكُ السَّمائيُّ المعَزّى، روحُ الحَقِّ الحاضِرُ فى كُلِّ مَكانٍ والمالئ الكلّ، كَنْز الصالحات ومُعْطى الحَياة، هَلمَّ تَفَضَّلْ وحُلَّ فينا وطَهِّرنا مِنْ كلِّ دَنَسٍ أيُّها الصّالحُ وخلِّصْ نُفوسَنا. ( ذُو كصابترى )'),
      PrayerSection(
          id: 'third_22',
          title: 'القطعة الخامسة',
          body:
              'كَما كُنْتَ مَعَ تَلاميذِكَ أيُّها المخَلِّصُ وأعْطَيتَهمُ السَّلام، هَلمَّ أيْضاً كُنْ مَعنا وامْنحْنا سَلامَكَ وخَلِّصْنا ونَجِّ نُفوسَنا. ( كى نين )'),
      PrayerSection(
          id: 'third_23',
          title: 'القطعة السادسة',
          body:
              'إذا ما وقَفْنا فى هَيْكلك المقَدَّسِ نحْسب كالقِيامِ فى السَّماءِ، يا والدةَ الإلَه أنتِ هِىَ بابُ السَّماء إفْتَحى لَنا بابَ الرَّحْمَة.'),
      PrayerSection(
          id: 'third_24',
          title: 'يارب ارحم 41 مرة',
          body: 'يُقال ( كيريى لَيْسُون ) يَارَبُّ ارْحَمْ 41 مرة.'),
      PrayerSection(
          id: 'third_25',
          title: 'قدوس قدوس قدوس',
          body:
              'قُدّوسٌ قُدّوسٌ قُدّوسٌ رَبُّ الصَّباؤوتِ. السَّماءُ والأرْضُ مَمْلوءتانِ مِنْ مَجْدكَ وكَرامَتكَ. إرْحَمْنا يا اللَّهُ الآبُ ضابِطُ الكُلِّ، أيُّها الثّالوثُ القُدّوسُ إرْحَمْنا. أيُّها الرَّبُّ إلهُ القُوّاتِ كُنْ مَعَنا، لأنَّهُ لَيسَ لَنا مُعينٌ فى شَدائِدنا وضيقاتِنا سِواكَ. حلّ واغْفِرْ واصْفَحْ لَنا يا اللَّهُ عَنْ سَيِّئاتِنا الَّتى صَنَعْناها بإرادَتِنا والَّتى صَنَعْناها بغَيرِ إرادَتنا، الَّتى فَعلْناها بمَعرِفةٍ والَّتى فَعلْناها بغَير مَعْرِفةٍ، الخَفيَّةِ والظاهِرةِ، يا رَبُّ اغْفِرها لَنا مِنْ أجْلِ إسْمِكَ القُدّوسِ الَّذى دُعى عَليْنا. كَرحْمتِكَ يا رَبُّ ولا كَخَطايانا.'),
      PrayerSection(
          id: 'third_26',
          title: 'الصلاة الربانية',
          body:
              'اللَّهُم اجْعلنا مُستحِقين أنْ نقولَ بِشكرٍ:\nأبانا الذي في السَّمَواتِ، لِيتَقدس اسْمكَ. ليأتِ مَلكوتُكَ. لتَكن مَشيئَتُكَ، كما في السّماءِ كَذلك على الأرْضِ. خُبزَنا الذي للغدِ اعطِنا اليومَ. واغفِر لنا ذنوبَنا كما نغْفر نحنُ أيضّا للمذنبينَ إلينا. ولا تُدخِلنا في تَجرِبةٍ. لكن نجّنا مِنْ الشّريرِ. بالمسيحِ يسوعُ ربُّنا، لأنَّ لَكَ المُلكَ والقوةَ والمجدَ إلى الأبدِ. آمين.'),
      PrayerSection(
          id: 'third_27',
          title: 'التحليل',
          body:
              'يا إلهَ كُلِّ الرَّأفات وربَّ كُلَّ عَزاءٍ، الَّذى عَزّانا كُلَّ حينٍ بعَزاءِ روحِك القُدّوسِ، نَشْكركَ لأنَّكَ أقَمْتَتنا للصَّلاةِ فى هَذهِ السّاعَة المقَدَّسَة، الَّتى فيها أفْضَتْ نِعْمةُ روحِكَ القُدّوسِ بغنَى عَلَى تَلاميذِكَ القِدّيسينَ ورُسُلِكَ المكرَّمينَ الطّوباويّينَ مِثْلَ ألْسِنَة نارِ. نَسْألُ ونَطلُبُ مِنْكَ يا مُحبَّ البَشَر، إقْبَلْ إليْكَ صَلواتَنا، واغْفِر لنا خَطايانا، وارْسِلْ عَلَيْنا نِعْمةَ روحِكَ القُدّوسِ، وطَهِّرنا مِنْ كُلِّ دَنَسِ الجَسَدِ والرّوحِ، وانْقلنا إلَى سيرَةٍ روحانِيَّةٍ، لِكَىْ نَسْعَى بالرّوحِ ولا نُكمِّلُ شَهْوةَ الجَسَدِ، واجْعَلنا مُستحقّينَ أنْ نَخْدمكَ بطَهارةٍ وبرٍّ كُلَّ أيّامِ حَياتنا. لأنَّه يَليقُ بكَ المجْدُ والكرامَةُ والعِزَّةُ مَعَ أبيكَ الصَالِح والرّوحِ القُدُسِ. الآنَ وكُلُّ أوانٍ وإلَى الأبدِ. آمين.'),
      PrayerSection(
          id: 'third_28',
          title: 'طلبة تقال آخر كل ساعة',
          body:
              'إرْحَمْنا يا اللَّهُ ثمَّ إرْحَمْنا، يا مَنْ فى كلِّ وقْتٍ وكلِّ ساعَةٍ، فى السَّماءِ وعلَى الأرْض مَسْجودٌ لَهُ ومُمجَّدٌ، المسيحُ إلَهنا الصّالحُ الطَّويلُ الرّوحِ الكثيرُ الرَّحْمةِ الجَزيلُ التَّحنُّنِ، الَّذى يُحبُّ الصِّدّيقيَن ويَرْحمُ الخُطاةَ الَّذينَ أوَّلهُم أَنا، الَّذى لا يَشاءُ مَوْت الخاطِئ مِثل ما يَرجعُ ويَحْيا، الدّاعى الكُلَّ إلَى الخَلاصِ لأجْلِ الموْعدِ بالخَيْراتِ المنْتَظرةِ.\nيا رَبُّ اقْبَل مِنّا فى هَذهِ السّاعةِ وكُلِّ ساعَةٍ طلباتِنا. سَهِّلْ حَياتَنا، وأرشِدْنا إلَى العَمَل بوَصاياكَ. قَدِّسْ أرْواحَنا.طهِّرْ أجْسامَنا. قَوِّمْ أفْكارَنا. نَقِّ نِيّاتَنا واشْفِ أمْراضَنا واغْفِرْ خَطايانا. ونَجِّنا مِنْ كلِّ حُزنٍ رَدئٍ ووَجَِعِ قَلْبٍ، أحِطْنا بمَلائِكتِكَ القدّيسينَ لكىْ نَكونَ بمُعَسْكَرهِم مَحْفوظينَ ومُرْشَدينَ، لنَصِلَ إلَى إتِّحاد الإيمانِ وإلَى مَعْرفةِ مَجْدكَ غَيرِ المحْسوسِ وغَيْر المحْدود، فإنَّكَ مُبارَكٌ إلَى الأبَدِ. آمين.'),
    ];
  }

  List<PrayerSection> _getSixthHourSections() {
    return [
      PrayerSection(
          id: 'sixth_01',
          title: 'الصلاة الربانية',
          body:
              'بِسْم الآب والابنْ والرُوح القُدُس\nالإلَه الوَاحِد، آمين\n( كيريى لَيْسُون ) يَارَبُّ ارْحَمْ. يَارَبُّ ارْحَمْ. يَارَبُّ بارِكْ. آمين.\nالمجدُ للآبِ والابنِ والروحِ القُدسِ الآنَ وكلَّ أوانِ وإِلَى دهرِ الدهورِ. آمين.\nاللَّهُم اجْعلنا مُستحِقين أنْ نقولَ بِشكرٍ:\nأبانا الذي في السَّمَواتِ، لِيتَقدس اسْمكَ. ليأتِ مَلكوتُكَ. لتَكن مَشيئَتُكَ، كما في السّماءِ كَذلك على الأرْضِ. خُبزَنا الذي للغدِ اعطِنا اليومَ. واغفِر لنا ذنوبَنا كما نغْفر نحنُ أيضّا للمذنبينَ إلينا. ولا تُدخِلنا في تَجرِبةٍ. لكن نجّنا مِنْ الشّريرِ. بالمسيحِ يسوعُ ربُّنا، لأنَّ لَكَ المُلكَ والقوةَ والمجدَ إلى الأبدِ. آمين.'),
      PrayerSection(
          id: 'sixth_02',
          title: 'صلاة الشكر',
          body:
              'فَلْنشْكُرّ صَانِعَ الخَيراتِ الرَّحُومَ الله أبَا رَبِّنَا وإلهِنَا ومُخَلِصَنا يَسُوعِ المسِيحِ. لأنَّهُ سَتَرنَا، وأعَانَنَا، وحَفِظَنا، وقَبِلَنا إليهِ، وأشْفَقَ عَلينَا، وعَضَّدنَا، وأَتَى بنا إلى هَذِهِ السَّاعَة. هُو أيْضاً فَلْنَسْأَلَهُ أنْ يَحْفَظَنا فى هَذَا اليَومِ المقَدَّسِ وكُلِّ أيَّامِ حَيَاتنَا بكلِّ سَلامِ. الضَّابِطُ الكُلّ الرَّبُ إلَهنَا.\nأيُّهَا السَّيِدُ الرَّبُّ الإلَه ضَابطُ الكُلِّ أبُو ربِّنَا وإلهنَا ومُخَلصَّنَا يَسُوعِ المسِيح نَشْكرُكَ عَلَى كُلِّ حالٍ، ومِنْ أجْل كلِّ حَالٍ، وفى كُلِّ حالٍ، لأنَّكَ سَترْتَنا، وأعَنْتَنا، وحفِظْتنَا، وقَبلْتنَا إليْكَ، وأشْفَقْت عَلينا، وعَضَّدْتَنَا، وأتَيتَ بِنَا إلىَ هَذِه السَّاعةِ.\nمن أجْلِ هَذَا نَسْألُ ونَطْلبُ مِنْ صَلاحِكَ يَامُحبَّ البَشَر، امْنَحنَا أنْ نُكْملَ هذا اليَوْمَ المقَدَّسَ وكلّ أيَّامِ حَياتِنَا بِكلِّ سَلامٍ مَعَ خَوفِكَ، كُلُّ حَسَدٍ، وكلُّ تَجربَةٍ. وكلُّ فِعْلِ الشَّيْطانِ، ومُؤامَرةِ النَّاسِ الأشْرارِ، وقِيام الأعْدَاءِ الخَفيِّينَ والظَّاهِرينَ، إنْزَعهَا عنَّا وعَنْ سَائِرِ شَعْبكَ وعَنْ مَوضِعِكَ المقَدَّسِ هَذا. أمَّاَ الصَّالِحاتُ والنَّافعاتُ فَارزُقْنا إيَّاهَا. لأنَّكَ أنْتَ الذِى أعْطَيتَنا السُّلْطانَ أنْ ندوسَ الحَيَّاتِ والعَقارِبَ وكُلَّ قوَّةِ العَدوِّ.\nولا تُدْخِلنَا فى تَجربَةٍ، لَكنْ نَجِّنا مِنَ الشِّرِّيرِ. بالنِّعْمةِ والرَّأْفَاتِ ومَحبَّة البَشرِ اللَّواتِى لإبْنِك الوَحيدِ ربِّنا وإلهِنَا ومُخلِّصِنا يَسُوعِ المسيحِ. هَذَا الذِى مِنْ قِبَلِه الَمجْدُ والإكْرام والعزَّةُ والسُّجودُ تَلِيقُ بكَ مَعهُ مَعُ الرُّوحِ القُدُسِ الَمحْيى المسَاوِى لَكَ الآنَ وكلَّ أوَانٍ وإلىَ دَهرِ الدُّهُورِ. آمين.'),
      PrayerSection(
          id: 'sixth_03',
          title: 'المزمور الخمسوت',
          body:
              'إرْحَمنِى يَا الله كَعَظيمِ رَحْمتِكَ، ومِثْل كَثْرةِ رَأفتِكَ تَمْحُو إثْمِى. تَغْسلُنِى كَثيراً مِنْ إثْمِى، ومِنْ خَطيَّتِى تُطهَّرنِى. لأنِّى عارفٌ بإثْمِى، وخَطيَّتِى أمَامِى فى كلِّ حينٍ. لَكَ وحْدَك أخْطأْت، والشَّرُّ قدامَكَ صَنعْتُ. لِكىْ تَتَبرَّرَ فى أقْوالِكَ. وتَغْلبَ إذَا حَاكمْت. لأنِّى هَا أنَذَا بالاثْمِ حُبلَ بِى، وبالَخَطايَا وَلَدتْنِى أمِّى. لأنَّكَ هَكَذا قَدْ أحْبَبتُ الحقَّ، إذْ أوْضَحتَ لِى غَوامِضَ حِكْمتِكَ ومَسْتورَاتِها. تَنضَحُ عَلىَّ بِزُوفَاكَ فأطَّهَّرُ، تَغْسلُنِى فَأبْيضُّ أكْثَر مِنَ الثَّلجِ، تَسْمعُنِى سُرُوراً وفَرحاً، فتَبْتهجُ عِظامِى المنْسَحقةُ. أصْرِفْ وجْهَكَ عَنْ خَطايَاىَ، وأمْحُ كلَّ اثَامِى. قَلبِاً نَقياً أخْلقْ فىَّ يَا الله، ورُوحاً مُسْتَقيماً جدِّدهُ فى أحْشَائِى. لا تَطْرحْنِى مِنْ قُدَّامَ وجْهكَ، ورُوحكَ القُدُّوسِ لا تَنْزعْهُ مِنِّى. امْنَحْنِى بَهْجةَ خَلاصِكَ، وبرُوحِ مُدبِّرٍ عَضِّدّنِى فأعْلمِ الأثَمَةَ طُرُقكَ، والمنَافِقونَ إليْكَ يَرجعونَ، نَجِّنِى مِنَ الدِّماء يا الله إلَه خَلاصِى، فيَبتَّهجُ لِسانِى ببرَّكَ. يَاربِّ إفْتَح شَفتَىَّ فَيُخبرُ فَمِى بَتَسْبيحِكَ. لأنَّكَ لَوْ أثَرتَ الذَّبيحةَ، لَكُنْتُ الآنَ أعْطِى. ولَكنَّكَ لا تُسرُّ بالَمحْرقَاتِ، فالذَبيحَةُ للهِ رُوحَّ مُنْسحقَّ. القَلْبُ المنْكسِرُ والمتَواضِعُ لايُرْزلهُ الله، أنْعمْ يَا ربّ بِمَسرتكَ عَلى صِهْيُون، ولْتَبنِ أسْوَارَ أورْشَلِيم. حِينَئذٍ تُسرُّ بذَبائِح البَرِّ قرباناً ومُحْرقَات ويُقَّربون عَلى مَذابِحكَ العُجُول. هَلِّلُويا.'),
      PrayerSection(
          id: 'sixth_04',
          title: 'بدء الصلاة',
          body:
              'تَسْبحَةُ السّاعة السّادسَة مِنَ النَّهارِ المبارَكِ أقدِّمها للْمَسيحِ مَلِكى وإلَهى وأرْجوهُ أنْ يَغْفرَ لِى خَطاياىَ.'),
      PrayerSection(
          id: 'sixth_05',
          title: 'مزمور 53: اللهم باسمك خلصني',
          body:
              'اللَّهُمَّ بإسْمِكَ خَلِّصْنى، وبقُوَّتكَ احْكُمْ لى. اسْتَمِعْ يا اللهُ صَلاتى، وأنْصِتْ إلَى كَلامِ فَمى. فإنَّ الغُرَباءَ قَدْ قاموا عَلَىَّ والأقْوياءَ طَلبوا نَفْسى، لَمْ يَجْعلوا اللَّه أمامَهُم. هُوَذا اللَّهُ عَوْنى والرَّبُّ ناصرُ نَفْسى، يَردُّ الشُّرورَ عَلَى أعْدائى وبِحَقِّكَ إسْتَأصِلهُم فأذْبَحُ لَكَ طائعاً، وأعْتَرفُ لإسْمِكَ يا رَبُّ فإنَّهُ صالِحٌ لأنَّكَ مِنْ جَميعِ الشَّدائِدِ نَجَّيْتنى وبأَعْدائى نَظَرتْ عَيْناىَ. هَلِّلُويا'),
      PrayerSection(
          id: 'sixth_06',
          title: 'مزمور 56: ارحمني يا الله ارحمني',
          body:
              'ارْحَمْنى يا اللَّهُ ارْحَمْنى، فإنَّهُ عَليْكَ تَوكَّلَتْ نَفْسى. وبظِلِّ جَناحَيْك أعْتَصِمُ، إلَى أنْ يَعْبُرَ الإثمُ. أصْرُخُ إلَى اللَّهِ العَلىِّ، الإلَه المحسِن إلَىَّ. أرْسَل مِنَ السَّماءِ فَخلَّصنى، وجَعَلَ العارَ عَلَى الَّذينَ يَطأُونَنى أرْسَلَ اللَّهُ رَحْمَتَهُ وحقَّهُ، وخَلَّصَ نَفْسى مِنْ بَينِ الأشْبالِ إذْ نِمْتُ مُضْطَرباً. أسْنانُ أبْناءِ البَشَرِ سِلاحٌ وسِهامٌ، ولسانُهُم سَيْفٌ مُرهَفٌ اللَّهمَّ إرْتَفِعْ عَلَى السَّمَواتِ، وليرْتَفِعْ مَجْدُكَ عَلَى كُلِّ الأرْضِ. نَصَبوا لِرجْلى فِخاخاً وأحْنَوْا نَفْسى، حَفروا قُدّامَ وجْهى حُفْرةً سَقَطوا فيها.\nمُستَعدٌ قَلْبى يا اللَّهُ، مُسْتَعدٌ قَلْبى، أُسبِّحُ وأُرتِّلُ فى تَمْجيدى اسْتَيقِظى يا نَفْسى اسْتَيقِظْ أيُّها المزْمارُ والقيثارَةُ. أَنا أسْتَيقِظُ مُبَكِّراًً. أعْتَرفُ لَكَ فى الشُّعوبِ يا رَبُّ، وأرتِّلُ لَكَ فى الأمَمِ. لأنَّ رحْمتَكَ قَدْ عَظُمَت إلَى السَّمَواتِ وإلَى السَّحابِ عَدْلكَ. اللهُمَّ ارْتَفعْ عَلَى السَّمَواتِ ولْيرتَفِعْ مَجْدُك عَلَى سائِرِ الأرْضِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'sixth_07',
          title: 'مزمور 60: استمع يا الله طلبتي',
          body:
              'اسْتَمعْ يا اللَّهُ طلبَتى، واصْغ إلَى صَلاتى. مِنْ أَقاصى الأرْضِ صَرَخْتُ إليْكَ عنْدَما ضَجرَ قَلْبى، عَلَى الصَّخْرةِ رَفَعْتنى وأرْشَدْتَنى. صِرْتَ رَجائى وبُرْجاً حَصيناً فى وَجْه العَدوِّ. فأسْكُن فى مَسْكنِكَ إلَى الدَّهْر، وأسْتظِل بسِتْرِ جَناحَيكَ. لأنَّكَ أنْتَ يا اللَّهُ اسْتَمَعتَ صَلَواتى، أَعْطَيْتَ ميراثاً لخائِفى إسْمِكَ، تَزيدُ الملِكَ أيّاماً عَلَى أيّامِهِ وسِنيناً عَلَى سِنيهِ. إلَى جيلٍ فَجيلٍ ويَدومُ إلَى الأبَدِ قُدّامَ اللَّهِ. رَحْمتُهُ وحَقُّه يَحْفَظانِهِ. هَكَذا أُرتِّلُ لإسْمِكَ إلَى دَهْرِ الدُّهورِ، لأَفى نُذورى يَوماً فَيَوماً. هَلِّلُويا.'),
      PrayerSection(
          id: 'sixth_08',
          title: 'مزمور 62: يا الله إلهي إليك أبكر',
          body:
              'يا اللَّهُ إلَهي إليْكَ أُبَكِّرُ، إذْ عَطِشَتْ نَفسى إليْكَ يَشْتاقُ إلَيْكَ جَسَدى، فى أرْضٍ مُقْفرَةٍ ومَوْضِعٍ غَيرِ مَسْلوكٍ ومَكانٍ بَلا ماءٍ. هَكذا تَراءَيْتُ لَكَ فى القُدسِ، لأرَى قُوَّتَكَ ومَجْدَكَ، لأنَّ رحْمتَكَ أفْضَلُ مِنَ الحَياةِ. شَفََتاى تُسبِّحانك. لِذَلكَ أُبارِككَ فى حَياتى، وباسْمِكَ أرْفَعُ يَدى فَتشْبعُ نَفْسى كَما مِنْ شَحْمٍ ودَسَمٍ، بشِفاهِ الإبْتِهاجِ نُبارِكُ إسْمَك. كنْتُ أذْكُركَ عَلَى فِراشى، وفى أوْقات الأسْحارِ كنْتُ أُرتِّلُ لَكَ. لأنَّكَ صِرْتَ لى عَوْناً، وبظِلِّ جَناحيْكَ أبْتَهجُ.\nإلْتَصقَت نَفْسى بِكَ، ويَمينُكَ عَضَّدتْنى، أمّا الَّذينَ طَلَبوا نَفْسى للهَلاكِ، فيَدْخلونَ فى أسافِل الأرْضِ ويُدْفَعونَ إلَى يَدِ السَّيفِ، ويَكونونَ أنْصِبةً للثعالِبِ أمّا الملِكُ فَيفرحُ باللَّهِ، ويفْتَخرُ كُلُّ مَنْ يَحْلفُ بهِ. لأنَّ أفواهَ المتَكلَّمينَ بالظُّلْم تُسدُّ. هَلِّلُويا.'),
      PrayerSection(
          id: 'sixth_09',
          title: 'مزمور 66: ليتراءف الله علينا',
          body:
              'لِيتَراءفَ اللَّهُ عَلينَا ولِيُباركِنَا، وليُنِرْ بوجْهِهِ عَليْنَا ويَرْحَمْنا. لَتُعْرفَ فى الأرْض طَريقُكَ، وفى جَميعِ الأممِ خَلاصُكَ. فلْتَعْتَرَفْ لكَ الشَّعوبُ يااللَّهُ، فلْتَعْترفْ لكَ الشُّعوبُ كلُّها. لتَفْرَح الأمَمُ وتَبْتهجُ، لأنَّكَ تدِينُ الشَّعوبَ بالإسْتِقامَةِ وتَهْدى الأممَ فى الأرْض. فلْتَعْتَرفْ لَكَ الشُّعوبُ يَااللَّهُ، فلْتَعْتَرفْ لَكَ الشُّعوبُ جَميعاً الأرْضُ أعْطَتْ ثَمَرتَها. فَليُبارِكنَا اللهُ إلهنَا. لِيُباركنَا اللهُ. فَلْتَخشَهُ جَميعُ أقْطارِ الأرْضِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'sixth_10',
          title: 'مزمور 69: اللهم التفت إلى معونتي',
          body:
              'اللَّهُمَّ إلْتَفتْ إلى مَعُونَتِى، يَاربُّ أسْرعْ وأعِنِّى. ليُخْزَ ويَخْجَل طَالبُو نَفْسى، وليرْتَدَّ إلى خَلْفٍ ويَخْجَل الذِينَ يبْتَغونَ لى الشَّرَّ. وليرْجعَ بالخِزْىِ سَريعاً القَائِلونَ لى نَعماً نعمَا. ولِيبْتَهجْ ويَفْرَح بكَ جَميعُ الذِينَ يلْتمسُونِكَ، ولِيَقَل فى كلِّ حينٍ مُحبُّو خَلاصِكَ لِيتعَظَّمَ الرَّبُّ. وأمَّا أنَا فمِسْكينٌ وفَقِيرٌ. اللَّهمَّ أعِنِّى. أنْتَ مُعينِى ومُخلِّصِى يَاربُّ فَلا تُبْطِئ. هَلِّلُويا.'),
      PrayerSection(
          id: 'sixth_11',
          title: 'مزمور 83: مساكنك محبوبة',
          body:
              'مَساكِنُكَ مَحْبوبةٌ يا رَبُّ إلَهَ القُوّات. تَشْتاقُ وتَذوبُ نَفْسى للدُّخولِ إلَى دِيارِ الرَّبِّ. قَلْبى وجِسْمى قَد إبْتَهَجا بالإلَهِ الحَىِّ. العُصْفورُ وجَدَ لهُ بَيْتاً واليَمامَةُ عُشّاً لِتضَعَ فيهِ أفْراخَها، مَذابِحُكَ يا رَبُّ إلَه القُوّاتِ مَلِكى وإلَهى. طوبَى لِكلِّ السُّكانِ فى بَيْتِِكَ، يُبارِكونَكَ إلَى الأبَدِ. طوبَى للرَّجُلِ الَّذى نَصَرتَهُ مِنْ عِنْدكَ يا رَبُّ، رَتَّبْ فى قَلبهِ أنْ يَصْعدَ، فى وادى البُكاءِ فى المَكانِ الَّذى قَرَّرهُ. لأنَّ البَرَكات يُعْطيها واضِعُ النّاموسِ، يَسيرونَ مِنْ قُوَّةٍ إلَى قُوَّةٍ. يَتَجلَّى إلهُ الآلِهَة فى صهْيونِ.\nأيُّها الرَّبُّ إلَه القُوّاتِ إسْمَعْ صَلاتى، أنْصتْ يا إلهَ يَعْقوبَ. انْظُر أيُّها الإلهُ ناصِرُنا وأطَّلِعْ إلَى وَجْهِ مَسيحكَ. لأنَّ يَوماً صالِحاً فى دِيارِكَ خَيرٌ مِنْ آلافٍ. إخْتَرتُ لنَفْسى أنْ أطْرَحَ عَلَي بابِ بَيْتِ اللَّهِ أفْضَل مِنْ أنْ أسْكُنَ فى مَظال الخُطاةِ. لأنَّ الرَّبَّ الإلَهَ يُحبُّ الرَّحْمَة والحَقَّ، ويُعْطى مَجْداً ونِعْمةً. الرَّبُّ لا يَمْنَع الخَيْرات عَنِ السّالِكينَ بالدَّعَةِ. يا رَبَّ إلَه القُوّاتِ طوبَى للإنْسانِ المتَّكِلِ عَليْكَ. هَلِّلُويا.'),
      PrayerSection(
          id: 'sixth_12',
          title: 'مزمور 84: أمل يا رب أذنك',
          body:
              'رَضِيتَ يا رَبُّ عَلَى أرْضِكَ، رَدَدْت سَبْى يَعْقوبَ، غَفَرتَ آثامَ شَعْبكَ، سَتَرتَ جَميعَ خَطاياهُم. حَللْتَ كُلَّ رِجْزكَ، رَجَعْت عَنْ سُخْط غَضَِكَ. رُدَّنا يا إلَه خَلاصِنا، واصْرِفْ غَضَبِكَ عَنا، هَلْ إلَى الأبَدِ تَغْضبُ عَليْنا، أوْ تُواصِلُ رِجْزَكَ مِنْ جيلٍ إلَى جيلٍ؟ أنْتَ يا اللَّهُ تَعودُ فَتُحْيينا، وشَعْبُكَ يفْرَُ بِكَ. أرِنا يا رَبُّ رَحْمَتَك واعْطِنا خَلاصَكَ.\nإنّى أسْمَعُ ما يَتَكلَّمُ بهِ الرَّبًّ الإلَهُ لأنَّهُ يتَكلَّمَ بالسَّلامِ لشَعْبهِ ولقدّيسيهِ وللَّذينَ رَجعوا إلَيْه بكُلِّ قلوبِهِمْ. لأنَّ خَلاصَهُ قَريبٌ مِنْ جَميعِ خائِفيه لِيسْكُن المجْدُ فى أرْضِنا. الرَّحْمةُ والحَقَّ تَلاقيا، البرُّ والسَّلامُ تلائَما الحَقُّ مِنَ الأرْضِ أشْرَقَ، والبرُّ مِنَ السَّماءِ اطَّلعَ. لأنَّ الرَّبَّ يُعْطى الخَيْرات. وأرْضُنا تُعْطى ثَمرَها. البرُّ أمامهُ يسْلك، ويَسيرُ فى طَريقِ خطواتِهِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'sixth_13',
          title: 'مزمور 85: أمال يا رب أذنك',
          body:
              'أَملْ يا رَبُّ أُذُنَك واسْتَمعْنى لأنّى مسْكينٌ وبائِسٌ أَنا. إحْفَظْ نَفْسي لأنّى بارٌّ، يا إلَهى خلِّصْ عَبْدِكَ المتَّكلَ عَليكَ. ارْحَمْنى يا رَبُّ لأنّى إليكَ أصْرخُ اليَومَ كلَّهُ. فَرِّحْ نَفْسَ عَبْدكَ لأنّى إليْكَ يا رَبُّ رَفَعتُ نَفْسى. لأنَّكَ أنْتَ يا رَبُّ صالِحٌ وَوَديعٌ، ورَحْمتُكَ كَثيرَةٌ لِكافَةِ المسْتَغيثينَ بكَ.\nأنْصِتْ يا رَبُّ إلَى صَلاتى، واصْغِ إلَى صَوْتِ تَضرُّعى. فى يَومِ شدَّتى إليْكَ صَرَخْتُ فَأجَبْتنى. فَليسَ لَكَ شَبيهٌ فى الآلِهَةِ يا رَبُّ ولا مَنْ يَصْنَعُ كأعْمالِكَ. كُلُّ الأممِ الَّذينَ خَلقْتَهُم يَأْتونَ ويَسْجُدونَ أمامَكَ يا رَبُّ ويُمجِّدونَ إسْمَكَ. لأنَّكَ أنْتَ عَظيمٌ وصانِعُ العَجائِبِ، أنْتَ وحْدَكَ الإلَهُ العَظيمُ.\nإهْدِنى يا رَبُّ إلَى طَريقِكَ فَأسْلكَ فى حقِّكَ، ليَفْرحَ قَلبى عِنْد خَوفِه مِنْ إسْمِكَ. أعْتَرفُ لَكَ أيُّها الرَّبُّ إلَهى مِنْ كُلِّ قَلْبى، وأُمجِّدُ إسْمَكَ إلَى الأبدِ. لأنَّ رَحْمتَكَ عَظيمَةٌ عَلَىَّ، وقَدْ نَجَّيتَ نَفْسى مِنَ الجَحيمِ السُّفلىِّ.\nاللَّهُمَّ إنَّ مُخالِفى النّاموسِ قَدْ قاموا عَلَىَّ، ومَجْمعُ الأعِزّاءِ طَلبوا نَفْسى، ولَمْ يَسْبقوا أنْ يَجْعَلوكَ أمامهمْ، وأنْتَ أيُّها الرَّبُّ الإلهُ أنْتَ رَؤوفٌ ورَحيمٌ، أنْتَ طَويلُ الرّوحِ وكَثيرُ الرَّحْمةِ وصادِقٌ. انْظُر إلَىَّ وارْحَمْنى. أَعْطِ عِزَّةً لِعبْدِكَ، وخَلِّص إبْنِ أمَتكَ، إصْنَع مَعى آيةً صالحَةً لِيرَى ذَلكَ مُبْغِضىَّ فَيخْزوْا. لأنَّكَ أنْتَ يا رَبُّ أعنْتَنى وعزَّيتَنى. هَلِّلُويا.'),
      PrayerSection(
          id: 'sixth_14',
          title: 'مزمور 86: أساساته في الجبال المقدسة',
          body:
              'أَساساتهُ فى الجِبالِ المقَدَّسةِ. يُحِبُّ الرَّبُّ أبْوابَ صِهْيونَ، أفْضَلُ مِنْ جَميعِ مَساكنِ يَعْقوبَ. أعْمالٌ مَجيدةٌ قَدْ قيلَتْ عَنْكِ يا مدينَةَ اللَّهِ.\nأذْكُرُ رَهَبَ وبابِلَ اللَّتَيْنِ تَعْرفانى هُوذا القَبائِلُ الغَريبةُ وصورُ وشَعْبُ الحَبشَةِ، هَؤُلاء وُلِدوا هُناكَ. أمّا صِهْيون الأمّ فتَقولُ: إنَّ إنْساناً إنْساناً وُلِدَ فيها، والعَلىُّ هُوَ الَّذى أسَّسَها إلَى الأبَد. الرَّبُّ يُحْصى فى كُتُب الشُّعوبِ والرُّؤَساءِ، أُولَئِكَ الَّذينَ وُلِدوا فيها. لأنَّهُم يسْكُنونَ جَميعُهُم بِفَرحٍ فيك. هَلِّلُويا.'),
      PrayerSection(
          id: 'sixth_15',
          title: 'مزمور 90: السكن في عون العلى',
          body:
              'السّاكِنُ فى عَوْنِ العَلىِّ، يَسْتَريحُ فى ظِلِّ إلهِ السَّماءِ. يَقولُ للرَّبِّ أنْتَ هُوَ ناصِرى ومَلْجَئى، إلَهى فأتَّكِلُ عَليهِ. لأنَّهُ يُنجّيكَ مِنْ فَخِّ الصَّيّادِ، ومِنَ الوَباءِ الخَطِرِ. فى وَسَطِ مَنْكبيْهِ يُظلِّلُكَ، وتَحْتَ جَناحَيهِ تَعْتَصمُ، عَدْلهُ يُحيطُ بِكَ كالسِّلاح. فَلا تَخْشَى مِنْ خَوْفِ اللَّيْلِ ولا مِنْ سَهْمٍ يَطيرُ في النَّهار، ولا مِنْ أمْرٍ يسْلكُ في الظُّلمَةِ، ولا مِنْ هَلاكٍ يفسد فى الظَّهيرَةِ. يَسْقطُ عَنْ يَساركَ أُلوفٌ وعَنْ يَمينكَ رِبْواتٌ، وأمّا أنْتَ فَلا يقْتَربُ إليْكَ الشَّرُّ بَلْ بِعَيْنيْكَ تُعايِنُ ومُجازاةُ الخُطاةِ تُبْصرُ.\nلأنَّكَ أنْتَ يا رَبُّ رَجائى، جَعلْتَ العَلىَّ مَلْجأَكَ فلا تُصيبكَ الشُّرورُ، ولا تدْنو ضَرْبةً مِنْ مَسْكنِكَ. لأنَّهُ يوصى مَلائِكتَهُ بِكَ. ليَحْفظونكَ فى جَميعِ طُرقكَ. وعَلَى أيْديهِمْ يحْمِلونَكَ، لئَلاّ تَعْثُر بحَجَرٍ رِجْلُكَ. تَطأُ الأفْعَى ومَلِكَ الحيّات، وتَسْحقُ الأسَدَ والتِّنّينَ. لأنَّهُ تَعلَّقَ بى فَأنجّيه، أُرفِّعُهُ لأنَّهُ عَرفَ إسْمى. يدْعونى فأسْتجيب لَهُ، مَعهُ أَنا فى الشِّدَّة، أنْقِذهُ وأمَجِّدهُ ومِنْ طولِ الأيّامِ أشْبِعُهُ، وأُريهِ خَلاصى. هَلِّلُويا.'),
      PrayerSection(
          id: 'sixth_16',
          title: 'مزمور 92: الرب قد ملك',
          body:
              'الرَّبُّ قَدْ مَلكَ، لَبِسَ الجَلالَ. لَبِسَ الرَّبُّ القُوَّةَ وتَمنْطَقَ بِها، لأنَّهُ ثَبتَ المسْكونَة فَلَن تَتَزعْزَعَ. كُرْسِيُّكَ ثابتٌ مُنْذُ البَدءِ وأنْتَ هُوَ مُنْذُ الأزَل. رَفَعتِ الأنْهارُ يا رَبُّ، رَفَعتِ الأنْهارُ صَوتَها. تَرفَعُ الأنْهارُ صَوتَها، مِنْ صَوتِ مِياهٍ كَثيرةٍ. عَجيبَةٌ هِىَ أمْواجُ البَحْر، بَلْ عَجيبٌ هُوَ الرَّبُّ فى الأَعالى. شهاداتُهُ صادِقةٌ جداً، لبَيْتِكَ ينْبَغى التَّقديسُ يا رَبُّ طول الأيّامِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'sixth_17',
          title: 'الإنجيل (متى 5:1-16)',
          body:
              'فَلمّا أبْصَرَ الجُموعَ صَعِدَ إلَى الجَبَلِ وعِنْدما جَلسَ تَقَدَّم إلْيهِ تَلاميذُهُ فَفَتَحَ فاهُ وعلَّمهُمْ قائِلاً: طوبَى للمَساكين بالرّوحِ لأنَّ لَهُم مَلكوتَ السَّمَواتِ. طوبَى للْحَزانَى الآنَ لأنَّهُم يَتعزّوْنَ. طوبَى للوُدَعاءِ لأنَّهمْ يَرثونَ الأرْضَ. طوبَى للجِياعِ والعِطاشِ إلَى البرِّ لأنَّهمْ يشْبَعونَ. طوبَى للرُّحَماءِ لأنَّهمْ يرْحَمون. طوبَى لأنْقياءِ القَلْبِ لأنَّهمْ يُعاينونَ اللَّهَ. طوبَى لصانِعى السَّلامِ لأنَّهمْ يُدْعَوْنَ أبْناءَ اللَّهِ. طوبَى للمَطْرودينَ مِنْ أجْلِ البرِّ. لأنَّ لَهُم مَلَكوت السَّمَوات. طوبَى لَكُم إذا طَرَدوكُم وعَيَّروكُم وقالوا فيكُم مِنْ أجْلى كُلَّ شَرٍّ كاذِبينَ. افْرَحوا وتَهلَّلوا لأنَّ أجْرَكُم عَظيمٌ فى السَّمَواتِ. فإنَّهُمْ هَكَذا طَرَدوا الأنْبِياءَ الَّذينَ كانوا قَبْلَكم.\nأنْتُم مِلْحُ الأرْضِ. فَإذا فَسَدَ المِلْحُ فَبِماذا يُملَّحُ، لا يَصْلُحُ بَعدُ لشَئٍ، إلاَّ لأنْ يُطْرحَ خارِجاً وتَدوسُهُ النّاسُ. أنْتُم نورُ العالَم لا يُمْكنُ أنْ تُخْفَى مَدينَةٌ كائِنَةٌ عَلَى جَبلٍ. ولا يوقِدونَ سِراجاً ويضعَونهُ تَحْت المكْيالِ، بَلْ يَضعونَهُ عَلَى المنارَةِ فيُضئ لِكّلِّ مَنْ فى البَيتِ. هَكَذا فَلْيُضئ نورُكُم قُدّامِ النّاسِ، لِكىْ يَروْا أعْمالَكُمُ الصّالِحةُ فيُمجِّدوا أباكُم الَّذى فى السَّمَواتِ. والمجْدُ للَّهِ دائِماً.'),
      PrayerSection(
          id: 'sixth_18',
          title: 'القطعة الأولى',
          body:
              'يا مَنْ فى اليَوْمِ السّادِسِ وفى السّاعَةِ السّادِسَة سُمِّرتَ عَلَى الصَّليبِ مِنْ أجْل الخَطيَّةِ الَّتى تَجرَّأ عَليْها أبونا أدَمُ فى الفِرْدَوسِ، مَزِّقْ صَكَّ خَطايانا أيُّها المسيحُ إلهُنا وخَلِّصْنا. أَنا صَرخْتُ إلَى اللَّهِ والرَّبُّ سَمِعَنى. اللَّهمَّ اسْتَجبْ صَلاتى ولا تَرفُضْ طلبَتى. إلْتَفِتْ إلَىَّ واسْمَعْنى، عَشِيَّة وباكِر ووَقْت الظُّهْر. كَلامى أقولُهُ فيَسْمعُ صَوْتى، ويُخلِّصُ نَفْسى بسَلامٍ. ( ذُو كصابترى )'),
      PrayerSection(
          id: 'sixth_19',
          title: 'القطعة الثانية',
          body:
              'يا يَسوعُ المَسيح إلَهنا الَّذى سُمِّرتَ عَلَى الصَّليبِ فى السّاعَةِ السَادسَةِ، وقَتلْتَ الخَطيَّةَ بالخَشَبةِ، وأحْيَيتَ الميِّتَ بِمَوْتِك، الَّذى هُوَ الإنْسانُ الَّذى خَلقْتهُ بِيَديْكَ، الَّذى ماتَ بالخَطِيَّةِ، اقْتُل أوْجاعَنا بِآلامِكَ الشّافِيةِ المحْيِيَّةِ، وبالمَساميِر الَّتى سًمِّرْتَ بِها. أنْقِذْ عُقولَنا مِنْ طياشَةِ الأعْمالِ الهيلوليَّةِ والشَّهَواتِ العالَميَّةِ، وإلَى تذْكارِ أحْكامِكَ السَّمائِيَّةِ كَرأفَتكَ. ( كى نين )'),
      PrayerSection(
          id: 'sixth_20',
          title: 'القطعة الثالثة',
          body:
              'إذْ لَيسَ لَنا دالَّةٌ ولا حُجَّةٌ ولا مَعْذرةٌ مِنْ أجْلِ كَثْرةِ خَطايانا، فنَحْنُ بِك نَتَوسَّلُ إلَى الَّذى وُلِدَ مِنْك يا والِدةَ الإلهِ العَذْراء. لأَّن كَثيرةً هِىَ شَفاعتكِ ومَقْبولةً عِنْد مُخلِّصِنا. أيَّتُها الأُمُّ الطّاهرةُ لا ترْفُضى الخُطاةَ مِنْ شَفاعَتكِ عِنْد الَّذى وُلِدَ مِنكِ. لأنَّهُ رَحومٌ وقادرٌ عَلَى خَلاصِنا، لأنَّهُ تألَّمَ مِنْ أجْلِنا لِكى يُنْقذَنا، فَلتُدركْنا رَأفَتُك سَريعاً لأنَّنا قَدْ تَمسَّكْنا جدّاً أعنّا يا اللَّهُ مُخَلِّصُنا مِنْ أجْل مّجْدِ إسْمِكَ. يا رَبُّ نَجِّنا واغْفِر لَنا خَطايانا مِنْ أجْلِ إسْمِكَ القُدّوس. ( كى نين )'),
      PrayerSection(
          id: 'sixth_21',
          title: 'القطعة الرابعة',
          body:
              'صَنَعتَ خَلاصاً فى وَسَطِ الأرْضِ كُلَّها أيُّها المسيحُ إلهُنا، عِنْدَما بَسَطْتَ يَديْكَ الطّاهِرتَيْنِ عَلَى عودِ الصَّليبِ فَلهَذا كُلُّ الأمَمِ تَصْرخُ قائلَةً: المجْدُ لَكَ يا رَبُّ. ( ذُوكصابترى )'),
      PrayerSection(
          id: 'sixth_22',
          title: 'القطعة الخامسة',
          body:
              'نَسْجدُ لِشَخْصِك غَيْر الفاسِد أيُّها الصّالِحُ طالِبينَ مَغْفرةَ خَطايانا أيُّها المسيحُ إلَهُنا. لأنَّكَ بمَشيئتكَ سُرِرْتَ أنْ تَصْعدَ عَلَى الصَّليبِ، لتُنجى الَّذينَ خَلقْتهُم مِنْ عُبوديَّةِ العَدوِّ. نَصْرُخُ إليْكَ ونَشْكُركَ لأنَّكَ مَلأتَ الكُلَّ فَرحاً أيُّها المخَلِّص لمّا أتَيْتَ لتُعينَ العالَم، يا رَبُّ المجْدُ لَكَ. ( كى نين)'),
      PrayerSection(
          id: 'sixth_23',
          title: 'القطعة السادسة',
          body:
              'أنتِ هِىَ الممْتَلئةُ نعْمةً يا والدَةَ الإلهِ العَذْراءَ. نُعظِّمكِ لأنَّ مِنْ قِبَلِ صَليبِ إبْنكِ إنْهبَطَ الجَحيمُ وبَطلَ الموْتُ. أمْواتاً كُنّا فَنَهضْنا، واسْتَحقَقنا الحَياةَ الأبدِيَّةَ ونِلْنا نَعيمَ الفِرْدَوسِ الأوَّل. مِنْ أجْلِ هَذا نُمجِّدُ بِشُكْرِ غَير المائِتِ المسيحِ إلَهِنا لأنَّه قَويٌّ.'),
      PrayerSection(
          id: 'sixth_24',
          title: 'يارب ارحم 41 مرة',
          body: 'يُقال ( كيريى لَيْسُون ) يَارَبُّ ارْحَمْ 41 مرة.'),
      PrayerSection(
          id: 'sixth_25',
          title: 'قدوس قدوس قدوس',
          body:
              'قُدّوسٌ قُدّوسٌ قُدّوسٌ رَبُّ الصَّباؤوتِ. السَّماءُ والأرْضُ مَمْلوءتانِ مِنْ مَجْدكَ وكَرامَتكَ. إرْحَمْنا يا اللَّهُ الآبُ ضابِطُ الكُلِّ، أيُّها الثّالوثُ القُدّوسُ إرْحَمْنا. أيُّها الرَّبُّ إلهُ القُوّاتِ كُنْ مَعَنا، لأنَّهُ لَيسَ لَنا مُعينٌ فى شَدائِدنا وضيقاتِنا سِواكَ. حلّ واغْفِرْ واصْفَحْ لَنا يا اللَّهُ عَنْ سَيِّئاتِنا الَّتى صَنَعْناها بإرادَتِنا والَّتى صَنَعْناها بغَيرِ إرادَتنا، الَّتى فَعلْناها بمَعرِفةٍ والَّتى فَعلْناها بغَير مَعْرِفةٍ، الخَفيَّةِ والظاهِرةِ، يا رَبُّ اغْفِرها لَنا مِنْ أجْلِ إسْمِكَ القُدّوسِ الَّذى دُعى عَليْنا. كَرحْمتِكَ يا رَبُّ ولا كَخَطايانا.'),
      PrayerSection(
          id: 'sixth_26',
          title: 'الصلاة الربانية',
          body:
              'اللَّهُم اجْعلنا مُستحِقين أنْ نقولَ بِشكرٍ:\nأبانا الذي في السَّمَواتِ، لِيتَقدس اسْمكَ. ليأتِ مَلكوتُكَ. لتَكن مَشيئَتُكَ، كما في السّماءِ كَذلك على الأرْضِ. خُبزَنا الذي للغدِ اعطِنا اليومَ. واغفِر لنا ذنوبَنا كما نغْفر نحنُ أيضّا للمذنبينَ إلينا. ولا تُدخِلنا في تَجرِبةٍ. لكن نجّنا مِنْ الشّريرِ. بالمسيحِ يسوعُ ربُّنا، لأنَّ لَكَ المُلكَ والقوةَ والمجدَ إلى الأبدِ. آمين.'),
      PrayerSection(
          id: 'sixth_26',
          title: 'التحليل',
          body:
              'نَشْكُركَ يا مَلِكنا ضابِطَ الكُلِّ أَبا رَبِّنا وإلهِنا ومُخَلِّصِنا يَسوعِ المسيحِ ونُمجِّدُكَ، لأنَّكَ جَعلتَ أوْقاتَ آلامِ إبْنِكَ الوَحيد أوْقاتَ عَزاءٍ وصَلاةٍ، اقْبَل إليْكَ تَضرُّعَنا، وامْحُ عَنّا صَكَّ خَطايانا المكْتوبَ عَلَينا، كَما مَزَّقْتَه فى هَذهِ السّاعَةِ المقَدَّسَةِ بصَليبِ إبْنِكَ الوَحيدِ يَسوعِ المَسيح ربِّنا ومُخلِّص نُفوسِنا، هَذا الَّذى بِهِ هَدمْتَ كُلَّ قُوَّةِ العَدوِّ. أعْطِنا يا اللَّهُ وقْتاً بَهيّاً، وسيَرًة بلا عَيْبٍ، وحَياةً هادِئةً، لِنُرْضىَ إسْمَكَ القُدّوس المسْجودُ لهُ، ونَقفُ أمامَ المنْبَرِ المخوفِ العادِل الَّذى لإبْنكَ الوَحيدِ يَسوعِ المسيحِ ربِّنا بغَيْرِ وقوعٍ فى دَيْنونَةٍ، ونُمجِّدكَ مَعَ كافَّةِ قِدّيسيكَ، أنْتَ الآبُ غَيرُ المبْتدئِ والإبْنُ المُساوى لَكَ والرّوحُ القدُسُ المحْيي، الآنَ وكُلُّ أوانٍ وإلَى دَهْرِ الدُّهورِ كُلِّها. آمين.'),
      PrayerSection(
          id: 'sixth_27',
          title: 'طلبة تقال آخر كل ساعة',
          body:
              'إرْحَمْنا يا اللَّهُ ثمَّ إرْحَمْنا، يا مَنْ فى كلِّ وقْتٍ وكلِّ ساعَةٍ، فى السَّماءِ وعلَى الأرْض مَسْجودٌ لَهُ ومُمجَّدٌ، المسيحُ إلَهنا الصّالحُ الطَّويلُ الرّوحِ الكثيرُ الرَّحْمةِ الجَزيلُ التَّحنُّنِ، الَّذى يُحبُّ الصِّدّيقيَن ويَرْحمُ الخُطاةَ الَّذينَ أوَّلهُم أَنا، الَّذى لا يَشاءُ مَوْت الخاطِئ مِثل ما يَرجعُ ويَحْيا، الدّاعى الكُلَّ إلَى الخَلاصِ لأجْلِ الموْعدِ بالخَيْراتِ المنْتَظرةِ. يا رَبُّ اقْبَل مِنّا فى هَذهِ السّاعةِ وكُلِّ ساعَةٍ طلباتِنا. سَهِّلْ حَياتَنا، وأرشِدْنا إلَى العَمَل بوَصاياكَ. قَدِّسْ أرْواحَنا.طهِّرْ أجْسامَنا. قَوِّمْ أفْكارَنا. نَقِّ نِيّاتَنا واشْفِ أمْراضَنا واغْفِرْ خَطايانا. ونَجِّنا مِنْ كلِّ حُزنٍ رَدئٍ ووَجَِعِ قَلْبٍ، أحِطْنا بمَلائِكتِكَ القدّيسينَ لكىْ نَكونَ بمُعَسْكَرهِم مَحْفوظينَ ومُرْشَدينَ، لنَصِلَ إلَى إتِّحاد الإيمانِ وإلَى مَعْرفةِ مَجْدكَ غَيرِ المحْسوسِ وغَيْر المحْدود، فإنَّكَ مُبارَكٌ إلَى الأبَدِ. آمين.'),
    ];
  }

  List<PrayerSection> _getNinthHourSections() {
    return [
      PrayerSection(
          id: 'ninth_01',
          title: 'الصلاة الربانية',
          body:
              'بِسْم الآب والابنْ والرُوح القُدُس\nالإلَه الوَاحِد، آمين\n( كيريى لَيْسُون ) يَارَبُّ ارْحَمْ. يَارَبُّ ارْحَمْ. يَارَبُّ بارِكْ. آمين.\nالمجدُ للآبِ والابنِ والروحِ القُدسِ الآنَ وكلَّ أوانِ وإِلَى دهرِ الدهورِ. آمين.\nاللَّهُم اجْعلنا مُستحِقين أنْ نقولَ بِشكرٍ:\nأبانا الذي في السَّمَواتِ، لِيتَقدس اسْمكَ. ليأتِ مَلكوتُكَ. لتَكن مَشيئَتُكَ، كما في السّماءِ كَذلك على الأرْضِ. خُبزَنا الذي للغدِ اعطِنا اليومَ. واغفِر لنا ذنوبَنا كما نغْفر نحنُ أيضّا للمذنبينَ إلينا. ولا تُدخِلنا في تَجرِبةٍ. لكن نجّنا مِنْ الشّريرِ. بالمسيحِ يسوعُ ربُّنا، لأنَّ لَكَ المُلكَ والقوةَ والمجدَ إلى الأبدِ. آمين.'),
      PrayerSection(
          id: 'ninth_02',
          title: 'صلاة الشكر',
          body:
              'فَلْنشْكُرّ صَانِعَ الخَيراتِ الرَّحُومَ الله أبَا رَبِّنَا وإلهِنَا ومُخَلِصَنا يَسُوعِ المسِيحِ. لأنَّهُ سَتَرنَا، وأعَانَنَا، وحَفِظَنا، وقَبِلَنا إليهِ، وأشْفَقَ عَلينَا، وعَضَّدنَا، وأَتَى بنا إلى هَذِهِ السَّاعَة. هُو أيْضاً فَلْنَسْأَلَهُ أنْ يَحْفَظَنا فى هَذَا اليَومِ المقَدَّسِ وكُلِّ أيَّامِ حَيَاتنَا بكلِّ سَلامِ. الضَّابِطُ الكُلّ الرَّبُ إلَهنَا.\nأيُّهَا السَّيِدُ الرَّبُّ الإلَه ضَابطُ الكُلِّ أبُو ربِّنَا وإلهنَا ومُخَلصَّنَا يَسُوعِ المسِيح نَشْكرُكَ عَلَى كُلِّ حالٍ، ومِنْ أجْل كلِّ حَالٍ، وفى كُلِّ حالٍ، لأنَّكَ سَترْتَنا، وأعَنْتَنا، وحفِظْتنَا، وقَبلْتنَا إليْكَ، وأشْفَقْت عَلينا، وعَضَّدْتَنَا، وأتَيتَ بِنَا إلىَ هَذِه السَّاعةِ.\nمن أجْلِ هَذَا نَسْألُ ونَطْلبُ مِنْ صَلاحِكَ يَامُحبَّ البَشَر، امْنَحنَا أنْ نُكْملَ هذا اليَوْمَ المقَدَّسَ وكلّ أيَّامِ حَياتِنَا بِكلِّ سَلامٍ مَعَ خَوفِكَ، كُلُّ حَسَدٍ، وكلُّ تَجربَةٍ. وكلُّ فِعْلِ الشَّيْطانِ، ومُؤامَرةِ النَّاسِ الأشْرارِ، وقِيام الأعْدَاءِ الخَفيِّينَ والظَّاهِرينَ، إنْزَعهَا عنَّا وعَنْ سَائِرِ شَعْبكَ وعَنْ مَوضِعِكَ المقَدَّسِ هَذا. أمَّاَ الصَّالِحاتُ والنَّافعاتُ فَارزُقْنا إيَّاهَا. لأنَّكَ أنْتَ الذِى أعْطَيتَنا السُّلْطانَ أنْ ندوسَ الحَيَّاتِ والعَقارِبَ وكُلَّ قوَّةِ العَدوِّ.\nولا تُدْخِلنَا فى تَجربَةٍ، لَكنْ نَجِّنا مِنَ الشِّرِّيرِ. بالنِّعْمةِ والرَّأْفَاتِ ومَحبَّة البَشرِ اللَّواتِى لإبْنِك الوَحيدِ ربِّنا وإلهِنَا ومُخلِّصِنا يَسُوعِ المسيحِ. هَذَا الذِى مِنْ قِبَلِه الَمجْدُ والإكْرام والعزَّةُ والسُّجودُ تَلِيقُ بكَ مَعهُ مَعُ الرُّوحِ القُدُسِ الَمحْيى المسَاوِى لَكَ الآنَ وكلَّ أوَانٍ وإلىَ دَهرِ الدُّهُورِ. آمين.'),
      PrayerSection(
          id: 'ninth_03',
          title: 'المزمور الخمسون',
          body:
              'إرْحَمنِى يَا الله كَعَظيمِ رَحْمتِكَ، ومِثْل كَثْرةِ رَأفتِكَ تَمْحُو إثْمِى. تَغْسلُنِى كَثيراً مِنْ إثْمِى، ومِنْ خَطيَّتِى تُطهَّرنِى. لأنِّى عارفٌ بإثْمِى، وخَطيَّتِى أمَامِى فى كلِّ حينٍ. لَكَ وحْدَك أخْطأْت، والشَّرُّ قدامَكَ صَنعْتُ. لِكىْ تَتَبرَّرَ فى أقْوالِكَ. وتَغْلبَ إذَا حَاكمْت. لأنِّى هَا أنَذَا بالاثْمِ حُبلَ بِى، وبالَخَطايَا وَلَدتْنِى أمِّى. لأنَّكَ هَكَذا قَدْ أحْبَبتُ الحقَّ، إذْ أوْضَحتَ لِى غَوامِضَ حِكْمتِكَ ومَسْتورَاتِها. تَنضَحُ عَلىَّ بِزُوفَاكَ فأطَّهَّرُ، تَغْسلُنِى فَأبْيضُّ أكْثَر مِنَ الثَّلجِ، تَسْمعُنِى سُرُوراً وفَرحاً، فتَبْتهجُ عِظامِى المنْسَحقةُ. أصْرِفْ وجْهَكَ عَنْ خَطايَاىَ، وأمْحُ كلَّ اثَامِى. قَلبِاً نَقياً أخْلقْ فىَّ يَا الله، ورُوحاً مُسْتَقيماً جدِّدهُ فى أحْشَائِى. لا تَطْرحْنِى مِنْ قُدَّامَ وجْهكَ، ورُوحكَ القُدُّوسِ لا تَنْزعْهُ مِنِّى. امْنَحْنِى بَهْجةَ خَلاصِكَ، وبرُوحِ مُدبِّرٍ عَضِّدّنِى فأعْلمِ الأثَمَةَ طُرُقكَ، والمنَافِقونَ إليْكَ يَرجعونَ، نَجِّنِى مِنَ الدِّماء يا الله إلَه خَلاصِى، فيَبتَّهجُ لِسانِى ببرَّكَ. يَاربِّ إفْتَح شَفتَىَّ فَيُخبرُ فَمِى بَتَسْبيحِكَ. لأنَّكَ لَوْ أثَرتَ الذَّبيحةَ، لَكُنْتُ الآنَ أعْطِى. ولَكنَّكَ لا تُسرُّ بالَمحْرقَاتِ، فالذَبيحَةُ للهِ رُوحَّ مُنْسحقَّ. القَلْبُ المنْكسِرُ والمتَواضِعُ لايُرْزلهُ الله، أنْعمْ يَا ربّ بِمَسرتكَ عَلى صِهْيُون، ولْتَبنِ أسْوَارَ أورْشَلِيم. حِينَئذٍ تُسرُّ بذَبائِح البَرِّ قرباناً ومُحْرقَات ويُقَّربون عَلى مَذابِحكَ العُجُول. هَلِّلُويا.'),
      PrayerSection(
          id: 'ninth_04',
          title: 'بدء الصلاة',
          body:
              'تَسْبحَةُ السّاعة التّاسِعة مِنَ النَّهارِ المبارَكِ أقدِّمها للْمَسيحِ مَلِكى وإلَهى وأرْجوهُ أنْ يَغْفرَ لِى خَطاياىَ.'),
      PrayerSection(
          id: 'ninth_05',
          title: 'مزمور 95: سبحوا الرب تسبيحاً جديداً',
          body:
              'سَبِّحوا الرَّبَّ تَسْبيحاً جَديداً، سَبِّحى الرَّبَّ يا كُلَّ الأرْضِ. سَبِّحوا الرَّبَّ وبارِكوا إسْمَهُ، بَشِّروا مِنْ يَومٍ إلَى يَومٍ بِخَلاصِهِ. حَدِّثوا فى الأممِ بمَجْدِهِ، بَيْنَ جَميعِ الشُّعوبِ بعَجائِبهِ. لأنَّ الرَّبَّ عَظيمٌ هُوَ ومُسَبحٌ جِداً، مَهوبٌ عَلَى كُلِّ الآلِهَةِ. لأنَّ كلَّ آلِهَةِ الأممِ شَياطينُ أمّا الرَّبُّ فَصَنَعَ السَّمَواتِ. الجَلالُ والبَهاءُ قُدّامَهُ، الطُّهْرُ والجَمالُ العَظيمُ فى قُدْسِه.\nقَدِّموا للرَّبِّ يا جَميعَ قَبائِل الأممِ، قَدِّموا للرَّبِّ مَجْداً وكَرامَةً. قَدِّموا للرَّبِّ مَجْداً لاسْمِهِ، احْملوا الذَّبائِحَ وادْخُلوا دِيارَهُ. اسْجُدوا للرَّبِّ فى دِيارهِ المقَدَّسةِ، فَلْتَتَزَلْزَل الأرْضُ كُلُّها أمامِ وجْهِهِ. قولوا بَيْنَ الأممِ إنَّ الرَّبَّ قَدْ مَلَكَ عَلَى خَشَبَةٍ، وأيْضاً ثَبَّتَ المسْكونَةَ فَلَنْ تُزَعْزَع. يدينُ الشُّعوبَ بالاسْتِقامَةِ، فلْتَفْرَح السَّمَوات ولتَبْتَهِج الأرْضُ. وليَعج البَحْر وجَميع مِلْئِهِ، تَفْرحُ الودْيانُ وكُلُّ ما فيها. حينَئذٍ يبْتَهجُ كُلُّ شَجَرِ الغابِ أمامَ وَجْهِ الرَّبِّ لأنَّهُ يأتى. يَأْتى لِيَدينَ الأرْضَ. يَدينَ المسْكونَةَ بالعَدْلِ، والشُّعوبَ بالاسْتِقامةِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'ninth_06',
          title: 'مزمور 96: الرب قد ملك فلتتهلل الأرض',
          body:
              'الرَّب قَدْ مَلََكَ فلْتَتَهلَّل الأرْضُ، ولْتَفْرح الجَزائِرُ الكَثيرةُ. سَحابٌ وضَبابٌ حَوْلهُ، العَدلُ والقَضَاءُ قوامُ كُرْسِيِّه. النّارُ تَسْبقُ فَتَسْلك أمامَه، وبلهيبٍ تَحْرقُ أعْداءهُ الَّذينَ حَوْلهُ. أضاءَت بُروقُهُ المسْكونَة، نَظَرت الأرْضُ فَتَزلْزَلت. ذابت الجِبالُ مِثلَ الشَّمْع مِنْ وَجْهِ الرَّبِّ ومِنْ وَجْه الأرْضِ كُلِّها. أخْبرَت السَّمَوات بِعَدْلهِ وعايَنَت جَميعُ الشُّعوبِ مَجْدَه.\nيَخْزَى جَميعُ السّاجدينَ لِصَنعةِ الأيْدى، المُفْتَخِرينَ بأصْنامِهِم. اسْجُدوا للَّهِ يا جَميعَ ملائِكتِهِ. سَمعَتْ صهْيونُ فَفَرحَتْ، وتَهلَّلَت بناتُ يَهوذا مِنْ أجْل أحْكامِكَ يا رَبُّ لأنَّكَ أنْتَ هُوَ الرَّبُّ العالى عَلَى كُلِّ الأرْضِ. ارْتَفَعْتَ جِدّاً فَوقَ جَميعٍ الآلِهَةِ.\nيا مُحبّى الرَّبِّ أَبْغِضوا الشَّرَّ. إنَّ الرَّبَّ يَحْفظُ نُفوسَ أبْرارِه ويُنَجِّيهِم مِنْ أيْدى الخُطاةِ. نورٌ أشْرقَ للصَّدّيقيَن. وفَرحٌ للمُسْتَقيمي القُلوبِ افْرَحوا أيُّها الصِّدّيقون بالرَّبِّ، واعْتَرفوا لذِكْرِ قَداستِهِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'ninth_07',
          title: 'مزمور 97: سبحوا الرب تسبيحاً جديداً',
          body:
              'سَبِّحوا الرَّبَّ تَسْبيحاً جَديداً، لأنَّ الرَّبَّ قّدْ صَنَع أعْمالاً عَجيبَةً. خَلَّصَت لَهُ يَمينَهُ وذِراعَهُ القُدّوسَ. أعْلنَ الرَّبُّ خَلاصَهُ، وكَشَفَ قُدّامَ الأممِ عَدْلهُ. ذَكَرَ رَحْمتَهُ ليَعْقوبَ وحقَّهُ لبَيْتِ إسْرائيلَ. نَظَرَتْ أَقاصى الأرْضِ جَميعاً خَلاصَ إلَهِنا.\nهَلِّلُوا للرَّبِّ يا كُلَّ الأرْضِ، سَبِّحوا وهَلِّلُوا ورَتِّلوا. رَتِّلوا للرَّبِّ بالقيثارَةِ، بالقيثارَةِ وصَوتِ المزْمارِ، بأبْواقٍ خافِقَةٍ وصَوْتِ بوقِ القَرْن، هَلِّلُوا أمامَ الرَّبِّ الملِكِ. فَلْيعج البَحْرُ وكُلُّ مِلئِهِ. المسْكونَة وكُلُّ السّاكِنينَ فيها، تُصفِّقُ جَميعُ الأنْهارِ، الجِبالُ تَبْتهجُ أمامَ وَجْه الرَّبِّ. لأنَّهُ أتَى ليَدينَ الأرْضَ، يَدينُ المسْكونَةَ بالعَدْلِ والشُّعوبَ بالاسْتِقامةِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'ninth_08',
          title: 'مزمور 98: الرب قد ملك فلترتعد الشعوب',
          body:
              'الرَّبُّ قَدْ مَلَكَ فَلْتَرتَعِد الشُّعوبُ، الجالِسُ عَلَى الشّاروبيم فَلْتَتَزَلْزل الأرْضُ. عَظيمٌ هُوَ الرَّبُّ فى صِهْيونَ، ومُتَعالٍ عَلَى كُلِّ الشُّعوبِ. فَلْيَعْتَرفوا لإسْمِكَ العَظيم، لأنَّهُ مرْهوبٌ وقُدّوسٌ، وكَرامَةُ الملِكِ أنْ يُحبَّ العَدْلَ. أنْتَ هَيَّأتَ الاسْتِقامَةَ، أنْتَ أجْريْتَ القَضاءَ والعَدلَ فى يَعْقوب.\nإرْفَعوا الرَّبَّ إلَهَنا، واسْجُدوا لموْطِئ قَدَمَيْه فإنَّه قُدّوسٌ هُوَ، موسَى وهَرونُ بَينَ كَهَنتِهِ، وصَموئيلُ بَينَ الذينَ يَدْعونَ باسْمِهِِ، كانوا يَدْعونَ الرَّبَّ فَيسْتَجيبُ لَهُم، بعَمودِ الغَمامِ كانَ يُكلِّمهُم. لأنَّهُم حَفِظوا شَهاداته، والأوامرَ الَّتى أعْطاهُم. أيُّها الرَّبُّ إلهُنا أنْتَ إسْتَجبْتَ لَهُم، صِرْتَ لَهُم يا اللَّهُ غَفوراً ومنْتَقماً عَلَى جَميعِ أعْمالِهِم، ارْفَعوا الرَّبَّ إلَهَنا، واسْجُدوا فى جَبَلِه المقَدَّس فإنَّ الرَّبَّ إلَهَنا قُدّوسٌ. هَلِّلُويا.'),
      PrayerSection(
          id: 'ninth_09',
          title: 'مزمور 99: هللوا للرب يا كل الأرض',
          body:
              'هَلِّلُوا للرَّبِّ يا كُلّ الأرْضِ، اعْبدوا الرَّبَّ بالفَرَحِ، ادْخُلوا أمامَهُ بالتَّهْليلِ، اعْلَموا أنَّ الرَّبَّ هُوَ إلَهنا. هُوَ صَنَعَنا ونَحْنُ لَهُ، نَحْنُ شَعْبُهُ وغَنَمُ رعيَّتِهِ، ادْخُلوا أبْوابَهُ بالإعْتِراف، ودِيارَه بالتَّسابيحِ، اعْتَرفوا لَهُ وبارِكوا إسْمَهُ، فإنَّ الرَّبَّ صالحٌ هُوَ.وإلَى الأبَدِ رحْمَتُه، وإلَى جيلٍ فَجيلٍ حَقُّهُ. هَلِّلُويا.'),
      PrayerSection(
          id: 'ninth_10',
          title: 'مزمور 100: لرحمتك وعدلك',
          body:
              'لرَحْمتِكَ وعَدْلكَ أُسَبِّحُكَ يا رَبُّ، أترنَّمُ لَكَ وأتَفهَّمُ فى طَريقٍ بلا عَيبٍ. مَتَى تَأْتى إلَىَّ؟ كنْتُ أسْلُكُ بِدَعةِ قَلبى فى وَسَطِ بَيْتى، لَمْ أضَعْ أمامَ عَينَىَّ أمْراً يُخالِفُ النّاموسَ. صانِعى المعْصِيةِ أبْغَضْتُ. لَمْ يَلْصَقْ بِىَ قَلبٌ مُعوجٌ، وعنْدَ مَيَلانِ الشَّرّير عَنّى لَمْ أكُنْ أعْلم والَّذى يَغْتابُ قَريبَهُ سِرّاً كنتُ أُطاردُهُ، المسْتَكبرُ بعيْنَيهِ والمنْتَفخُ القَلْب لَمْ أآكلَهُ.\nعَيْناىَ عَلَى جَميعِ أُمَناءِ الأرْضِ لِكَىْ أُجْلِسَهُم مَعى، السّالِكُ فى الطَّريقِ بِلا عَيبٍ، هَذا كانَ يخْدُمنى. المتَكبِّرُ لَمْ يَسْكُنْ فى وَسَطِ بَيْتى، المتَكلِّمُ بالظُّلمِ لَمْ يَسْتَقِمْ أمامَ عَيْنىَّ، فى أوْقاتِ الغَدَوات كُنتُ أقْتلُ جَميعَ خُطاةِ الأرْضِ، لأبيدَ مِنْ مَدينَةِ الرَّبِّ جَميعَ صانِعى الإثْمِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'ninth_11',
          title: 'مزمور 109: قال الرب لربي',
          body:
              'قالَ الرَّبُّ لِرَبّى إجْلسْ عَنْ يَمينى، حَتَّى أَضع أعْدائِكَ عِنْدَ مَوْطئ قَدَميْكَ. عَصا قُوَّة يُرْسلُ لَكَ الرَّبُّ مِنْ صِهْيون، فَتَسودُ فى وَسَطِ أعْدائِكَ. مَعَكَ الرِّياسَةُ فى يَومِ قُوَّتِكَ فى بَهاءِ القدّيسينَ. مِن البَطْنِ قَبْل كَوْكبِ الصُّبْح وَلدتكَ.\nأَقْسَمَ الرَّبُّ ولَنْ يَنْدَم، أنَّكَ أنْتَ هُوَ الكاهِنُ إلَى الأبدِ عَلَى طَقْسِ مَلْكى صادَق. الرَّبُّ عَنْ يَمينِكَ، يُحطِّمُ فى يَوْمِ رِجْزِهِ مُلوكاً، يَقْضى بَينَ الأممِ، يَمْلأ الأرْضَ جُثَثاً. يَسْحقُ رؤوسَ كَثيرينَ عَلَى الأرْضِ، وفى الطَّريقِ يَشْربُ الماءَ مِنَ الْوادى. لذَلِكَ يرْفَعُ رَأسَه. هَلِّلُويا.'),
      PrayerSection(
          id: 'ninth_12',
          title: 'مزمور 110: أعترف لك يا رب',
          body:
              'أعْتَرفُ لَكَ يا رَبُّ مِنْ كُلِّ قَلبى، فى مَجْلسِ المسْتَقيمينَ وفى مَجْمَعِهِم. عَظيمةٌ هِىَ أعْمالُ الرَّبِّ، ومَشيئاتُه كُلُّها مفْحوصةٌ. جَلالٌ وبَهاءٌ عَملُهُ، وعَدْلهُ دائمٌ إلَى الأبَدِ. ذَكَرَ جَميعَ عَجائِبهِ، رَحيمٌ هُوَ الرَّبُّ ورَؤوفٌ. أعْطَى طعاماً لأتْقِيائِهِ، يَذكُرُ إلَى الدَّهرِ ميثاقَهُ، أخْبَرَ شَعبهُ بِقُوةِ أعْمالِهِ، لِيُعطيهُم ميراثَ الأممِ. أعْمالُ يَدَيهِ حَقٌّ وعَدْلٌ، كُلُّ وَصاياهُ صادقَةٌ ثابتَةٌ إلَى دَهْر الدُّهورِ، مَصْنوعَةٌ بالحَقِّ والإسْتِقامَةِ. أرْسَلَ خَلاصاً لشَعْبهِ، أمَرَ بعهْدِهِ إلَى الأبدِ. إسْمُهُ قُدّوسٌ مَرْهوبٌ، رأسُ الحِكْمَةِ مَخافةُ الرَّبِّ، والفَهْمُ صالحٌ لِكُلِّ مَنْ يَعْملُ بِهِ. وتسْبِحَتُه دائِماً إلَى الأبَدِِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'ninth_13',
          title: 'مزمور 111: طوبى للرجل الخائف الرب',
          body:
              'طوبَى للرَّجُل الخائِفِ الرَّبِّ، ويَهْوَى وَصاياه جِدّاً، يُقَوّى نَسْلهُ عَلَى الأرْضِ، جيلُ المسْتَقيمينَ يُبارَكُ. مَجْدٌ وغِنى فى بَيْتِهِ، وبرُّهُ يَدومُ إلَى الأبَدِ. نورٌ أشْرَقَ فى الظُّلْمةِ للمُسْتَقيمينَ، الرَّبُّ الإلهُ رَحيمٌ ورَؤوفٌ وبارٌّ.\nصالِحٌ هُوَ الرَّجُلُُ الَّذى يَتَرَأَّفُ ويُقْرِضُ. يُدبِّرُ أقْوالَهُ بالحَقِّ، لأنَّهُ لا يَتزعْزَعُ إلَى الدَّهرِ، ذِكْرُ الصِّدّيقِ يَدومُ إلَى الأبَدِ، لا يَخْشَى مِنْ خَبرِ السّوءِ. قلْبُهُ ثابتٌ فَلا يَتزعْزَعُ حتَى يَرَى بأعْدائِهِ. فَرَّقَ أعْطَى المساكينَ، برُّهُ دائمٌ إلَى دَهْرِ الدُّهورِ. يَرتَفع قَرنَهُ بالمجْدِ. الخاطئُ يُبْصرُ فَيغْتاظ، ويُصرُّ بأسْنانِه ويَذوبُ. شَهْوةُ الخاطئ تبيدُ. هَلِّلُويا.'),
      PrayerSection(
          id: 'ninth_14',
          title: 'مزمور 112: سبحوا الرب أيها الفتيان',
          body:
              'سبِّحُوا الرَّبِّ أيُّها الفتِيانُ، سَبِّحُوا إسْمَ الرَّبِّ. لِيَكُنِ إسْمُ الرَّبِّ مُبارَكاً مِنَ الآنِ وإلى الأبَدِ. مِنْ مَشَارقِ الشَّمْسِ إلى مَغارِبِها بَاركُوا إسْمَ الرَّبِّ. الرَّبُّ عَالٍ عَلى كلِّ الأمُمِ، فَوْقَ السَّمَوات مَجْدهُ. مَنْ مِثْلُ الرَّبِّ إلَهنَا السَّاكِنِ فى الأعَالى، النَّاظِرِ إلى المتَواضِعِينَ فى السَّماءِ وعَلى الأرْضِ. المقِيمِ المسْكِينَ مِنَ التُّرابِ، الرَّافِع البَائِسِ مِنَ المزْبَلةِ، لِكىْ يُجْلسَهُ مَعَ رُؤسَاءِ شَعْبهِ. الذِى يَجْعلُ العَاقِرَ ساكِنَة فى بَيْتٍ، أمَّ أوْلادٍ فرِحةً. هَلِّلُويا.'),
      PrayerSection(
          id: 'ninth_15',
          title: 'مزمور 114: أحببت أن يسمع الرب',
          body:
              'أحْببتُ أَنْ يَسْمعَ الرَّبُّ صَوتَ تَضَرُّعى، لأنَّهُ أمالَ أُذنَهُ إلَىَّ فأدْعوهُ كُلَّ أيّامى. لأَنَّ أوْجاعَ الموْتِ اكْتَنَفتْنى، وشَدائِدَ الجَحيمِ أصابَتنى ضيقاً وحُزْنا وَجَدت. وباسْم الرَّبِّ دَعوت. يا رَبُّ نَجِّ نَفْسى. الرَّبُّ رَحيمٌ وصِدّيقٌ، وإلَهنا يَرْحَمُ. الَّذى يَحْفظُ الأطْفالَ هُوَ الرَّبُّ، إتَّضَعْتُ فَخلِّصنى. ارْجِعى يا نَفْسي إلَى مَوْضِعِ راحَتكِ، لأنَّ الرَّبَّ قَدْ أحْسَنَ إلَىَّ وأنْقَذَ نَفْسى مِنَ الموْتِ، وعَيْنَىَّ مِنَ الدُّموعِ، ورِجْلَىَّ مِنَ الزَّلَلِ. أرْضَى الرَّبّ أماَمه فى كورَةِ الأحْياءِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'ninth_16',
          title: 'مزمور 115: آمنت لذلك تكلمت',
          body:
              'آمَنْتُ لِذلِكَ تَكلَّمْتُ، وأَنا اتَّضَعتُ جِدّاً. أَنا قلْتُ فى حَيْرتى أنَّ كُلَّ النّاسِ كاذِبونَ. بِماذا أُكافِئُ الرَّبَّ عَنْ كُلِّ ما أعْطانيهِ؟ كأْسُ الخَلاصِ آخُذُ وباسْمِ الرَّبِّ أدْعو. أُوفى نُذورى للَّرِّب قُدّامَ كُلِّ شَعْبِهِ.\nكَريمٌ أمامَ الرَّبِّ مَوْت قِدّيسيهِ. يا رَبُّ أَنا عَبْدكَ، أَنا عَبْدكَ. وابْنُ أمَتِكَ. قَطَعْتَ قُيودى. فَلَكَ أذْبَحُ ذَبيحةَ التَّسْبيحِ. وباسْمِ الرَّبِّ أدْعو. أُوفى للرَّبِّ نُذورى، فى دِيارِ بَيتِ الرَّبِّ، قُدّامَ كُلِّ شَعْبِهِ، فى وَسَطِ أورُشَليم. هَلِّلُويا.'),
      PrayerSection(
          id: 'ninth_17',
          title: 'الإنجيل (لوقا 9:10-17)',
          body:
              'ولمّا رَجعَ الرُّسُلُ حَدَّثوهُ بما فَعلوا، فأخَذَهُم مَعهُ ودَخلَ عَلَى إنْفِرادٍ إلَى مَوْضع خَلاءٍ لمدينَةٍ تُسَمَّى بَيْتَ صَيْدا. فَلَمّا عَلِمَت الجُموعُ تَبعوهُ فَقَبلهُمْ وخاطَبَهُم عَنْ مَلَكوتِ اللَّهِ. والمحْتاجونَ إلَى الشِّفاءِ شَفاهُمْ، وكانَ النَّهارُ قَد بَدأ يَميلُ فَتقدَّمَ إليْهِ الإثْنا عَشَر وقالوا لَهُ اصْرِف الجُموعَ لِيَذْهَبوا إلَى القُرَى المحيطةِ والحُقول ليَسْتَريحوا ويَجِدوا ما يَأْكلونَهُ، فإنَّنا هَهُنا فى مَوضِعٍ قَفْرٍ. فَقالَ لَهُم: أعْطوهُم أنْتُم ليَأْكُلوا. فَقالوا لَيْسَ عِنْدَنا أكْثَر مِنْ خَمْسِ خُبْزاتٍ وسَمَكَتيْنِ، إلاّّ أنْ نَمْضى نَحنُ وَنَشْتَرى أطْعِمةً لهَذا الشَّعْبِ جَميعِهِ، وَكانوا نَحْو خَمْسةِ آلافِ رَجُلٍ. فَقالَ لتَلاميذِه: لِيَتَّكِئُوا فى كُلِّ مَوْضِعٍ خَمْسينَ خَمْسينَ فَفَعَلوا هَكَذا واتكأوهُمْ أجْمعيَن. فأخَذَ الخَمس خبْزاتٍ والسَّمكَتيْنِ ونَظَرَ إلَى السَّمَاءِ وبارَكَها وقَسَّمَها وأعْطَى التَّلاميذَ ليَضَعوا أَمامَ الجُموعِ. فَأَكَلوا جَميعُهُمْ وشَبعوا، ثُمَّ رَفَعوا ما فَضَلَ عَنْهُم مِنَ الكِسَرِ اثْنَتَىْ عَشَرَة قُفَّةً مَمْلوءةً. والمجْدُ للَّهِ دائما.'),
      PrayerSection(
          id: 'ninth_18',
          title: 'القطعة الأولى',
          body:
              'يا مَنْ ذاقَ الموْتَ بالجَسَدِ فى وَقْتِ السّاعَةِ التّاسِعَةِ مِنْ أجْلِنا نَحْنُ الخُطاةُ، أَمِتْ حَواسَّنا الجسْمانِيَّةَ أيُّها المسيحُ إلَهُنا ونَجِّنا. فَليَدنْ تَوَسُّلى قُدّامك يارَبُّ، كقَوْلكَ فَهِّمنى. لتَدْخُل طلبَتى إلَى حَضْرتِكَ، كَكَلِمَتك أحْيينِى. ( ذُوكصابترى )'),
      PrayerSection(
          id: 'ninth_19',
          title: 'القطعة الثانية',
          body:
              'يا مَنْ أسْلمَ الرّوحَ فى يَدَى الآبِ عِنْدَما عُلِّقتَ عَلَى الصَّليبِ وَقْت السّاعةِ التّاسِعةِ، وهَديْتَ اللِّصَّ المصْلوبَ مَعَك للدُّخولِ إلَى الفِرْدَوْسِ، لا تَغْفلْ عنّى أيُّها الصّالِحُ، ولا ترْذلنى أَنا الضّالُّ. بلْ قَدِّسْ نَفْسى وأَضئ فَهْمى. واجْعَلنى شَريكًا لنِعْمَةِ أسْرارِكَ المُحْيِيَةِ. لِكَيْما إذا ذُقْتُ مِنْ إحْساناتِكَ، أُقدِّمُ لَكَ تَسْبحةً بِغَيْرِ فُتورٍ،مُشْتاقاً إلَى بَهائِكَ أفْضَل مِنْ كُلِّ شَئٍ أيُّها المسيحُ إلهُنا ونَجِّنا. ( كى نين )'),
      PrayerSection(
          id: 'ninth_20',
          title: 'القطعة الثالثة',
          body:
              'يا مَنْ وُلِدْتَ مِنَ البَتولِ مِنْ أجْلِنا واحْتَملْتَ الصَّلْبَ أيُّها الصّالُح، وقَتَلْتَ الموْتَ بمَوْتكَ وأظْهَرتَ القِيامَةَ بقِيامَتِكَ، لا تُعْرِض يا اللَّهُ عن الَّذينَ جَبَلتَهُم بِيَديْكَ، أَظْهِر مَحبَّتكَ للبَشَرِ أيُّها الصَالحُ. اقْبَلْ مِنْ والِدَتِكَ شَفاعةً مِنْ أجْلنا. نَجِّ يا مُخلِّصُ شَعْباً مُتواضِعاً، لا تَتْركْنا إلَى الإنْقِضاءِ، ولا تُسلِّمنا إلَى الدَّهْر، ولا تَنْقُضْ عَهْدكَ. ولا تَنْزعْ عَنّا رَحْمتَكَ، مِنْ أجْل إبْراهيم حَبيبِكَ، وإسْحَق عَبْدِك، وإسْرائيل قِدّيسِكَ. ( كى نين )'),
      PrayerSection(
          id: 'ninth_21',
          title: 'القطعة الرابعة',
          body:
              'لَمّا أبْصَرَ اللِّصُّ رَئيسَ الحَياةِ عَلَى الصَّليبِ مُعَلَّقًا قالَ: لَوْلا أنَّ المصْلوبَ مَعنا إلهٌ مُتَجسِّدٌ، ما كانَت الشَّمسُ أخْفَتْ شُعاعَها ولا الأرْض ماجَت مُرتَعدةً. لَكِن أيُّها القادِرُ عَلَى كُلِّ شَئٍ والمحْتَملُ كُلَّ شَئٍ، اذْكُرْنى يا رَبُّ مَتَى جِئت فى مَلَكوتكَ. ( ذُوكصابترى )'),
      PrayerSection(
          id: 'ninth_22',
          title: 'القطعة الخامسة',
          body:
              'يا مَن قَبلَ إلَيْه إعْتِرافُ اللِّصِّ عَلَى الصَّليبِ، إقْبَلنا إليْكَ أيُّها الصّالحُ نَحْنُ المسْتَوْجبينَ حُكْم الموْتِ مِنْ أجْل خَطايانا. نُقِرُّ بِخَطايانا مَعَهُ، مُعْترفينَ بأُلوهِيَّتِكَ، ونَصرخُ مَعَه جَميعًا: اذْكُرنا يا رَبُّ مَتَى جِئتُ فى مَلَكوتِكَ. ( كى نين )'),
      PrayerSection(
          id: 'ninth_23',
          title: 'القطعة السادسة',
          body:
              'عنْدَما نَظَرَت الوالِدةُ الحَمَلَ والرّاعى مُخَلِّصَ العالَم عَلَى الصَّليبِ مُعلَّقًا، قالَت وهِىَ باكِيَةٌ: أمّا العالمُ فَيفْرحُ لقَبولهِ الخَلاص، وأمّا أحْشائى فَتلْتَهبُ عِنْد نَظَرى إلَى صَلَبوتِكَ الَّذى أَنْتَ صابرٌ عَليهِ مِنْ أجْلِ الكُلِّ يا إبْنى وإلَهى.'),
      PrayerSection(
          id: 'ninth_24',
          title: 'يارب ارحم 41 مرة',
          body: 'يُقال ( كيريى لَيْسُون ) يَارَبُّ ارْحَمْ 41 مرة.'),
      PrayerSection(
          id: 'ninth_25',
          title: 'قدوس قدوس قدوس',
          body:
              'قُدّوسٌ قُدّوسٌ قُدّوسٌ رَبُّ الصَّباؤوتِ. السَّماءُ والأرْضُ مَمْلوءتانِ مِنْ مَجْدكَ وكَرامَتكَ. إرْحَمْنا يا اللَّهُ الآبُ ضابِطُ الكُلِّ، أيُّها الثّالوثُ القُدّوسُ إرْحَمْنا. أيُّها الرَّبُّ إلهُ القُوّاتِ كُنْ مَعَنا، لأنَّهُ لَيسَ لَنا مُعينٌ فى شَدائِدنا وضيقاتِنا سِواكَ. حلّ واغْفِرْ واصْفَحْ لَنا يا اللَّهُ عَنْ سَيِّئاتِنا الَّتى صَنَعْناها بإرادَتِنا والَّتى صَنَعْناها بغَيرِ إرادَتنا، الَّتى فَعلْناها بمَعرِفةٍ والَّتى فَعلْناها بغَير مَعْرِفةٍ، الخَفيَّةِ والظاهِرةِ، يا رَبُّ اغْفِرها لَنا مِنْ أجْلِ إسْمِكَ القُدّوسِ الَّذى دُعى عَليْنا. كَرحْمتِكَ يا رَبُّ ولا كَخَطايانا.'),
      PrayerSection(
          id: 'ninth_26',
          title: 'الصلاة الربانية',
          body:
              'اللَّهُم اجْعلنا مُستحِقين أنْ نقولَ بِشكرٍ:\nأبانا الذي في السَّمَواتِ، لِيتَقدس اسْمكَ. ليأتِ مَلكوتُكَ. لتَكن مَشيئَتُكَ، كما في السّماءِ كَذلك على الأرْضِ. خُبزَنا الذي للغدِ اعطِنا اليومَ. واغفِر لنا ذنوبَنا كما نغْفر نحنُ أيضّا للمذنبينَ إلينا. ولا تُدخِلنا في تَجرِبةٍ. لكن نجّنا مِنْ الشّريرِ. بالمسيحِ يسوعُ ربُّنا، لأنَّ لَكَ المُلكَ والقوةَ والمجدَ إلى الأبدِ. آمين.'),
      PrayerSection(
          id: 'ninth_27',
          title: 'التحليل',
          body:
              'يا اللَّهُ الآبُ أَبو رَبِّنا وإلَهِنا ومُخَلِّصِنا يَسوعِ المَسيحِ هَذا الَّذى بظُهورِهِ خَلَّصْتَنا وأنْقَذْتَنا مِنْ عُبوديَّةِ العَدُوِّ، نَسْألُكَ باسْمِه المُبارَك العَظيمِ، انْقُلْ عُقولنا مِنَ الإهْتِمامِ العالَمى والشَّهَواتِ الجَسَديَّةِ إلَى تِذْكارِ أحْكامِكَ السَّمائِيَّةِ. وكَمِّلْ لَنا مَحبَّتِكَ للْبَشرِ أيُّها الصّالِحُ. ولِتَكنْ صَلَواتُنا كُلَّ حينٍ، وصَلاةُ هَذِه السّاعةِ التّاسِعةِ مقْبولةً أمامَكَ، امْنَحْنا أَنْ نَسْلُكَ كَما يَليقُ بالدَّعْوةِ الَّتى دُعينا إلَيْها، لِكَىْ إذا خَرجْنا مِنْ هَذا الجَسَدِ نُحسَبُ مَعَ السّاجِدينَ المسْتَحقّينَ لآلامِ إبْنِكَ الوَحيدِ يَسوعِ المَسيحِ رَبِّنا، ونَظْفر بالرَّحْمَةِ وغُفْرانِ خَطايانا. والخَلاصِ مََ مَصافِّ القِدّيسينَ الَّذينَ أرْضوكَ بالحَقيقَةِ مُنْذُ الدَّهْرِ وإلَى الأبَِ.\nاللَّهُمَّ أبْطِلْ عَنّا كُلَّ قُوَّةِ المُعانِدِ وجَميعَ جُنودِهِ الرَّديئةِ، كَما داسَهُم إبْنُكَ الوَحيدُ بِقُوَّةِ صَليبِهِ المُحْيي. اقْبَلْنا إليْكَ يا سيِّدى يَسوعِ المَسيحِ، كَما قَبِلتَ اللِّصّ اليَمين وأنْتَ مُعَلَّقٌ عَلَى عودِ الصَّليبِ. وأَنرْ عَليْنا كَما أنَرْتَ عَلَى الَّذينَ كانوا فى ظُلْمةِ الجَحيمِ. وَرُدَّنا جَميعًا إلَى فِرْدوسِ النَّعيمِ. لأنَّكَ يا سَيِّدى إلَهٌ مُبارَكٌ ويَنْبغى لَكَ مَعَ أبيكَ الصّالحِ والرّوحِ القُدُسِ المجْدُ والإكْرامُ والعِزَّةُ والسُّلْطانُ والسُّجودُ إلَى الأبَدِ. آمين.'),
      PrayerSection(
          id: 'ninth_28',
          title: 'طلبات تقال آخر كل ساعة',
          body:
              'إرْحَمْنا يا اللَّهُ ثمَّ إرْحَمْنا، يا مَنْ فى كلِّ وقْتٍ وكلِّ ساعَةٍ، فى السَّماءِ وعلَى الأرْض مَسْجودٌ لَهُ ومُمجَّدٌ، المسيحُ إلَهنا الصّالحُ الطَّويلُ الرّوحِ الكثيرُ الرَّحْمةِ الجَزيلُ التَّحنُّنِ، الَّذى يُحبُّ الصِّدّيقيَن ويَرْحمُ الخُطاةَ الَّذينَ أوَّلهُم أَنا، الَّذى لا يَشاءُ مَوْت الخاطِئ مِثل ما يَرجعُ ويَحْيا، الدّاعى الكُلَّ إلَى الخَلاصِ لأجْلِ الموْعدِ بالخَيْراتِ المنْتَظرةِ.\nيا رَبُّ اقْبَل مِنّا فى هَذهِ السّاعةِ وكُلِّ ساعَةٍ طلباتِنا. سَهِّلْ حَياتَنا، وأرشِدْنا إلَى العَمَل بوَصاياكَ. قَدِّسْ أرْواحَنا.طهِّرْ أجْسامَنا. قَوِّمْ أفْكارَنا. نَقِّ نِيّاتَنا واشْفِ أمْراضَنا واغْفِرْ خَطايانا. ونَجِّنا مِنْ كلِّ حُزنٍ رَدئٍ ووَجَِعِ قَلْبٍ، أحِطْنا بمَلائِكتِكَ القدّيسينَ لكىْ نَكونَ بمُعَسْكَرهِم مَحْفوظينَ ومُرْشَدينَ، لنَصِلَ إلَى إتِّحاد الإيمانِ وإلَى مَعْرفةِ مَجْدكَ غَيرِ المحْسوسِ وغَيْر المحْدود، فإنَّكَ مُبارَكٌ إلَى الأبَدِ. آمين.'),
    ];
  }

  List<PrayerSection> _getSunsetSections() {
    return [
      PrayerSection(
          id: 'sunset_01',
          title: 'الصلاة الربانية',
          body:
              'بِسْم الآب والابنْ والرُوح القُدُس\nالإلَه الوَاحِد، آمين\n( كيريى لَيْسُون ) يَارَبُّ ارْحَمْ. يَارَبُّ ارْحَمْ. يَارَبُّ بارِكْ. آمين.\nالمجدُ للآبِ والابنِ والروحِ القُدسِ الآنَ وكلَّ أوانِ وإِلَى دهرِ الدهورِ. آمين.\nاللَّهُم اجْعلنا مُستحِقين أنْ نقولَ بِشكرٍ:\nأبانا الذي في السَّمَواتِ، لِيتَقدس اسْمكَ. ليأتِ مَلكوتُكَ. لتَكن مَشيئَتُكَ، كما في السّماءِ كَذلك على الأرْضِ. خُبزَنا الذي للغدِ اعطِنا اليومَ. واغفِر لنا ذنوبَنا كما نغْفر نحنُ أيضّا للمذنبينَ إلينا. ولا تُدخِلنا في تَجرِبةٍ. لكن نجّنا مِنْ الشّريرِ. بالمسيحِ يسوعُ ربُّنا، لأنَّ لَكَ المُلكَ والقوةَ والمجدَ إلى الأبدِ. آمين.'),
      PrayerSection(
          id: 'sunset_02',
          title: 'صلاة الشكر',
          body:
              'فَلْنشْكُرّ صَانِعَ الخَيراتِ الرَّحُومَ الله أبَا رَبِّنَا وإلهِنَا ومُخَلِصَنا يَسُوعِ المسِيحِ. لأنَّهُ سَتَرنَا، وأعَانَنَا، وحَفِظَنا، وقَبِلَنا إليهِ، وأشْفَقَ عَلينَا، وعَضَّدنَا، وأَتَى بنا إلى هَذِهِ السَّاعَة. هُو أيْضاً فَلْنَسْأَلَهُ أنْ يَحْفَظَنا فى هَذَا اليَومِ المقَدَّسِ وكُلِّ أيَّامِ حَيَاتنَا بكلِّ سَلامِ. الضَّابِطُ الكُلّ الرَّبُ إلَهنَا.\nأيُّهَا السَّيِدُ الرَّبُّ الإلَه ضَابطُ الكُلِّ أبُو ربِّنَا وإلهنَا ومُخَلصَّنَا يَسُوعِ المسِيح نَشْكرُكَ عَلَى كُلِّ حالٍ، ومِنْ أجْل كلِّ حَالٍ، وفى كُلِّ حالٍ، لأنَّكَ سَترْتَنا، وأعَنْتَنا، وحفِظْتنَا، وقَبلْتنَا إليْكَ، وأشْفَقْت عَلينا، وعَضَّدْتَنَا، وأتَيتَ بِنَا إلىَ هَذِه السَّاعةِ.\nمن أجْلِ هَذَا نَسْألُ ونَطْلبُ مِنْ صَلاحِكَ يَامُحبَّ البَشَر، امْنَحنَا أنْ نُكْملَ هذا اليَوْمَ المقَدَّسَ وكلّ أيَّامِ حَياتِنَا بِكلِّ سَلامٍ مَعَ خَوفِكَ، كُلُّ حَسَدٍ، وكلُّ تَجربَةٍ. وكلُّ فِعْلِ الشَّيْطانِ، ومُؤامَرةِ النَّاسِ الأشْرارِ، وقِيام الأعْدَاءِ الخَفيِّينَ والظَّاهِرينَ، إنْزَعهَا عنَّا وعَنْ سَائِرِ شَعْبكَ وعَنْ مَوضِعِكَ المقَدَّسِ هَذا. أمَّاَ الصَّالِحاتُ والنَّافعاتُ فَارزُقْنا إيَّاهَا. لأنَّكَ أنْتَ الذِى أعْطَيتَنا السُّلْطانَ أنْ ندوسَ الحَيَّاتِ والعَقارِبَ وكُلَّ قوَّةِ العَدوِّ.\nولا تُدْخِلنَا فى تَجربَةٍ، لَكنْ نَجِّنا مِنَ الشِّرِّيرِ. بالنِّعْمةِ والرَّأْفَاتِ ومَحبَّة البَشرِ اللَّواتِى لإبْنِك الوَحيدِ ربِّنا وإلهِنَا ومُخلِّصِنا يَسُوعِ المسيحِ. هَذَا الذِى مِنْ قِبَلِه الَمجْدُ والإكْرام والعزَّةُ والسُّجودُ تَلِيقُ بكَ مَعهُ مَعُ الرُّوحِ القُدُسِ الَمحْيى المسَاوِى لَكَ الآنَ وكلَّ أوَانٍ وإلىَ دَهرِ الدُّهُورِ. آمين. '),
      PrayerSection(
          id: 'sunset_03',
          title: 'المزمور الخمسون',
          body:
              'إرْحَمنِى يَا الله كَعَظيمِ رَحْمتِكَ، ومِثْل كَثْرةِ رَأفتِكَ تَمْحُو إثْمِى. تَغْسلُنِى كَثيراً مِنْ إثْمِى، ومِنْ خَطيَّتِى تُطهَّرنِى. لأنِّى عارفٌ بإثْمِى، وخَطيَّتِى أمَامِى فى كلِّ حينٍ. لَكَ وحْدَك أخْطأْت، والشَّرُّ قدامَكَ صَنعْتُ. لِكىْ تَتَبرَّرَ فى أقْوالِكَ. وتَغْلبَ إذَا حَاكمْت. لأنِّى هَا أنَذَا بالاثْمِ حُبلَ بِى، وبالَخَطايَا وَلَدتْنِى أمِّى. لأنَّكَ هَكَذا قَدْ أحْبَبتُ الحقَّ، إذْ أوْضَحتَ لِى غَوامِضَ حِكْمتِكَ ومَسْتورَاتِها. تَنضَحُ عَلىَّ بِزُوفَاكَ فأطَّهَّرُ، تَغْسلُنِى فَأبْيضُّ أكْثَر مِنَ الثَّلجِ، تَسْمعُنِى سُرُوراً وفَرحاً، فتَبْتهجُ عِظامِى المنْسَحقةُ. أصْرِفْ وجْهَكَ عَنْ خَطايَاىَ، وأمْحُ كلَّ اثَامِى. قَلبِاً نَقياً أخْلقْ فىَّ يَا الله، ورُوحاً مُسْتَقيماً جدِّدهُ فى أحْشَائِى. لا تَطْرحْنِى مِنْ قُدَّامَ وجْهكَ، ورُوحكَ القُدُّوسِ لا تَنْزعْهُ مِنِّى. امْنَحْنِى بَهْجةَ خَلاصِكَ، وبرُوحِ مُدبِّرٍ عَضِّدّنِى فأعْلمِ الأثَمَةَ طُرُقكَ، والمنَافِقونَ إليْكَ يَرجعونَ، نَجِّنِى مِنَ الدِّماء يا الله إلَه خَلاصِى، فيَبتَّهجُ لِسانِى ببرَّكَ. يَاربِّ إفْتَح شَفتَىَّ فَيُخبرُ فَمِى بَتَسْبيحِكَ. لأنَّكَ لَوْ أثَرتَ الذَّبيحةَ، لَكُنْتُ الآنَ أعْطِى. ولَكنَّكَ لا تُسرُّ بالَمحْرقَاتِ، فالذَبيحَةُ للهِ رُوحَّ مُنْسحقَّ. القَلْبُ المنْكسِرُ والمتَواضِعُ لايُرْزلهُ الله، أنْعمْ يَا ربّ بِمَسرتكَ عَلى صِهْيُون، ولْتَبنِ أسْوَارَ أورْشَلِيم. حِينَئذٍ تُسرُّ بذَبائِح البَرِّ قرباناً ومُحْرقَات ويُقَّربون عَلى مَذابِحكَ العُجُول. هَلِّلُويا.'),
      PrayerSection(
          id: 'sunset_04',
          title: 'بدء الصلاة',
          body:
              'تَسْبحَةُ الغُروب مِنَ النَّهارِ المبارَكِ أقدِّمها للْمَسيحِ مَلِكى وإلَهى وأرْجوهُ أنْ يَغْفرَ لِى خَطاياىَ.'),
      PrayerSection(
          id: 'sunset_05',
          title: 'مزمور 116: سبحوا الرب يا جميع الأمم',
          body:
              'سَبِّحوا الرَّبَّ يا جَميعَ الأممِ، ولتُبارِكهُ كافَّةُ الشُّعوب، لأنَّ رَحْمَتهُ قَدْ قَويَتْ عَليْنا، وحَقُّ الرَّبِّ يَدومُ إلَى الأبَدِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'sunset_06',
          title: 'مزمور 117: اعترفوا للرب لأنه صالح',
          body:
              'اعْتَرفوا للرَّبِّ لأنَّهُ صالِحُ وأنَّ إلَى الأبَدِ رَحْمَتَهُ. لِيَقُلْ بَيْتُ إسْرائيلَ إنَّهُ صالِحٌ وإنَّ إلَى الأبَدِ رَحْمَتَهُ. لِيَقُلْ بَيْتُ هَرونَ إنَّهُ صالِحٌ وإنَّ إلَى الأبَدِ رَحْمَتَهُ. لِيَقُلْ أتْقِياءُ الرَّبِّ إنَّهُ صالِحٌ وإنَّ إلَى الأبَدِ رَحْمَتَهُ.\nفى ضيقَتى صَرَخْتُ إلَى الرَّبِّ، فاسْتَجابَ لى وأخْرجَنى إلَى الرَّحْبِ. الرَّبُّ عَوْنى فَلا أخْشَى، ماذا يَصْنعُ بى الإنْسانُ؟ الرَّبُّ لى مُعينٌ، وأنا أرَى بأعْدائى. الإتِّكالُ عَلَى الرَّبِّ خَيْرٌ مِنَ الإتِّكالِ عَلَى البَشَرِ. الرَّجاءُ بالرَّبِّ خَيْرٌ مِنَ الرَّجاءِ بالرُّؤَساءِ. كُلُّ الأممِ أَحاطوا بى، وباسْمِ الرَّبِّ انْتَقَمتُ مِنْهُمْ. أَحاطوا بى احْتِياطًا واكْتَنَفونى وباسْمِ الرَّبِّ قَهَرْتُهُمْ. أَحاطوا بي مِثْلَ النَّحْلِ حَولَ الشَّهْدِ، والْتَهَبوا كَنارٍ فى شَوْكٍ، باسْمِ الرَّبِّ انْتَقمْتُ مِنْهُم. دُفِعْت لأَسْقُطَ والرَّبّ عَضدَنى. قُوَّتى وتَسْبِحَتى هُوَ الرَّبُّ، وقَدْ صارَ لى خَلاصاً. صَوْتُ التَّهْليلِ والخَلاصِ فى مَساكِنِ الأبْرارِ، يَمينُ الرَّبِّ صَنَعَتْ قُوَّةً، يَمينُ الرَّبِّ رَفَعَتْنى، يَمينُ الرَّبِّ صَنَعَتْ قُوَّةً فَلَنْ أَموت بَعْدَ، بَلْ أحْيا وأُحَدِّثُ بأعْمالِ الرَّبِّ، تأْديبًا أدَّبَنى الرَّبُّ. وإلَى الموْتِ لَمْ يُسلِمنى.\nإفْتَحوا لى أبْوابَ البِرِّ، لِكَىْ أدْخُلَ فيها وأعْتَرف للرَّبِّ. هَذا هُوَ بابُ الرَّبِّ، والصِّدّيقونَ يَدْخُلونَ فيهِ. أعْتَرفُ لَكَ يارَبُّ، لأنَّكَ اسْتَجَبْتَ لى وكُنتَ لى مُخلِّصًا. الحَجَرُ الَّذى رَذَلهُ البَنّاؤونَ، هَذا صارَ رَأْسًا للزّاوِيةِ. مِنْ قِبَلِ الرَّبِّ كانَ هَذا وهُوَ عَجيبٌ فى أعْيُننا.\nهَذا هُوَ اليَوْمُ الَّذى صَنَعَهُ الرَّبُّ، فَلْنَبْتَهجُ ونَفْرَحُ فيهِ. يا رَبُّ خَلِّصْنا، يارَبُّ سَهِّلْ سُبُلَنا، مُبارَكٌ الآتى باسْمِ الرَّبِّ، بارَكْناكُم مِنْ بَيْتِ الرَّبِّ، اللَّهُ الرَّبّ أضاءَ عَلَيْنا. رَتِّبوا عيداً بِمَوْكِبٍ حَتَّى قُرونِ المذْبَحِ، أنْتَ هُوَ إلَهى فأشْكُركَ، إلَهى أنْتَ فَأَرْفَعكَ. أعْتَرفُ لَكَ يا رَبُّ، لأنَّكَ إسْتَجَبتَ لى وصِرْتَ لى مُخلِّصًا. اشْكُروا الرَّبَّ فإنَّه صالحٌ وأنَّ إلَى الأبَدِ رَحْمتُهُ. هَلِّلُويا.'),
      PrayerSection(
          id: 'sunset_07',
          title: 'مزمور 119: إليك يا رب صرخت',
          body:
              'إلَيْكَ يا رَبُّ صَرَخْتُ فى حُزْنى، فاسْتَجَبْتَ لى. يا رَبُّ نَجِّ نَفْسى مِنَ الشِّفاهِ الظّالمةِ، ومِنَ اللِّسانِ الغاشِ، ماذا تُعْطَى وماذا تُزادُ أيُّها اللِّسانُ الغاشُّ؟ سِهامُ الأقْوياءِ مُرهَفةٌ مَعَ جَمْر البَرِّيَةِ. ويْلٌ لى فإنَّ غُرْبَتى قَدْ طالَت عَلَّى، وسَكنْتُ فى مَساكِن قيدار. طَويلاً سَكنَتْ نَفْسى فى الغُرْبَةِ، ومَعَ مُبْغِضى السَّلامِ كُنْتُ صاحِبَ سَلامٍ. وحينَ كُنتُ أُكَلِّمهُم بهِ كانوا يُقاتِلونَنى باطلاً. هَلِّلُويا.'),
      PrayerSection(
          id: 'sunset_08',
          title: 'مزمور 120: رفعت عيني إلى الجبال',
          body:
              'رَفَعْتُ عَيْنَيَّ إلَى الجِبالِ، مِنْ حَيْثُ يَأتى عَوْنى. مَعونَتى مِنْ عِنْدِ الرَّبِّ، الَّذى صَنَعَ السَّماءَ والأرْضَ. لا يُسَلِّمُ رِجْلَكَ للزَّللِ، فَما يَنْعسُ حافِظُك. هُوَذا لا يَنْعَسُ ولا يَنامُ حارِسُ إسْرائِيلَ. الرَّبُّ يَحْفَظُكَ، الرَّبُّ يُظلَّلُ عَلَى يَدِكَ اليُمْنَى. فَلا تَحْرقُكَ الشَّمْسُ بالنَّهارِ، ولا القَمَرُ باللَّيْلِ. الرَّبُّ يَحْفَظكَ مِنْ كُلِّ سوءٍ، الرَّبُّ يَحْفَظُ نَفْسَك. الرَّبُّ يَحْفَظُ دُخولَكَ وخُروجَكَ مِنَ الآنِ وإلَى الأبَدِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'sunset_09',
          title: 'مزمور 121: فرحت بقائلين لي',
          body:
              'فَرحْتُ بالقائِلينَ لى إلَى بَيْتِ الرَبِّ نّذْهَبُ. وَقَفَتْ أرْجلُنا فى أبْوابِ أورُشَليم. أورُشَليمُ المبْنِيَّةُ مِثْل مَدينَةٍ مُتَّصِلةٍ بَعْضُها ببَعْضٍ. لأَّن هُناكَ صَعِدَت القَبائِلُ، قَبائِلُ الرَّبِّ شَهادةً لإسْرائِيلَ. يَعْتَرِفونَ لإسْمِ الرَّبِّ. هُناكَ نُصِبَتْ كَراسِى للْقَضاءِ، كَراسى بَيْتِ داوُدَ.\nإسْأَلوا السَّلامَ لأورُشَليمَ، والخِصْبَ لِمُحِبِّيكِ، لِيَكُنْ السَّلامُ فى حِصْنِك، والخِصْبُ فى أبْراجِك الرَّصينَةِ. مِنْ أجْلِ إخْوَتي وأقارِبى، تَكَلَّمتُ مِنْ أجْلِك بالسَّلامِ. ومِنْ أجْلِ بَيْتِ الرَّبِّ إلَهِنا، إلْتَمَسْتُ لَك الخَيْرات. هَلِّلُويا.'),
      PrayerSection(
          id: 'sunset_10',
          title: 'مزمور 122: إليك رفعت عيني',
          body:
              'إلَيْكَ رفَعْتُ عَيْنى يا ساكِنَ السَّماءِ. فَها هُما مِثْل عُيونِ العَبيدِ إلَى أيْدى مَواليهمْ، ومِثْل عَيْنَى الأمَةِ إلَى يَدَىْ سَيِّدَتِها. كَذَلِكَ أعْيُنُنا نَحْو الرَّبِّ إلَهِنا حَتَّى يَتَرأفَ عَلَيْنا. إرْحَمْنا يا رَبُّ إرْحَمْنا، فإنَّنا كَثيراً ما امْتَلأْنا هَواناً. وكَثيراً ما امْتَلأَتْ نُفوسُنا عاراً مِنَ المخَصِّبينَ، وإهانَةً مِنَ المتَعَظِّمينَ. هَلِّلُويا.'),
      PrayerSection(
          id: 'sunset_11',
          title: 'مزمور 123: لولا أن الرب كان معنا',
          body:
              'لَوْلا أنَّ الرَّبَّ كانَ مَعنا لِيَقُلْ إسْرائيلُ. لَوْلا أنَّ الرَّبَّ كان مَعنا عِنْدَما قامَ النّاسُ عَلَيْنا. لابْتَلَعونا ونَحْنُ أحْياء، عِنْدَ سَخطِ غَضَبِهِمْ عَلَيْنا. إذَنْ لَغرَقْنا فى الماءِ، وجازَ عَلَى نُفوسِنا السَّيْلُ. بَلْ جازَ عَلَى نُفوسِنا الماءُ الَّذى لا نِهايَةَ لَهُ. مُبارَكٌ الرَّبُّ الّذى لَمْ يُسَلِّمْنا فَريسةً لأسْنانِهِم. نَجَتْ أنْفُسُنا مِثْلَ العُصْفورِ مِنْ فَخِّ الصَّيّادينَ، الفَخُّ انْكَسَرَ ونَحْنُ نَجَوْنا، عَوْنُنا بإسْمِ الرَّبِّ، الَّذى صَنَعَ السَّماءَ والأرْضَ. هَلِّلُويا.'),
      PrayerSection(
          id: 'sunset_12',
          title: 'مزمور 124: المتوكلون على الرب',
          body:
              'المتَوَكِّلونَ عَلَى الرَّبِّ مِثْلُ جَبَلِ صِهْيونَ، لا يَتَزعْزَعُ إلَى الأبَدِ. السّاكِنُ بأورُشَليمَ. الجِبالُ حَوْلَها والرَّبُّ حَوْلَ شَعبهِ مِنَ الآنَ وإلَى الأبَدِ. الرَّبُّ لا يَتْركُ عَصا الخُطاةِ تَسْتَقرُّ عَلَى نَصيبِ الصِّدّيقينَ. لِكَىْ لا يَمُدَّ الصِّدّيقونَ أيْدِيَهُم إلَى الإثْمِ.\nأحْسِنْ يا رَبُّ إلَى الصّالِحينَ وإلَى المسْتَقيمى القُلوبِ. أمّا الَّذينَ يَميلونَ إلَى العَثَراتِ يَنْزَعهُم الرَّبُّ مَعَ فَعَلةِ الإثْمِ. والسَّلامُ عَلَى إسْرائِيلَ. هَلِّلُويا.'),
      PrayerSection(
          id: 'sunset_13',
          title: 'مزمور 125: إذا ما رد الرب سبي صهيون',
          body:
              'إذا ما رَدَّ الرَّبُّ سَبْىَ صِهْيونَ صِرْنا فَرِحينَ. حينَئِذٍ امْتَلأَ فَمُنا فَرحًا ولِسانُنا تَهْليلاً. حينَئِذٍ يُقالُ فى الأممِ إنَّ الرَّبّ قَدْ عَظَّمَ الصَّنيعَ مَعَهُم. عَظَّمَ الرَّبُّ الصَّنيعَ مَعَنا فَصِرْنا فَرِحينَ. ارْدد يا رَبُّ سَبْيَنا، مِثْلَ السُّيولِ فى الجَنوبِ. الَّذينَ يَزْرَعونَ بالدُّموعِ يَحْصُدونَ بالابْتِهاجِ. سَيْراً كانوا يَسيرونَ وهُمْ باكونَ حامِلينَ بِذارَهُم، ويَعودون بالفَرَحِ حامِلينَ أغْمارَهُم. هَلِّلُويا.'),
      PrayerSection(
          id: 'sunset_14',
          title: 'مزمور 126: إن لم يبن الرب البيت',
          body:
              'إنْ لَمْ يَبْنِ الرَّبُّ البَيْتَ، فَباطِلاً يَتْعبُ البَنّاؤُونَ. وإنْ لَمْ يَحْرُس الرَّبُّ المَدينَةَ. فَباطِلاً يَسْهرُ الحُرّاسُ. باطِلٌ هُوَ لَكُم التَّبْكيرُ في القِيامِ والتَّأَخُّر عَن الرقادِ يا آكِلي الخُبْزَ بالهُمومِ. فَإنَّهُ يَمْنَح أحِبّاءَهُ نَوْماً.\nالبَنونَ ميراثٌ مِنَ الرَّبِّ، وثَمَرَةُ البَْنِ عَطِيَّةٌ مِنْهُ. كالسِّهامِ بِيَدِ القَوِيِّ، كَذلِكَ أبْناء الشَّبيبَةِ. مَغْبوطٌ هُوَ الرَّجُلُ الَّذي يَمْلأُ جُعْبَتَه مِنْهُم، حينَئِذٍ لا يُخْزَوْنَ إذا كَلَّموا أعْداءَهُم في الأبْوابِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'sunset_15',
          title: 'مزمور 127: طوبى لجميع الذين يتقون الرب',
          body:
              'طوبَى لِجَميعِ الَّذينَ يتَّقونَ الرَّبَّ، السّالِكينَ فى طُرُقِه. لأنَّكَ تَأْكُلُ مِنْ ثَمَرةِ أتْعابِكَ، تَصيرُ مَغْبوطاً ويَكونُ لَكَ الخَيْر. إمْرأَتُكَ تَصير مِثْلَ كَرْمةٍ مُخْصِبَةٍ فى جَوانِبِ بَيْتِكَ، بَنوكَ مِثْلُ غُروسِ الزَّيْتونِ الجُددِ حَوْلَ مائِدَتكَ. هَكَذا يُبارِِكُ الإنْسانُ المتَّقى الرَّبَّ. يُباركُكَ الرَّبُّ مِنْ صِهْيونَ، وتُبْصِرُ خَيْراتِ أورُشَليمَ جَميعَ أيّامِ حَياتِكَ. وتَرَى بَنى بَنيكَ، والسَّلامُ عَلَى إسْرائيلَ. هَلِّلُويا.'),
      PrayerSection(
          id: 'sunset_16',
          title: 'مزمور 128: مراراً كثيرة حاربوني',
          body:
              'مِرارًا كَثيرةً حارَبونى مُنْذُ صِباى لِيَقُلْ إسْرائيلُ. مِرارًا كَثيرةً قاتَلونى مُنْذُ شَبابى، وإنَّهُم لَمْ يَقْدِروا عَلَىَّ. عَلَى ظَهْرى جَلَدنى الخُطاةُ وأَطالوا إثْمَهُمْ. الرَّبّ صِدّيقٌ هُوَ، يَقْطعُ أعْناقَ الخُطاةِ، فَلْيَخْزَ وَلْيَرْتَدَّ إلَى الوَراءِ، كُلُّ الَّذينَ يُبْغِضونَ صِهْيونَ، وليَكونوا مِثْلَ عُشْبِ السُّطوحِ، الَّذى يَيْبَسُ قَبْل أنْ يُقْطَع. الَّذى لَمْ يَمْلأ الحاصِدُ مِنْهُ يَدَهُ، ولا الَّذى يَجْمَعُ الغُمورُ حُضْنَهُ. ولَمْ يَقُل المجْتازونَ إنَّ بَرَكَة الرَّبِّ عَلَيْكُم، وبارَكْناكُم بإسْمِ الرَّبِّ. هَلِّلُويا.'),
      PrayerSection(
          id: 'sunset_17',
          title: 'الإنجيل (لوقا 4:38-41)',
          body:
              'ثُمَّ قامَ مِنَ المجْمَعِ ودَخَلَ بَيْتَ سِمْعانَ. وكانَتْ حَماةُ سِمْعانَ بِحُمَّى شَديدةٍ، فَسَألوهُ مِنْ أجْلِها، فَوَقَفَ فَوْقَاً مِنْها وزَجَرَ الحُمَّى فَتَرَكتْها وفى الحالِ قامَتْ وخَدَمَتْهُم. وعِنْدَ غُروبِ الشَّمْسِ كانَ الَّذينَ عِنْدَهُمْ مَرْضَى بأنْواعِ أمْراضٍ كَثيرةٍ يُقَدِّمونَهُم إليْهِ، أمّا هُوَ فَكانَ يَضَعُ يَدَيهِ عَلَى كُلِِّ واحِدٍ فَيشْفيهم، وكانت الشَّياطينُ تَخْرجُ مِنْ كَثيرينَ وهِىَ تَصْرخُ وتَقولُ: أنْتَ هُوَ المسيحُ إبْنُ اللَّهِ. فَكانَ يَنْتَهِرهُم ولا يَدَعهُم يَنْطِقون، لأنَّهُمْ كانوا قَدْ عَرفوهُ أنَّهُ هُوَ المَسيحُ. والمجْدُ للَّهِ دائِماً.'),
      PrayerSection(
          id: 'sunset_18',
          title: 'القطعة الأولى',
          body:
              'إذا كانَ الصِّدّيقُ بالجَهْدِ يُخلَّصُ فَأيْنَ أظْهَر أَنا الْخاطئ؟ ثِقَل النَّهار وحَرّه لَمْ أحْتَمِلْ لِضَعْفِ بَشَرِيَّتى. لَكِنْ أنْتَ يا اللَّهُ الرَّحومُ إحْسِبْنى مَعَ أصْحابِ السّاعَةِ الحادِيَةَ عَشَرَة. لأنّى هَأنَذا بالآثامِ حُبِلَ بى، وفى الخَطايا وَلَدتْنى أُمّى. فَما أَجْسَرَ أنْ أنْظرَ إلَى عُلُوِّ السَّماءِ، لَكنّى أتَّكِلُ عَلَى غِنَى رَحْمتِكَ ومَحبَّتِكَ لِلْبَشَرِيَّة، صارِخاً قائِلاً: اللَّهُمَّ اغْفِرْ لى أَنا الخاطِئ وارْحَمنى. ( ذُو كصابترى )'),
      PrayerSection(
          id: 'sunset_19',
          title: 'القطعة الثانية',
          body:
              'أسْرِعْ لى يا مُخَلِّصَ بِفَتْحِ الأحْضانِ الأَبَوِيَّةِِ، لأنّى أفْنَيْتُ عُمْرى فى اللَّذاتِ والشهَواتِ وقَدْ مَضَى مِنّى النَّهارُ وفاتَ. فالآنَ أتَّكلُ عَلَى غِنَى رَأْفتِكَ الَّتى لا تَفرغُ. فلا تَتَخلَّ عَنْ قَلْبٍ خاشِعٍ مُفْتَقِرٍ لرَحْمتِكَ. لأنّى إليْكَ أصْرُخُ يا رَبُّ بتَخَشُّعٍ: أخْطَأْتُ يا أبَتاهُ فى السَّماءِ وقُدّامِكَ، ولَسْتُ مُسْتحقاً أنْ أُدْعَى لَكَ إبْناً بَل إجْعَلَنى كَأحَدِ أُجَرائِك. ( كى نين )'),
      PrayerSection(
          id: 'sunset_20',
          title: 'القطعة الثالثة',
          body:
              'لِكُلِّ إثْمٍ بِحرْصٍ ونَشاطٍ فَعلْتُ، ولِكُلِّ خَطِيَّةٍ بشَوْقٍ وإجْتِهادٍ إرْتكَبْتُ، ولِكُلِّ عَذابٍ وحُكْمٍ إسْتَوْجَبْتُ. فَهَيّئ لى أسْبابَ التَّوبَةِ أيَّتُها السَّيدَةُ العَذْراءُ. فَإلَيْكِ أتَضرَّعُ، وبِكِ أسْتَشفعُ وإيّاكِ أدْعو أنْ تُساعِدينى لئلاّ أخْزَى. وعِنْدَ مُفارقَةِ نَفْسى مِنْ جَسَدى احْضَرى عِنْدى، ولمؤامَرةِ الأعْداءِ إهْزمى، ولأبْوابِ الجَحيمِ إغْلقى، لئلاّ يَبْتَلعوا نَفْسى يا عَروس بلا عَيبٍ للخَتْنِ الحَقيقىِّ.'),
      PrayerSection(
          id: 'sunset_21',
          title: 'يارب ارحم 41 مرة',
          body: 'يُقال ( كيريى لَيْسُون ) يَارَبُّ ارْحَمْ 41 مرة.'),
      PrayerSection(
          id: 'sunset_22',
          title: 'قدوس قدوس قدوس',
          body:
              'قُدّوسٌ قُدّوسٌ قُدّوسٌ رَبُّ الصَّباؤوتِ. السَّماءُ والأرْضُ مَمْلوءتانِ مِنْ مَجْدكَ وكَرامَتكَ. إرْحَمْنا يا اللَّهُ الآبُ ضابِطُ الكُلِّ، أيُّها الثّالوثُ القُدّوسُ إرْحَمْنا. أيُّها الرَّبُّ إلهُ القُوّاتِ كُنْ مَعَنا، لأنَّهُ لَيسَ لَنا مُعينٌ فى شَدائِدنا وضيقاتِنا سِواكَ. حلّ واغْفِرْ واصْفَحْ لَنا يا اللَّهُ عَنْ سَيِّئاتِنا الَّتى صَنَعْناها بإرادَتِنا والَّتى صَنَعْناها بغَيرِ إرادَتنا، الَّتى فَعلْناها بمَعرِفةٍ والَّتى فَعلْناها بغَير مَعْرِفةٍ، الخَفيَّةِ والظاهِرةِ، يا رَبُّ اغْفِرها لَنا مِنْ أجْلِ إسْمِكَ القُدّوسِ الَّذى دُعى عَليْنا. كَرحْمتِكَ يا رَبُّ ولا كَخَطايانا.'),
      PrayerSection(
          id: 'sunset_23',
          title: 'الصلاة الربانية',
          body:
              'اللَّهُم اجْعلنا مُستحِقين أنْ نقولَ بِشكرٍ:\nأبانا الذي في السَّمَواتِ، لِيتَقدس اسْمكَ. ليأتِ مَلكوتُكَ. لتَكن مَشيئَتُكَ، كما في السّماءِ كَذلك على الأرْضِ. خُبزَنا الذي للغدِ اعطِنا اليومَ. واغفِر لنا ذنوبَنا كما نغْفر نحنُ أيضّا للمذنبينَ إلينا. ولا تُدخِلنا في تَجرِبةٍ. لكن نجّنا مِنْ الشّريرِ. بالمسيحِ يسوعُ ربُّنا، لأنَّ لَكَ المُلكَ والقوةَ والمجدَ إلى الأبدِ. آمين.'),
      PrayerSection(
          id: 'sunset_24',
          title: 'التحليل',
          body:
              'نَشْكُركَ يا مَلِكنا المتَحنِّنْ، لأنَّكَ مَنَحتَنا أنْ نَعبُر هَذا اليَوْمِ بِسَلامَةٍ وأتَيْتَ بِنا إلَى المَساءِ شاكِرينَ، وجَعلْتَنا مُسْتحِقّينَ أنْ نَنْظُر النّورَ إلَى الَمَساءِ. اللَّهُمَّ اقْبَلْ تَمْجيدَنا هَذا الَّذى صارَ الآنَ، ونَجِّنا مِن حِيَلِ المُضادِّ، وابْطِلْ سائِرَ فِِخاخِهِ المنْصوبَةِ لَنا. هَبْ لَنا فى هَذِه اللَّيْلَةِ المقْبِلَةِ سَلامَةً بِغَيْرِ ألَمٍ ولا قَلَقٍ ولا تَعَبٍ ولا خَيالٍ، لِنَجْتازَها أيْضاً بسَلامٍ وعَفافٍ، ونَنْهَضُ للتَّسابيحِ والصَّلَواتِ كُلَّ حيٍن وفى كُلِّ مَكانٍ نُمجِّد إسْمَكَ القُدّوسَ فى كُلِّ شَئٍ مَعَ الآبِ غَيْرِ المدْرَكِ ولا المبْتَدئ. والرّوحِ القُدُسِ المحْيي المُساوى لَكَ الآنَ وكُلّ أوانٍ وإلَى دَهرِ الدُّهور آمين.'),
      PrayerSection(
          id: 'sunset_25',
          title: 'طلبات تقال آخر كل ساعة',
          body:
              'إرْحَمْنا يا اللَّهُ ثمَّ إرْحَمْنا، يا مَنْ فى كلِّ وقْتٍ وكلِّ ساعَةٍ، فى السَّماءِ وعلَى الأرْض مَسْجودٌ لَهُ ومُمجَّدٌ، المسيحُ إلَهنا الصّالحُ الطَّويلُ الرّوحِ الكثيرُ الرَّحْمةِ الجَزيلُ التَّحنُّنِ، الَّذى يُحبُّ الصِّدّيقيَن ويَرْحمُ الخُطاةَ الَّذينَ أوَّلهُم أَنا، الَّذى لا يَشاءُ مَوْت الخاطِئ مِثل ما يَرجعُ ويَحْيا، الدّاعى الكُلَّ إلَى الخَلاصِ لأجْلِ الموْعدِ بالخَيْراتِ المنْتَظرةِ.\nيا رَبُّ اقْبَل مِنّا فى هَذهِ السّاعةِ وكُلِّ ساعَةٍ طلباتِنا. سَهِّلْ حَياتَنا، وأرشِدْنا إلَى العَمَل بوَصاياكَ. قَدِّسْ أرْواحَنا.طهِّرْ أجْسامَنا. قَوِّمْ أفْكارَنا. نَقِّ نِيّاتَنا واشْفِ أمْراضَنا واغْفِرْ خَطايانا. ونَجِّنا مِنْ كلِّ حُزنٍ رَدئٍ ووَجَِعِ قَلْبٍ، أحِطْنا بمَلائِكتِكَ القدّيسينَ لكىْ نَكونَ بمُعَسْكَرهِم مَحْفوظينَ ومُرْشَدينَ، لنَصِلَ إلَى إتِّحاد الإيمانِ وإلَى مَعْرفةِ مَجْدكَ غَيرِ المحْسوسِ وغَيْر المحْدود، فإنَّكَ مُبارَكٌ إلَى الأبَدِ. آمين.'),
    ];
  }

  List<PrayerSection> _getBedtimeSections() {
    return [
      PrayerSection(
          id: 'bedtime_01',
          title: 'الصلاة الربانية',
          body:
              'بِسْم الآب والابنْ والرُوح القُدُس\nالإلَه الوَاحِد، آمين\n( كيريى لَيْسُون ) يَارَبُّ ارْحَمْ. يَارَبُّ ارْحَمْ. يَارَبُّ بارِكْ. آمين.\nالمجدُ للآبِ والابنِ والروحِ القُدسِ الآنَ وكلَّ أوانِ وإِلَى دهرِ الدهورِ. آمين.\nاللَّهُم اجْعلنا مُستحِقين أنْ نقولَ بِشكرٍ:\nأبانا الذي في السَّمَواتِ، لِيتَقدس اسْمكَ. ليأتِ مَلكوتُكَ. لتَكن مَشيئَتُكَ، كما في السّماءِ كَذلك على الأرْضِ. خُبزَنا الذي للغدِ اعطِنا اليومَ. واغفِر لنا ذنوبَنا كما نغْفر نحنُ أيضّا للمذنبينَ إلينا. ولا تُدخِلنا في تَجرِبةٍ. لكن نجّنا مِنْ الشّريرِ. بالمسيحِ يسوعُ ربُّنا، لأنَّ لَكَ المُلكَ والقوةَ والمجدَ إلى الأبدِ. آمين.'),
      PrayerSection(
          id: 'bedtime_02',
          title: 'صلاة الشكر',
          body:
              'فَلْنشْكُرّ صَانِعَ الخَيراتِ الرَّحُومَ الله أبَا رَبِّنَا وإلهِنَا ومُخَلِصَنا يَسُوعِ المسِيحِ. لأنَّهُ سَتَرنَا، وأعَانَنَا، وحَفِظَنا، وقَبِلَنا إليهِ، وأشْفَقَ عَلينَا، وعَضَّدنَا، وأَتَى بنا إلى هَذِهِ السَّاعَة. هُو أيْضاً فَلْنَسْأَلَهُ أنْ يَحْفَظَنا فى هَذَا اليَومِ المقَدَّسِ وكُلِّ أيَّامِ حَيَاتنَا بكلِّ سَلامِ. الضَّابِطُ الكُلّ الرَّبُ إلَهنَا. أيُّهَا السَّيِدُ الرَّبُّ الإلَه ضَابطُ الكُلِّ أبُو ربِّنَا وإلهنَا ومُخَلصَّنَا يَسُوعِ المسِيح نَشْكرُكَ عَلَى كُلِّ حالٍ، ومِنْ أجْل كلِّ حَالٍ، وفى كُلِّ حالٍ، لأنَّكَ سَترْتَنا، وأعَنْتَنا، وحفِظْتنَا، وقَبلْتنَا إليْكَ، وأشْفَقْت عَلينا، وعَضَّدْتَنَا، وأتَيتَ بِنَا إلىَ هَذِه السَّاعةِ. من أجْلِ هَذَا نَسْألُ ونَطْلبُ مِنْ صَلاحِكَ يَامُحبَّ البَشَر، امْنَحنَا أنْ نُكْملَ هذا اليَوْمَ المقَدَّسَ وكلّ أيَّامِ حَياتِنَا بِكلِّ سَلامٍ مَعَ خَوفِكَ، كُلُّ حَسَدٍ، وكلُّ تَجربَةٍ. وكلُّ فِعْلِ الشَّيْطانِ، ومُؤامَرةِ النَّاسِ الأشْرارِ، وقِيام الأعْدَاءِ الخَفيِّينَ والظَّاهِرينَ، إنْزَعهَا عنَّا وعَنْ سَائِرِ شَعْبكَ وعَنْ مَوضِعِكَ المقَدَّسِ هَذا. أمَّاَ الصَّالِحاتُ والنَّافعاتُ فَارزُقْنا إيَّاهَا. لأنَّكَ أنْتَ الذِى أعْطَيتَنا السُّلْطانَ أنْ ندوسَ الحَيَّاتِ والعَقارِبَ وكُلَّ قوَّةِ العَدوِّ. ولا تُدْخِلنَا فى تَجربَةٍ، لَكنْ نَجِّنا مِنَ الشِّرِّيرِ. بالنِّعْمةِ والرَّأْفَاتِ ومَحبَّة البَشرِ اللَّواتِى لإبْنِك الوَحيدِ ربِّنا وإلهِنَا ومُخلِّصِنا يَسُوعِ المسيحِ. هَذَا الذِى مِنْ قِبَلِه الَمجْدُ والإكْرام والعزَّةُ والسُّجودُ تَلِيقُ بكَ مَعهُ مَعُ الرُّوحِ القُدُسِ الَمحْيى المسَاوِى لَكَ الآنَ وكلَّ أوَانٍ وإلىَ دَهرِ الدُّهُورِ. آمين.'),
      PrayerSection(
          id: 'bedtime_03',
          title: 'المزمور الخمسون',
          body:
              'إرْحَمنِى يَا الله كَعَظيمِ رَحْمتِكَ، ومِثْل كَثْرةِ رَأفتِكَ تَمْحُو إثْمِى. تَغْسلُنِى كَثيراً مِنْ إثْمِى، ومِنْ خَطيَّتِى تُطهَّرنِى. لأنِّى عارفٌ بإثْمِى، وخَطيَّتِى أمَامِى فى كلِّ حينٍ. لَكَ وحْدَك أخْطأْت، والشَّرُّ قدامَكَ صَنعْتُ. لِكىْ تَتَبرَّرَ فى أقْوالِكَ. وتَغْلبَ إذَا حَاكمْت. لأنِّى هَا أنَذَا بالاثْمِ حُبلَ بِى، وبالَخَطايَا وَلَدتْنِى أمِّى. لأنَّكَ هَكَذا قَدْ أحْبَبتُ الحقَّ، إذْ أوْضَحتَ لِى غَوامِضَ حِكْمتِكَ ومَسْتورَاتِها. تَنضَحُ عَلىَّ بِزُوفَاكَ فأطَّهَّرُ، تَغْسلُنِى فَأبْيضُّ أكْثَر مِنَ الثَّلجِ، تَسْمعُنِى سُرُوراً وفَرحاً، فتَبْتهجُ عِظامِى المنْسَحقةُ. أصْرِفْ وجْهَكَ عَنْ خَطايَاىَ، وأمْحُ كلَّ اثَامِى. قَلبِاً نَقياً أخْلقْ فىَّ يَا الله، ورُوحاً مُسْتَقيماً جدِّدهُ فى أحْشَائِى. لا تَطْرحْنِى مِنْ قُدَّامَ وجْهكَ، ورُوحكَ القُدُّوسِ لا تَنْزعْهُ مِنِّى. امْنَحْنِى بَهْجةَ خَلاصِكَ، وبرُوحِ مُدبِّرٍ عَضِّدّنِى فأعْلمِ الأثَمَةَ طُرُقكَ، والمنَافِقونَ إليْكَ يَرجعونَ، نَجِّنِى مِنَ الدِّماء يا الله إلَه خَلاصِى، فيَبتَّهجُ لِسانِى ببرَّكَ. يَاربِّ إفْتَح شَفتَىَّ فَيُخبرُ فَمِى بَتَسْبيحِكَ. لأنَّكَ لَوْ أثَرتَ الذَّبيحةَ، لَكُنْتُ الآنَ أعْطِى. ولَكنَّكَ لا تُسرُّ بالَمحْرقَاتِ، فالذَبيحَةُ للهِ رُوحَّ مُنْسحقَّ. القَلْبُ المنْكسِرُ والمتَواضِعُ لايُرْزلهُ الله، أنْعمْ يَا ربّ بِمَسرتكَ عَلى صِهْيُون، ولْتَبنِ أسْوَارَ أورْشَلِيم. حِينَئذٍ تُسرُّ بذَبائِح البَرِّ قرباناً ومُحْرقَات ويُقَّربون عَلى مَذابِحكَ العُجُول. هَلِّلُويا.'),
      PrayerSection(
          id: 'bedtime_04',
          title: 'بدء الصلاة',
          body:
              'تَسْبحَةُ النَّوْم المُبارَك أقدِّمها للْمَسيحِ مَلِكى وإلَهى وأرْجوهُ أنْ يَغْفرَ لِى خَطاياىَ.'),
      PrayerSection(
          id: 'bedtime_05',
          title: 'مزمور 129: من الأعماق صرخت إليك يا رب',
          body:
              'مِن الأعْماقِ صَرختُ إلَيكَ يا رَبُّ. يا رَبُّ إسْمعْ صَوتى، لتكنْ إذُناكَ مُصْغيَتْينِ إلى صوت تَضرُّعى. إن كنتَ لللآثامِ راصداً يا رَبُّ، يا رَبُّ مَن يَثبُتُ لأنّ مِن عِندِكَ المَغفرَةَ. مِن أجل إسْمكَ صَبرتُ لكَ يا رَبُّ، تَمسّكتْ نَفسى بناموسِكَ. إنْتظَرَتْ نَفسى الرّبَّ مِن مَحرسَ الصُبّحِ، فَلْينظِرْ إسرائيلُ الرّبَّ. لأنّ الرّحمةَ مِن عِندِ الرّبّ، وعظيمٌ هو خلاصُهُ، وهو يَفتَدى إسْرائيلَ مِن كُلِّ آثامِهِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'bedtime_06',
          title: 'مزمور 130: يا رب لم يرتفع قلبي',
          body:
              'يا رَبُّ لَمْ يَرْتَفِعْ قَلْبى ولَمْ تَسْتَعلِ عَيْناي، ولَمْ أسْلُكْ فى العَظائِمِ ولا فى العَجائِبِ. الَّتى هِىَ أَعْلَى مِنّى. أمّا إنْ كُنْت لَمْ أتَّضِعْ، لَكِنْ رَفعْتُ صَوْتى مِثْلُ الفَطيمِ مِنَ اللَّبَنِ عَلَى أمِّهِ، كَذَلكَ تَكونُ عَلَىَّ نَفْسى. فَلْيتَّكِلْ إسْرائيلُ عَلَى الرَّبِّ، مِنَ الآنَ وإلَى الأبَدِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'bedtime_07',
          title: 'مزمور 131: اذكر يا رب داود وكل مذلته',
          body:
              'اذْكُر يا رَبُّ داوُدَ وكُلّ مَذَلَّتِهِ. كَيْفَ أقْسَمَ للرَّبِّ، ونَذَرَ لإلَهِ يَعْقوبَ: إنّى لا أدْخُل إلَى مَسْكنِ بَيْتى، ولا أصْعَدُ عَلَى سَريرِ فِراشى. ولا أُعْطى نَوْماً لِعَيْنى، ولا نُعاساً لأجْفانى، ولا راحَةً لصدْغى. إلَى أنْ أجِدَ مَوْضِعاً لِلرَّبِّ، ومَسْكَناً لإلَهِ يَعْقوبَ. ها قَدْ سَمِعْنا بِهِ فى أفْراته، ووَجَدْناهُ فى مَوْضِعِ الغابةِ. لِنَدْخُل إلَى مَساكِنِهِ، ونَسْجدَ فى المَوْضِعِ الَّذى فيهِ إسْتَقَرَّتْ قَدماهُ. قُمْ يا رَبُّ إلَى راحَتكَ، أنْتَ وتابوتُ قُدْسِكَ. كَهَنتُكَ يَلْبَسونَ البِرَّ، وأبْرارُكَ يَبْتهِجونَ. مِنْ أجْلِ داوُدَ عَبدِكَ، لا تَردَّ وَجْهكَ عَنْ مَسيحِكَ. حَلفَ الرَّبُّ لِداوُدَ حَقًّا ولا يُخْلِف، لأجْعَلَنَّ مِنْ ثَمَرَةِ بَطْنِكَ عَلَى كُرْسيكَ. إنْ حَفِظَ بَنوكَ عَهْدى وشَهاداتى الَّتى أُعْلِمهُمْ إيّاها. فَبَنوهُم أيْضاً يَجْلِسونَ إلَى الأبَدِ عَلَى كُرسيكَ. لأنَّ الرَّبَّ اخْتار صِهْيونَ، وَرَضيها مَسْكَناً لَهُ: هَذا هُوَ مَوْضِعُ راحَتى إلَى أَبَدِ الأبَدِ، هَهُنا أسْكُنُ لأنّى أرَدْتُه. لِطَعامِها أُبارِكُ تَبْريكاً، لمَساكينِها أُشْبِعُ خُبْزاً. لكَهَنَتِها أُلْبِسُ الخَلاصَ، وأبْرارُها يَبْتَهِجونَ ابْتِهاجاً. هُناكَ أُقيمُ قَرناً لداوُدَ، هَيأتَ سِراجاً لِمَسيحى. لأعْدائِهِ أُلْبِسُ الخِزْىَ، وعَليْهِ تَزْدهِرُ قَداسَتى. هَلِّلُويا.'),
      PrayerSection(
          id: 'bedtime_08',
          title: 'مزمور 132: هوذا ما أحسن وما أحلى',
          body:
              'هُوَذا ما أحْسَنَ وما أحْلَى أنْ يَسْكُن الأخْوَةُ مَعاً. كالطّيبِ الكائِنِ عَلَى الرَّأْسِ الَّذى يَنْزلُ عَلَى اللِّحْيةِ، لِحْيَة هَرونَ النّازِلةِ عَلَى جَيْبِ قَميصِه. ومِثْلُ نَدَى حَرْمونَ المنْحَدِر عَلَى جَبَل صِهْيونَ، لأنَّ هُناكَ أمَرَ الرَّبُّ بالبَرَكَةِ والْحَياةِ إلَى الأبَدِ. هَلِّلُويا.'),
      PrayerSection(
          id: 'bedtime_09',
          title: 'مزمور 133: ها باركوا الرب',
          body:
              'ها بارِكوا الرَّبَّ يا عَبيدَ الرَّبِّ القائِمينَ فى بَيْتِ الرَّبِّ في دِيارِ إلَهِنا. فى اللَّيالى ارْفَعوا أيْديَكُم إلَى القُدسِ، وبارِكوا الرَّبَّ. يُبارِككُم الرَّبُّ مِنْ صِهْيونَ، الَّذى خَلَقَ السَّمَوات والأرْضَ. هَلِّلُويا.'),
      PrayerSection(
          id: 'bedtime_10',
          title: 'مزمور 136: على أنهار بابل',
          body:
              'عَلَى أنْهارِ بابِلَ هُناكَ جَلَسْنا، بَكَيْنا عِنْدَما تَذَكّرْنا صِهْيونَ. عَلَى الصِّفْصافِ فى وَسَطِها عَلَّقنا قيثاراتنا، لأنَّهُ هُناكَ سَألَنا الَّذينَ سَبَوْنا أقْوالَ التَّسْبيح. والَّذينَ اسْتاقونا إلَى هُناك قالوا: سَبِّحوا لَنا تَسْبِحَةً مِنْ تَسابيحِ صِهْيونَ. كَيفَ نُسَبِّحُ تَسْبِحَةَ الرَّبِّ فى أرْضٍ غَريبَةٍ؟ إنْ نَسيتكِ يا أورُشَليمَ تنْسَي يَمينى، ويَلْتَصِقُ لِسانى بِحَنَكى إنْ لَمْ أذْكُرك، إنْ لَمْ أُفضِّلْ أورُشَليمَ عَلَى أَعْظَم فَرَحى. اذْكُرْ يا رَبُّ بَني أَدومَ فى يَومَ أورُشَليمَ القائِلينَ: انْقُضوا انْقُضوا حَتَى الأساسَ مِنْها. يا بِنْتَ بابِلَ الشَّقِيَّة، طوبَى لِمَنْ يُكافِئك مُكافأتكِ الَّتى جازَيتِنا. طوبَى لِمَنْ يُمْسِكُ أطْفالَكِ، ويَضْرِبُ بِهِمُ الصَّخْرةَ. هَلِّلُويا.'),
      PrayerSection(
          id: 'bedtime_11',
          title: 'مزمور 137: اعترف لك يا رب',
          body:
              'أعْتَرِفُ لَكَ يا رَبُّ مِنْ كُلِّ قَلْبى، لأنَّكَ إسْتَمعْتَ كُلَّ كَلِماتِ فَمى. أَمامَ الملائِكةِ أُرَتِّلُ لَكَ، وأسْجُدُ قُدّامَ هَيْكَلِكَ المقَدَّسِ، وأعْتَرِفُ لإسْمِكَ عَلَى رَحْمَتِكَ وحَقِّكَ، لأنَّكَ قَدْ عَظَّمْتَ إسْمَكَ القُدّوسَ عَلَى الكُلِّ. اليَومَ الَّذى أدْعوكَ فيهِ أجِبْنى بِسُرْعَةٍ، تُزَوِّدُ نَفْسى كَثيراً بِقُوَّةٍ. فَلْيَعْتَرِفْ لَكَ يا رَبُّ كُلُّ مُلوكِ الأرْضِ، لأنَّهُمْ سَمِعوا سائِرَ كَلِماتِ فَمِكَ. وليسبِّحوا فى طُرُقِ الرَّبِّ لأنَّ مَجْدَ الرَّبّ عَظيمٌ. لأنَّ الرَّبَّ عالٍ ويُعايِنُ المتواضِعينَ، أمّا المتَكبِّرونَ فَيَعْرِفهُم مِنْ بَعْد. إنْ سَلكْت فى وَسَطِ الشِّدَّةِ فَإنَّكَ تُحْيينى، عَلَى رِجْزِ الأعْداءِ مَدَدْتَ يَدَكَ وخَلصتنى يَمينك. الرَّبُّ يُجازى عَنّى. يارَبُّ رَحْمَتُكَ دائِمَةٌ إلَى الأبَدِ، أعْمالُ يَدَيْكَ يا رَبُّ لا تَتْرُكها. هَلِّلُويا.'),
      PrayerSection(
          id: 'bedtime_12',
          title: 'مزمور 140: يا رب إليك صرخت',
          body:
              'يا رَبُّ إليْكَ صَرخْتُ فاسْتَمِعْ لى، انْصِتْ إلَى صَوْتِ تَضرُّعى إذا ما صَرخْتُ إليْكَ. لِتَسْتَقِمْ صَلاتى كالْبَخور قُدّامِكَ، ولِيَكُن رَفْعُ يَدىَّ كذبيحَةٍ مَسائِيَّةٍ. ضَعْ يا رَبُّ حافِظًا لِفَمى، وباباً حَصيناً لشَفَتىَّ، ولا تُمِلْ قَلْبى إلَى كَلامِ الشَّرِّ، فَيُمارِسُ الْخَطايا مَعَ أُناسٍ فاعِلى الإثْمِ ولا أشْتَركُ فى ولائِمِهِمْ. فَلْيؤدِّبْنى الصِّدّيقُ برَحْمةٍ ويُوَبِّخنى، أمّا زَيْتُ الخاطئ فَلا يَدْهنُ رَأسى. لأنَّ صَلاتى أيْضًا ضِدَّ رَغَباتِهِم الشِّرّيرَةِ. ذُهِلَ أقْوياؤُهُم عِنْدَ الصَّخْرَةِ، يَسْمَعونَ كَلِماتى اللَّيِّنَةَ، مِثْل شَحْمِ الأرْضِ انْشَقوا عَلَى الأرْضِ. تَبَدَّدَت عِظامُهُمْ عِنْدَ الْجَحيمِ، لأنَّ عُيونَنا إليْكَ يا رَبُّ. يا رَبُّ عَليْكَ تَوكَّلْتُ فَلا تَقْتُل نَفْسى. احْفَظنى مِنَ الفخِّ الَّذى نَصَبوهُ لى، ومِنْ شُكوكِ فاعِلى الإثْمِ. يَسْقُطُ الْخُطاةُ فى شِباكِهِمْ وأكونُ أَنا وَحْدى حَتَّى يَجوز الإثْمُ. هَلِّلُويا.'),
      PrayerSection(
          id: 'bedtime_13',
          title: 'مزمور 141: بصوتي إلى الرب صرخت',
          body:
              'بصَوْتى إلَى الرَّبِّ صَرَخْتُ، بِصَوْتى إلَى الرَّبِّ تَضَرَّعْتُ أسْكُبُ أمامَه تَوَسُّلى، أبُثُّ لَدَيْهِ ضيقى عِنْدَ فَناءِ روحى مِنّى وأنْتَ عَلمت سُبُلى. فى الطَّريقِ الَّذى أسْلُكُ أخْفَوْا لى فَخّاً. تأمَّلْتُ عَنِ اليَمينِ وأبْصَرتُ، فلَمْ يَكُنْ مَنْ يَعْرفنى. ضاعَ الْمَهْرَبُ مِنّى ولَيْسَ مَنْ يَسْألُ عَنْ َنْفسى فَصَرخْتُ إليْكَ يا رَبُّ وقلْتُ: أنْتَ هُوَ رَجائى وحَظّى فى أرْضِ الأحْياءِ. أنْصِتْ إلَى طلبَتى، فإنّى قَدْ تَذلَّلْتُ جِدّاً. نَجِّنى مِنَ الَّذينَ يَضْطَهِدونى، لأنَّهُمْ قَدْ اعْتَزّوا أكثَرَ مِنّى. أَخْرِجْ مِنَ الْحَبْسِ نَفْسى، لِكَى أشْكُرَ إسْمَكَ يا رَبُّ. إيّاى ينْتَظِرُالصِّدّيقونَ حَتَى تُجازينى. هَلِّلُويا.'),
      PrayerSection(
          id: 'bedtime_14',
          title: 'مزمور 145: سبحي يا نفسي الرب',
          body:
              'سَبِّحى يا نَفْسى الرَّبَّ. أُسَبِّحُ الرَّبَّ فى حَياتى، وأُرَتِّلُ لإلَهى مادُمتُ حَيّاً. لا تَتَّكِلوا عَلَى الرُّؤساءِ ولا عَلَى بَنى البَشَرِ. الَّذينَ لَْسَ عِنْدهُمْ خَلاصٌ. تَخْرجُ روحُهُم فَيَعودونَ إلَى تُرابِهِمْ، فى ذَلِكَ اليَوْمِ تَهْلكُ كافَّة أفْكارِهِم. طوبَى لِمَنْ إلَهُ يَعْقوبَ مُعينُهُ، واتِّكالُهُ عَلَى الرَّبِّ إلَهِهِ. الَّذى صَنَعَ السَّماءَ والأرْضَ والبَحْرَ وكُلَّ ما فيها. الحافِظِ العَدْل إلَى الدَّهْرِ. الصّانِعِ الْحُكْمِ للمَظْلومينَ. المعْطى الطَّعامَ للجِياعِ. الرَّبُّ يَحلُّ المأْسورينَ، الرَّبُّ يُقيمُ السّاقِطينَ. الرَّبُّ يَحْكُم العُمْيانَ، الرَّبُّ يُحِبُّ الصِّدّيقينَ. الرَّبُّ يَحْفَظُ الغُرباءَ ويعضدُ اليَتيمَ والأرْمَلةَ، ويُبيدُ طُرقَ الْخُطاةِ. يَمْلكُ الرَّبُّ إلَى الدَّهْرِ، وإلَهُكِ يا صِهْيونُ مِنْ جيلٍ إلَى جيلٍ. هَلِّلُويا.'),
      PrayerSection(
          id: 'bedtime_15',
          title: 'مزمور 146: سبحوا الرب فإن المزمور جيد',
          body:
              'سَبِّحوا الرَّبَّ فإنَّ المزْمورَ جَيِّدٌ، لإلَهِنا يَلذُّ التَّسْبيحُ. الرَّبُّ يَبْنى أورُشَليمَ، الرَّبُّ يَجْمعُ مُتَفرِّقى إسْرائيلَ. الرَّبُّ يَشْفى مُنْكَسِرى القُلوبِ، ويُجبرُ جَميعَ كَسْرهِمْ. الْمُحْصى كَثْرةَ الكَواكِبِ، ولكافَّتِها يُعْطى أسْماء. عَظيمٌ هُوَ الرَّبُّ وعَظيمَةٌ هِىَ قُوَّتُهُ، ولا إحْصاء لِفهْمِهِ. الرَّبُّ يَرْفَعُ الوُدَعاءَ، ويُذِلُّ الْخُطاةَ إلَى الأرْضِ. ابْتَدِئُوا للرَّبِّ بالاعْتِراف، رَتِّلوا لإلَهِنا بالقيثارَةِ. الَّذى يُجَلِّلُ السَّماءَ بالغَمامِ، الَّذى يُهَيّئ للأرْضِ المطَرَ. الَّذى يُنبتُ العُشْبَ عَلَى الْجِبالِ، والْخُضْرةِ لِخِدْمَةِ البَشَرِ، ويُعْطى البَهائِمَ طَعامَها ولِفِراخِ الغِرْبانِ الَّتى تَدْعوهُ لا يُؤْثرُ قُوَّةَ الْخَيْل، ولا يُسَرُّ بِساقى الرَّجُل، بَلْ يُسَرُّ الرَّبُّ بِخائِفيهِ، وبالرّاجينَ رَحْمتَهُ. هَلِّلُويا.'),
      PrayerSection(
          id: 'bedtime_16',
          title: 'مزمور 147: سبحي الرب يا أورشليم',
          body:
              'سَبِّحى الرَّبَّ يا أورُشَليمَ، سَبِّحى إلَهَكِ يا صِهْيونَ. لأنَّهُ قَدْ قَوَّى مَغاليقَ أبْوابِكِ، وبارَكَ بَنيكِ فيكِ. الَّذى جَعََََل تُخومَكِ فى سَلامٍ، ويُشْبِعُكِ مِنْ شَحْم الْحِنْطَةِ. الَّذى يُرْسِلُ كَلِمَتَهُ إلَى الأرْضِ، فَيُسْرعُ قَولُه عاجِلاً جِدّأ. المعْطى الثَّلْجَ كالصّوفِ، المذَرّى الضَّبابَ كالرَّمادِ. ويُلْقى الْجَليدَ مِثْل الفُتاتِ، قُدّامَ وَجْه بردِهِ مَنْ يَقومُ؟ يُرْسِلُ كَلمَتَه فَتُذيبَهُ، تَهبُّ ريحُهُ فَتَسيلُ المياهَ، المخبرُ كَلمتَهُ لِيَعْقوبَ، وفَرائِضَهُ وأَحْكامَهُ لإسْرائيلَ. لَمْ يَصْنَع هَكَذا بكلِّ الأممِ، وأحْكامَهُ لَمْ يُوَضِّحها لَهُمْ. هَلِّلُويا.'),
      PrayerSection(
          id: 'bedtime_17',
          title: 'الإنجيل (لوقا 2:25-32)',
          body:
              'وإذا إنْسانٌ كانَ بأورُشَليمَ إسْمُهُ سِمْعانُ، وهَذا الإنْسانُ كانَ باراً تَقيّاً مُتَوقِّعاً تَعْزِيةَ إسْرائيلَ والرّوح القُدُس كانَ عَليهِ. وكانَ قَدْ أُعْلِمَ بِوَحْىٍ مِنَ الرّوحِ القُدُسِ أنَّهُ لا يَرَى الموْتَ قَبْل أنْ يُعاينَ المسيحَ الرَّبَّ فأقْبَلَ بالرّوحِ إلَى الهَيْكلِ، ولَمّا دَخَلََ بالطِّفْلِ يَسوعَ أبَواهُ ليَصْنَعا عَنْه كَما يَجبُ فى النّاموسِ، حَمَلهُ سِمْعانُ عَلَى ذِراعَيهِ وبارَكَ اللَّهُ قائِلاً: الآنَ يا سَيِّدى تُطْلِقُ عَبْدكَ بسَلامٍ حَسَبَ قَوْلكَ، لأنَّ عَيْنىَّ قَدْ أبْصَرتا خَلاصَكَ الِّذى أعْدَدتَهُ أمامَ جَميعِ الشُّعوبِ. نوراً تَجلَّى للأممِ، ومَجْدًا لِشَعْبِكَ إسْرائيلَ. والمجْدُ للَّهِ دائماً.'),
      PrayerSection(
          id: 'bedtime_18',
          title: 'القطعة الأولى',
          body:
              'هُوَذا أَنا عَتيدٌ أَنْ أَقِفَ أَمامَ الدَّيّانِ العادِلِ مَرْعوباً ومُرْتَعبًا مِنْ كَثْرةِ ذُنوبى، لأنَّ العُمْرَ المنْقَضى فى الْمَلاهى يَسْتوجِبُ الدَّيْنونَةَ. لَكِنْ توبى يانَفْسى ما دُمْتِ فى الأرْضِ ساكِنةً لأنَّ التُّرابَ فى القَبْرِ لا يُسَبِّحُ ولَيْسَ فى الموْتَى مَنْ يَذْكُر ولا فى الْجَحيمِ مَنْ يَشْكُر. بَلْ انْهَضى مِنْ رُقادِ الكَسَل وتَضَرَّعى إلَى المخَلِّصِ بالتَّوْبَةِ قائِلةً: اللَّهُمَّ ارْحَمْنى وخَلِّصنى. ( ذُوكصابترى )'),
      PrayerSection(
          id: 'bedtime_19',
          title: 'القطعة الثانية',
          body:
              'لَوْ كانَ العُمْرُ ثابتاً وهَذا العالَمُ مُؤَبَّدًا لَكانَ لَكِ يا نَفْسى حُجَّةٌ واضِحَةٌ. لَكِن إذا إنْكَشَفَتْ أفْعالُكِ الرَّديئة وشُروركِ القَبيحَة أَمامَ الدَّيّانِ العادِلِ، فَأَىُّ جَوابٍ تُجيبى وأنْتِ عَلَى سَريرِ الْخَطايا مُنْطَرحةً وفى إخْضاعِ الجَسَدِ مُتَهاونَةً؟ أيُّها المسيحُ إلَهُنا، لِكُرسى حُكْمِكَ المرْهوبِ أفْزَعُ. ولِمَجْلِسِ دَيْنونتِك أخْشَعُ. ولِنورِ شُعاعِ لاهوتكَ أجْزعُ. أَنا الشَّقِىُّ المتَدنِّسُ الرّاقِدُ عَلَى فِراشى، المتَهاوِنُ فى حَياتى. لَكنّى أَتَّخِذُ صورَة العشَّارِ قارِعاً صَدْرى قائِلاً: اللَّهُمَّ اغْفِرْ لى فإنّى خاطئ. ( كى نين )'),
      PrayerSection(
          id: 'bedtime_20',
          title: 'القطعة الثالثة',
          body:
              'أيَّتُها العَذْراءُ الطّاهِرةُ أسْبِلى ظلَّكِ السَّريعَ المعونَةِ عَلَى عَبْدكِ، وابْعِدى أمْواجَ الأفْكارِ الرَّديئةِ عَنّى، وانْهضى نَفْسى المريضَةَ للصَّلاةِ والسَّهَرِ، لأنَّها اسْتَغرقَتْ فى سُباتٍ عَميقٍ، فإنَّكِ أُمٌّ قادِرةٌ رَحيمةٌ مُعينةٌ والِدَةُ ينْبوعِ الْحَياةِ مَلِكى وإلَهى يَسوعِ المسيحِ رَجائى. َتفضَّلْ يا رَبُّ أنْ تَحْفَظَنا فى هَذِه اللَّيْلةِ بِغَيرِ خَطيَّةٍ. مُبارِكٌ أَنْتَ أيُّها الرَّبُّ إلهُ آبائِنا ومُتَزايدٌ بَرَكةً، وإسْمُكَ القُدّوسُ مَمْلوءٌ مَجْداً إلَى الأبَدِ آمين. فَلْتكنْ رَحمَتُكَ عَليْنا كَمثْلِ إتِّكالِنا عَليْكَ، لأنَّ أعْيُنَ الكُلَّ تَترَجّاكَ، لأنَّكَ أنْتَ الَّذى تُعْطيهم طَعامَهُم فى حينِه. إسْمَعنا يا اللَّهُ مُخلِّصَنا يا رَجاءَ أقْطارِ الأرْضِ كُلِّها. وأنْتَ يا رَبُّ تَحْفظُنا وتُنَجّينا مِنْ هَذا الجيلِ وإلَى الأبَدِ آمين. مُبارَكٌ أنْتَ يا رَبُّ عَلِّمنى عَدْلَك، مُبارَكٌ أنْتَ يا رَبُّ فَهِّمنى حُقوقَكَ. مُبارَكٌ أنْتَ يا رَبُّ أنِرْ لى بِرَّك، يا رَبُّ رَحْمَتُكَ دائِمَةٌ إلَى الأبَدِ. أعْمالُ يَديْكَ يا رَبُّ لا تَرفُضْها، لأنَّكَ صِرْتَ لى مَلجأً مِنْ جيلٍ إلَى جيلٍ. أَنا طَلبْتُ إلَى الرَّبِّ وقُلْتُ إرْحَمْنى وخَلِّصْ نَفْسى، فإنّى أخْطَأتُ إليْكَ. يارَبُّ إلْتَجأتُ إلَيكَ فَخلِّصنى، وعَلِّمنى أنْ أصْنَعَ مَشيئتَك. لأنَّكَ أنْتَ هُوَ إلَهى، وعِنْدكَ ينْبوعُ الْحَياةِ، وبِنورِكَ يا رَبُّ نُعاينُ النّورَ. فلْتَأتِ رَحْمتُكَ للَّذينَ يَعْرفونَكَ، وبِرُّكَ للْمُسْتقيمى القُلوبِ. لَكَ تجبُ البَركَةُ، لَكَ يَحقُّ التَّسْبيحُ. لَكَ يَنْبغى التَّمْجيدُ أيُّها الآبُ والإبْنُ والرّوحُ القُدُسُ الكائِنُ منْذُ البَدْءِ والآنَ وإلَى أبَدِ الأبَدِ. آمين. جَيِّدٌ هُوَ الإعْتِرافُ للرَّبِّ، والتَّرْتيلُ لإسْمِك أيُّها العَلىُّ. أنْ يُخبر برَحْمتِكَ فى الغَدَواتِ وحَقِّك فى كُلِّ لَيلةٍ.'),
      PrayerSection(
          id: 'bedtime_21', title: 'تفضل يا رب', body: 'ضع تفضل يا رب هنا'),
      PrayerSection(
          id: 'bedtime_22',
          title: 'الثلاث تقديسات',
          body:
              'قُدّوسٌ اللَّهُ. قُدّوسٌ القَوىُّ. قُدّوسٌ الحَىُّ الَّذى لا يَموتُ الَّذى وُلِدَ مِنَ العَذْراءِ إرْحَمْنا. قُدّوسٌ اللَّهُ. قُدّوسٌ القَوىُّ. قُدّوسٌ الحَىُّ الَّذى لا يَموتُ الَّذى صُلِبَ عنّا إرْحَمْنا. قُدّوسٌ اللَّهُ. قُدّوسٌ القَوىُّ. قُدّوسٌ الحَىُّ الَّذى لا يَموتُ الّذى قامَ مِنَ الأمْواتِ وصَعِدَ إلَى السَّمواتِ إرْحَمْنا. المجْدُ للآبِ والإبنِ والرّوحِ القُدُسِ، الآنَ وكلُّ أَوان وإلَى دَهْرِ الدّهورِ آمين. أيُّها الثّالوثُ القُدّوسُ إرْحَمْنا، أيُّها الثّالوثُ القُدّوسُ إرْحَمْنا، أيُّها الثّالوثُ القُدّوسُ إرْحَمْنا، يا رَبُّ إغْفِرْ لَنا خَطايانا. يا رَبُّ إغْفِرْ لَنا آثامَنا، يا رَبُّ إغْفِرْ لَنا زَلاّتَنا. يا رَبُّ إفْتَقدْ مَرْضَى شَعْبكَ، إشْفِهمْ مِنْ أجْل إسْمكَ القُدّوسِ. آباؤُنا وإخْوَتنا الَّذينَ رَقدوا يا رَبُّ نَيِّحْ نُفوسَهُم، يا مَنْ هُوَ بِلا خَطيَّة يا رَبُّ إرْحَمْنا، يا الَّذى بِلا خَطيَّةِ يا رَبُّ أَعِنّا، واقْبَلْ طَلباتِنا إلَيْكَ. لأنَّ لَكَ المجْدَ والعِزَّةَ والتَّقْديسَ المثلَّثَ. يا رَبُّ إرْحَمْ، يا رَبُّ إرْحَمْ، يا رَبُّ بارِكْ. آمين.'),
      PrayerSection(
          id: 'bedtime_23',
          title: 'قانون الإيمان',
          body:
              'بالحَقيقَةِ نُؤمِنُ بإلهٍ واحدٍ اللَُّهُ الآبُ ضابطُ الكُلِّ خالِقُ السَّماءِ والأرضِ، ما يُرَى وما لا يُرَى. نُؤمِنُ بربٍّ واحدٍ يَسوعِ المسيحِ إبْن اللهِ الوَحيدِ الموْلودِ مِنَ الآبِ قَبْلَ كلِّ الدُّهورِ. نورٌ مِنْ نورٍ إلهٌ حَقٌ مِنْ إلهٍ حَقٍّ، مَولودٌ غَيْرُ مَخْلوقٍ، مُساوٍ للآبِ فى الجَوْهرِ. الَّذى بِهِ كانَ كلُّ شئٍ. هَذا الَّذى مِنْ أجْلنا نَحنُ البَشَرَ ومِنْ أجْلِ خَلاصِنا نَزلَ مِنَ السَّماءِ وتَجسَّدَ مِنَ الرّوحِ القُّدُسِ، ومِنْ مَرْيَم العَذْراءِ تَأنَّسَ. وصُلبَ عنّا علَى عَهدِ بيلاطُس البنْطى، تألَّمَ وقُبرَ وقامَ مِن بَين الأمْواتِ فى اليَومِ الثّالثِ كَما في الكتُبِ، وصَعِدَ إلَى السَّمواتِ وجَلسَ عَنْ يَمينِ أبيهِ وأيْضاً يَأتي فى مَجدهِ ليُدينَ الأحْياءَ والأمْوات َ، الَّذى لَيسَ لملْكِهِ إنْقِضاءٌ. نَعَم نُؤمِنُ بالرّوحِ القُدُسِ، الرَّبُّ المحْيى المنْبَثقِ مِنَ الآبِ نَسْجُد لهُ ونُمجِّدهُ مَعَ الآبِ والإبْنِ النّاطِقِ فى الأنْبياءِ. وبكنيسَةٍ واحِدَةٍ مُقدَّسةٍ جامعَةٍ رسوليَّةٍ، ونَعْترِفُ بمَعْموديَّةٍ واحِدَةٍ لمغْفِرَةِ الخَطايا. وننْتَظرُ قِيامَةَ الأمْواتِ وحَياةَ الدَّهرِ الآتى آمين.'),
      PrayerSection(
          id: 'bedtime_24',
          title: 'يارب ارحم 14 مرة',
          body: 'يُقال ( كيريى لَيْسُون ) يَارَبُّ ارْحَمْ 41 مرة.'),
      PrayerSection(
          id: 'bedtime_25',
          title: 'قدوس قدوس قدوس',
          body:
              'قُدّوسٌ قُدّوسٌ قُدّوسٌ رَبُّ الصَّباؤوتِ. السَّماءُ والأرْضُ مَمْلوءتانِ مِنْ مَجْدكَ وكَرامَتكَ. إرْحَمْنا يا اللَّهُ الآبُ ضابِطُ الكُلِّ، أيُّها الثّالوثُ القُدّوسُ إرْحَمْنا. أيُّها الرَّبُّ إلهُ القُوّاتِ كُنْ مَعَنا، لأنَّهُ لَيسَ لَنا مُعينٌ فى شَدائِدنا وضيقاتِنا سِواكَ. حلّ واغْفِرْ واصْفَحْ لَنا يا اللَّهُ عَنْ سَيِّئاتِنا الَّتى صَنَعْناها بإرادَتِنا والَّتى صَنَعْناها بغَيرِ إرادَتنا، الَّتى فَعلْناها بمَعرِفةٍ والَّتى فَعلْناها بغَير مَعْرِفةٍ، الخَفيَّةِ والظاهِرةِ، يا رَبُّ اغْفِرها لَنا مِنْ أجْلِ إسْمِكَ القُدّوسِ الَّذى دُعى عَليْنا. كَرحْمتِكَ يا رَبُّ ولا كَخَطايانا.'),
      PrayerSection(
          id: 'bedtime_26',
          title: 'الصلاة الربانية',
          body:
              'اللَّهُم اجْعلنا مُستحِقين أنْ نقولَ بِشكرٍ:\nأبانا الذي في السَّمَواتِ، لِيتَقدس اسْمكَ. ليأتِ مَلكوتُكَ. لتَكن مَشيئَتُكَ، كما في السّماءِ كَذلك على الأرْضِ. خُبزَنا الذي للغدِ اعطِنا اليومَ. واغفِر لنا ذنوبَنا كما نغْفر نحنُ أيضّا للمذنبينَ إلينا. ولا تُدخِلنا في تَجرِبةٍ. لكن نجّنا مِنْ الشّريرِ. بالمسيحِ يسوعُ ربُّنا، لأنَّ لَكَ المُلكَ والقوةَ والمجدَ إلى الأبدِ. آمين.'),
      PrayerSection(
          id: 'bedtime_30',
          title: 'التحليل',
          body:
              'يا رَبُّ جَميعُ ما أخْطأْنا بِهِ إليْكَ فى هَذا اليَومِ، إنْ كانَ بالفِعْلِ أوْ بالقَولِ أوْ بالفِكْر أو بِجَميعِ الْحَواسِّ، فاصْفَحْ واغفْر لَنا مِنْ أجْلِ إسْمِِِكَ القُدّوسِ كَصالحٍ ومُحبٍّ للبَشَرِ. وأنْعمْ عَلَيْنا اللَّهُمَّ بلَيلةٍ سالمةٍ، وبِهَذا النَّوْم طاهِراً مِنْ كُلِّ قَلقٍ وأرْسِلْ لَنا مَلاكَ السَّلامَةِ ليَحرُسَنا مِنْ كُلِّ شَرٍّ، ومِنْ كُلِّ ضَرْبَةٍ، ومِنْ كُلِّ تَجْربَةِ العَدُوِّ. بالنِّعْمةِ والرَّأفاتِ ومَحبَّةِ البَشَرِ اللَّواتي لإبْنِكَ الوَحيدِ رَبِّنا وإلَهِِنا ومُخلِّصِنا يَسوعِِِ المسيحِ. هَذا الَّذى مِنْ قِبَلهِ يَليقُ بِكَ مَعهُ المجْدُ والكَرامَةُ والعِزَّةُ، مَعَ الرّوحِ القُدُسِ الْمُحْيى الْمُساوى لَكَ الآنَ وكُلُّ أوانٍ وإلَى دَهْرِ الدُّهورِ آمين.'),
      PrayerSection(
          id: 'bedtime_27',
          title: 'طلبات تقال آخر كل ساعة',
          body:
              'إرْحَمْنا يا اللَّهُ ثمَّ إرْحَمْنا، يا مَنْ فى كلِّ وقْتٍ وكلِّ ساعَةٍ، فى السَّماءِ وعلَى الأرْض مَسْجودٌ لَهُ ومُمجَّدٌ، المسيحُ إلَهنا الصّالحُ الطَّويلُ الرّوحِ الكثيرُ الرَّحْمةِ الجَزيلُ التَّحنُّنِ، الَّذى يُحبُّ الصِّدّيقيَن ويَرْحمُ الخُطاةَ الَّذينَ أوَّلهُم أَنا، الَّذى لا يَشاءُ مَوْت الخاطِئ مِثل ما يَرجعُ ويَحْيا، الدّاعى الكُلَّ إلَى الخَلاصِ لأجْلِ الموْعدِ بالخَيْراتِ المنْتَظرةِ. يا رَبُّ اقْبَل مِنّا فى هَذهِ السّاعةِ وكُلِّ ساعَةٍ طلباتِنا. سَهِّلْ حَياتَنا، وأرشِدْنا إلَى العَمَل بوَصاياكَ. قَدِّسْ أرْواحَنا.طهِّرْ أجْسامَنا. قَوِّمْ أفْكارَنا. نَقِّ نِيّاتَنا واشْفِ أمْراضَنا واغْفِرْ خَطايانا. ونَجِّنا مِنْ كلِّ حُزنٍ رَدئٍ ووَجَِعِ قَلْبٍ، أحِطْنا بمَلائِكتِكَ القدّيسينَ لكىْ نَكونَ بمُعَسْكَرهِم مَحْفوظينَ ومُرْشَدينَ، لنَصِلَ إلَى إتِّحاد الإيمانِ وإلَى مَعْرفةِ مَجْدكَ غَيرِ المحْسوسِ وغَيْر المحْدود، فإنَّكَ مُبارَكٌ إلَى الأبَدِ. آمين.'),
    ];
  }

  @override
  Widget build(BuildContext context) {
    final themeProvider = Provider.of<ThemeProvider>(context);
    if (_prayerSections.isEmpty) {
      return Directionality(
        textDirection: TextDirection.rtl,
        child: Scaffold(
          backgroundColor: themeProvider.backgroundColor,
          appBar: AppBar(
            backgroundColor: themeProvider.cardColor,
            elevation: 0,
            centerTitle: true,
            leading: IconButton(
              icon: const Icon(Icons.arrow_back_rounded,
                  color: Color(0xFF4ADE80)),
              onPressed: () => Navigator.pop(context),
            ),
            title: Text(
              widget.prayerName,
              style: GoogleFonts.cairo(
                fontWeight: FontWeight.w900,
                color: const Color(0xFF4ADE80),
                fontSize: 20 * themeProvider.fontScale,
              ),
            ),
          ),
          body: const Center(child: Text('لا توجد أقسام')),
        ),
      );
    }
    return Directionality(
      textDirection: TextDirection.rtl,
      child: Scaffold(
        backgroundColor: themeProvider.backgroundColor,
        appBar: AppBar(
          backgroundColor: themeProvider.cardColor,
          elevation: 0,
          centerTitle: true,
          leading: IconButton(
            icon:
                const Icon(Icons.arrow_back_rounded, color: Color(0xFF4ADE80)),
            onPressed: () => Navigator.pop(context),
          ),
          title: Text(
            widget.prayerName,
            style: GoogleFonts.cairo(
              fontWeight: FontWeight.w900,
              color: const Color(0xFF4ADE80),
              fontSize: 20 * themeProvider.fontScale,
            ),
          ),
        ),
        body: Column(
          children: [
            Container(
              margin: const EdgeInsets.all(16),
              decoration: BoxDecoration(
                color: themeProvider.cardColor,
                borderRadius: BorderRadius.circular(20),
                boxShadow: [
                  BoxShadow(
                    color: Colors.black.withOpacity(0.05),
                    blurRadius: 10,
                    offset: const Offset(0, 2),
                  ),
                ],
              ),
              child: Padding(
                padding:
                    const EdgeInsets.symmetric(horizontal: 20, vertical: 4),
                child: DropdownButtonHideUnderline(
                  child: DropdownButton<String>(
                    value: _prayerSections[_selectedIndex].id,
                    isExpanded: true,
                    icon: const Icon(Icons.arrow_drop_down,
                        color: Color(0xFF4ADE80)),
                    dropdownColor: themeProvider.cardColor,
                    style: GoogleFonts.cairo(
                      fontSize: 16,
                      fontWeight: FontWeight.w600,
                      color: themeProvider.textColor,
                    ),
                    items: _prayerSections.map((section) {
                      return DropdownMenuItem<String>(
                        value: section.id,
                        child: Text(
                          section.title,
                          style: GoogleFonts.cairo(fontSize: 14),
                          textAlign: TextAlign.center,
                        ),
                      );
                    }).toList(),
                    onChanged: (String? newId) {
                      if (newId != null) {
                        final newIndex = _prayerSections
                            .indexWhere((section) => section.id == newId);
                        _pageController.animateToPage(
                          newIndex,
                          duration: const Duration(milliseconds: 300),
                          curve: Curves.easeInOut,
                        );
                      }
                    },
                  ),
                ),
              ),
            ),
            Expanded(
              child: PageView.builder(
                controller: _pageController,
                physics: const BouncingScrollPhysics(
                  parent: AlwaysScrollableScrollPhysics(),
                ),
                onPageChanged: (index) {
                  setState(() {
                    _selectedIndex = index;
                  });
                },
                itemCount: _prayerSections.length,
                itemBuilder: (context, index) {
                  final section = _prayerSections[index];
                  return SingleChildScrollView(
                    physics: const BouncingScrollPhysics(),
                    padding: const EdgeInsets.all(16),
                    child: Container(
                      padding: const EdgeInsets.all(24),
                      decoration: BoxDecoration(
                        color: themeProvider.cardColor,
                        borderRadius: BorderRadius.circular(24),
                        boxShadow: [
                          BoxShadow(
                            color: Colors.black.withOpacity(0.05),
                            blurRadius: 10,
                            offset: const Offset(0, 2),
                          ),
                        ],
                      ),
                      child: Text(
                        section.body,
                        style: GoogleFonts.cairo(
                          fontSize: 22 * themeProvider.fontScale,
                          color: themeProvider.textColor,
                          height: 1.7,
                        ),
                        textAlign: TextAlign.center,
                      ),
                    ),
                  );
                },
              ),
            ),
          ],
        ),
      ),
    );
  }
}

class PrayerSection {
  final String id;
  final String title;
  final String body;
  PrayerSection({
    required this.id,
    required this.title,
    required this.body,
  });
}
